-- Poems batch 250
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('caca09d0-2ac6-44c4-bf0c-13506ab665c8','劉褘之','林同','宋','宋诗','song-poetry','','[]','卿家著忠孝，朕子頼師模。',24,'全唐诗/poet.song.225000.json','["卿家著忠孝，朕子頼師模。", "蓬在麻中直，多應不待扶。"]'),
('1d072402-a772-44c6-9595-f4690d18bb19','韋景駿','林同','宋','宋诗','song-poetry','','[]','長抱罔極痛，嗟余少不天。',24,'全唐诗/poet.song.225000.json','["長抱罔極痛，嗟余少不天。", "汝今幸有母，不省汝胡然。"]'),
('f3ed7d36-9002-4e4e-a9ab-7b7c0ae369f9','張九齡','林同','宋','宋诗','song-poetry','','[]','連理庭中木，叢生坐側芝。',24,'全唐诗/poet.song.225000.json','["連理庭中木，叢生坐側芝。", "未嘗聞孝感，一一有茲奇。"]'),
('3463bdc5-f2d6-447d-8e9f-d16097822030','顔真卿','林同','宋','宋诗','song-poetry','','[]','祇是見忠節，何曾省孝誠。',24,'全唐诗/poet.song.225000.json','["祇是見忠節，何曾省孝誠。", "唐宗休歎息，猶未識真卿。"]'),
('48d37162-c9f7-43cf-a112-d00867d66130','韓思復','林同','宋','宋诗','song-poetry','','[]','向來曹孟德，曾擬表征西。',24,'全唐诗/poet.song.225000.json','["向來曹孟德，曾擬表征西。", "那得忠孝字，金書作墓題。"]'),
('de5f6d2f-5609-4fae-8c85-fa93da4b877b','崔縱','林同','宋','宋诗','song-poetry','','[]','直以母事妾，祇云父所安。',24,'全唐诗/poet.song.225000.json','["直以母事妾，祇云父所安。", "可憐遭楚毒，加意更承顔。"]'),
('127542e8-4d16-4954-acd2-d1fcc01a52e5','崔沔','林同','宋','宋诗','song-poetry','','[]','憶昨升堂拜，何曾有雜賓。',24,'全唐诗/poet.song.225000.json','["憶昨升堂拜，何曾有雜賓。", "事亡忍廢禮，不復問疎親。"]'),
('d33e305c-c626-49f3-9f04-9d4d7c751317','李乂','林同','宋','宋诗','song-poetry','','[]','俱以文章顯，無慙孝謹稱。',24,'全唐诗/poet.song.225000.json','["俱以文章顯，無慙孝謹稱。", "弟兄同一集，華萼著嘉名。"]'),
('3e836324-d3a9-4a7d-9339-2e905e053036','裴子餘','林同','宋','宋诗','song-poetry','','[]','直以孝爲謚，真無愧此心。',24,'全唐诗/poet.song.225000.json','["直以孝爲謚，真無愧此心。", "可憐張說歎，知得子餘深。"]'),
('8621060d-0417-474c-8294-34d73aeec7bd','李勉','林同','宋','宋诗','song-poetry','','[]','不誅人厭己，而恕子祈親。',24,'全唐诗/poet.song.225000.json','["不誅人厭己，而恕子祈親。", "賢矣李觀察，今無復此人。"]'),
('e05b0bf3-a9a8-4c51-9ba9-e5fff70080f0','陽城','林同','宋','宋诗','song-poetry','','[]','學者學爲孝，諸生久講明。',24,'全唐诗/poet.song.225000.json','["學者學爲孝，諸生久講明。", "謁歸二十輩，毋乃爲陽城。"]'),
('71f812bd-add9-4c8b-846a-31d6cf53c7a6','段秀實','林同','宋','宋诗','song-poetry','','[]','意其失兵久，怏怏必吾從。',24,'全唐诗/poet.song.225000.json','["意其失兵久，怏怏必吾從。", "奪笏直前擊，那知是孝童。"]'),
('e15de1c2-8d40-465f-a8fd-e8c6cab74d54','李晟','林同','宋','宋诗','song-poetry','','[]','箇是一孤兒，曾聞事母時。',24,'全唐诗/poet.song.225000.json','["箇是一孤兒，曾聞事母時。", "身能幾許大，却佩國安危。"]'),
('9dc5cf31-a98a-4281-a97b-71e6e0f72c1f','元德秀','林同','宋','宋诗','song-poetry','','[]','進士能毋舉，偏親可忍離。',24,'全唐诗/poet.song.225000.json','["進士能毋舉，偏親可忍離。", "紫芝亦良苦，負母入京師。"]'),
('f9755214-b31a-4755-b44b-1daf978e755a','穆寧','林同','宋','宋诗','song-poetry','','[]','儻非親所樂，至枉道而行。',24,'全唐诗/poet.song.225000.json','["儻非親所樂，至枉道而行。", "雖以三牲養，難辭不孝名。"]'),
('40467b55-f6a4-4136-b170-cf17e3a392a2','侯程','林同','宋','宋诗','song-poetry','','[]','三年天下共，胡爾獨終身。',24,'全唐诗/poet.song.225000.json','["三年天下共，胡爾獨終身。", "無處著深痛，何心求過人。"]'),
('7316a83b-6213-408b-bc10-658262b9b24f','李唐','林同','宋','宋诗','song-poetry','','[]','我念卿毋怪，難拚膝上兒。',24,'全唐诗/poet.song.225000.json','["我念卿毋怪，難拚膝上兒。", "好將南內意，說與肅宗知。"]'),
('61f5545b-ce7a-4221-b5f5-1ba4c08fce96','韓滉','林同','宋','宋诗','song-poetry','','[]','謹勿第門壞，那容堂廡增。',24,'全唐诗/poet.song.225000.json','["謹勿第門壞，那容堂廡增。", "父猶足乎此，我顧莫之承。"]'),
('ebe7e4a9-8fc4-47e0-921a-5ce577e60972','賈直言','林同','宋','宋诗','song-poetry','','[]','幾曾聞飲鴆，有不隕其身。',24,'全唐诗/poet.song.225000.json','["幾曾聞飲鴆，有不隕其身。", "那得獨全活，天應知代親。"]'),
('6e7575fa-b3a7-49b3-a056-cb523a4f4f1c','李景讓','林同','宋','宋诗','song-poetry','','[]','既爾家能孝，還於國盡忠。',24,'全唐诗/poet.song.225000.json','["既爾家能孝，還於國盡忠。", "誰宜舉斯爵，知是莫如公。"]'),
('e5836c13-49dd-415c-9050-c0479a2d7933','韓愈','林同','宋','宋诗','song-poetry','','[]','未有子之孝，而公不用情。',24,'全唐诗/poet.song.225000.json','["未有子之孝，而公不用情。", "大書甄濟傳，更作董生行。"]'),
('f95d6a5c-be7c-4732-a0e5-f7806dbc0e9d','柳宗元','林同','宋','宋诗','song-poetry','','[]','乃翁定奇士，先友盡斯人。',24,'全唐诗/poet.song.225000.json','["乃翁定奇士，先友盡斯人。", "福畤智已故，儀曹意轉新。"]'),
('e3a97ae4-9867-46d8-a28f-41259110be44','甄逢','林同','宋','宋诗','song-poetry','','[]','史書良爲稹，褒詔却因袁。',24,'全唐诗/poet.song.225000.json','["史書良爲稹，褒詔却因袁。", "足使濟不朽，何堪逢自言。"]'),
('a690424d-0fc9-4c2f-8230-2ca024f1bc14','董召南','林同','宋','宋诗','song-poetry','','[]','躬稼復樵漁，養親還讀書。',24,'全唐诗/poet.song.225000.json','["躬稼復樵漁，養親還讀書。", "不聞官賜帛，惟見吏催租。"]'),
('730fd6bc-34be-470c-89c6-309805f26584','李興','林同','宋','宋诗','song-poetry','','[]','刲股如爲孝，還應載聖經。',24,'全唐诗/poet.song.225000.json','["刲股如爲孝，還應載聖經。", "莫明柳子意，因甚取殘形。"]'),
('85eababb-ccd0-4827-ad5e-c6b488e91cb9','何蕃','林同','宋','宋诗','song-poetry','','[]','五載莫歸省，雙親孰問安。',24,'全唐诗/poet.song.225000.json','["五載莫歸省，雙親孰問安。", "固云親有命，不謂我何顔。"]'),
('63803c78-dfe1-48ac-b761-dba0fd320e87','鄭潛曜','林同','宋','宋诗','song-poetry','','[]','願以身代母，書焚上徹天。',24,'全唐诗/poet.song.225000.json','["願以身代母，書焚上徹天。", "若非神許我，未必字依然。"]'),
('2aa82096-1a82-4012-b7cc-9b3d70f598b9','裴敬彝','林同','宋','宋诗','song-poetry','','[]','親命懸醫手，敢將親命輕。',24,'全唐诗/poet.song.225000.json','["親命懸醫手，敢將親命輕。", "爲輿不辭往，重母故身迎。"]'),
('9292b29a-84ab-4d71-9e55-2496d331c30a','張志寬','林同','宋','宋诗','song-poetry','','[]','何忽省母病，每因身疾知。',24,'全唐诗/poet.song.225000.json','["何忽省母病，每因身疾知。", "可憐張里正，尚得令君疑。"]'),
('1ade34c3-92df-402d-b700-ec0b77e2d8bd','趙隠','林同','宋','宋诗','song-poetry','','[]','至今說花縣，當日奉潘輿。',24,'全唐诗/poet.song.225000.json','["至今說花縣，當日奉潘輿。", "未必若趙母，囘班候起居。"]'),
('fa1b2d78-86bc-4b5f-b0fb-4fd3b4e38664','路隋','林同','宋','宋诗','song-poetry','','[]','兒貌酷類父，母知兒不知。',24,'全唐诗/poet.song.225000.json','["兒貌酷類父，母知兒不知。", "可堪引鏡照，正復益兒悲。"]'),
('b4aafea9-6956-4333-a617-6b88bdf3d1c2','李訥','林同','宋','宋诗','song-poetry','','[]','先人敝廬在，觸目百悲辛。',24,'全唐诗/poet.song.225000.json','["先人敝廬在，觸目百悲辛。", "忍作優笑地，圖娛權貴人。"]'),
('c89b6af0-3157-4319-bfb4-32ea035189d6','許孝謹','林同','宋','宋诗','song-poetry','','[]','既不忍飲乳，還能知奉親。',24,'全唐诗/poet.song.225000.json','["既不忍飲乳，還能知奉親。", "何曾自人教，端是出天真。"]'),
('3f464bcc-f8ab-4f50-9fd1-a9d2389790fd','柳玭','林同','宋','宋诗','song-poetry','','[]','名父難爲子，纖瑕即辱身。',24,'全唐诗/poet.song.225000.json','["名父難爲子，纖瑕即辱身。", "直須留面目，他日見先人。"]'),
('79daa297-89de-45cf-9d07-25c0831ab61b','韋溫','林同','宋','宋诗','song-poetry','','[]','常恐愧屋漏，追懷在室詩。',24,'全唐诗/poet.song.225000.json','["常恐愧屋漏，追懷在室詩。", "可憐忍死誦，不負乃今知。"]'),
('a61ce056-227e-42ec-9987-48464d518614','林欑','林同','宋','宋诗','song-poetry','','[]','七閩獨莆郡，雙闕鬰相望。',24,'全唐诗/poet.song.225000.json','["七閩獨莆郡，雙闕鬰相望。", "豈識林孝子，曾來尉福唐。"]'),
('613041ab-4cf7-4fc3-9743-f04fa82bc168','釋迦','林同','宋','宋诗','song-poetry','','[]','入般涅槃際，拳拳報母知。',24,'全唐诗/poet.song.225000.json','["入般涅槃際，拳拳報母知。", "從棺更湧出，爲母說分離。"]'),
('f06bc4bc-e72d-4cb9-89ad-7ee25903e98a','老子','林同','宋','宋诗','song-poetry','','[]','子之於父母，毋以有其身。',24,'全唐诗/poet.song.225000.json','["子之於父母，毋以有其身。", "老子玄虛祖，諄諄此語人。"]'),
('6c4c2d42-15dc-436d-9bbd-605ea2e15f5a','孝悌王','林同','宋','宋诗','song-poetry','','[]','七星明歷歷，萬古仰煌煌。',24,'全唐诗/poet.song.225000.json','["七星明歷歷，萬古仰煌煌。", "誰識斗宮內，中居孝悌王。"]'),
('5bc86ec9-16f0-4457-959f-ca7a0dd0d7ea','目連會','林同','宋','宋诗','song-poetry','','[]','能將身入地，拔取母生天。',24,'全唐诗/poet.song.225000.json','["能將身入地，拔取母生天。", "歲歲盂蘭會，今猶說目連。"]'),
('3d5327a0-b108-41ef-8ac8-578382dc6043','許真君','林同','宋','宋诗','song-poetry','','[]','鄉以孝廉舉，仙爲孝道宗。',24,'全唐诗/poet.song.225000.json','["鄉以孝廉舉，仙爲孝道宗。", "謂予言不信，君請問蘭公。"]'),
('e0ce9a4e-0544-45fe-9aeb-cf5e6621d463','吳真君','林同','宋','宋诗','song-poetry','','[]','何事不驅蚊，癯然牀下身。',24,'全唐诗/poet.song.225000.json','["何事不驅蚊，癯然牀下身。", "傷膚非所懼，所懼去傷親。"]'),
('c4bc3183-562a-4f10-bf33-0d1e89b70230','六祖','林同','宋','宋诗','song-poetry','','[]','新州在何處，有箇養親人。',24,'全唐诗/poet.song.225000.json','["新州在何處，有箇養親人。", "一旦成佛去，那知昔賣薪。"]'),
('fb51cd5b-5bb9-471c-b6e3-5e5d8e012f20','睦州','林同','宋','宋诗','song-poetry','','[]','捨俗還將母，禪關晦迹深。',24,'全唐诗/poet.song.225000.json','["捨俗還將母，禪關晦迹深。", "共呼擔板漢，誰識織蒲心。"]'),
('0ee37ed0-5b8b-430b-a288-d6a2ac672a51','蘇仙公','林同','宋','宋诗','song-poetry','','[]','世傳蘇氏子，白日去登仙。',24,'全唐诗/poet.song.225000.json','["世傳蘇氏子，白日去登仙。", "念母留空柜，敲時即得錢。"]'),
('202224a2-a31a-488e-918d-0d59cc199209','寒山子','林同','宋','宋诗','song-poetry','','[]','鍋裏爺娘語，寒山太猛生。',24,'全唐诗/poet.song.225000.json','["鍋裏爺娘語，寒山太猛生。", "不妨時著眼，直是得人驚。"]'),
('41138a1f-6a66-4ed3-a4e2-993bb7cd2e4d','辟司徒妻','林同','宋','宋诗','song-poetry','','[]','君父今安在，諄諄免矣乎。',24,'全唐诗/poet.song.225000.json','["君父今安在，諄諄免矣乎。", "可憐齊女子，不問辟司徒。"]'),
('70f917fd-9e47-4938-bc64-0d37f9b18d94','雍姬','林同','宋','宋诗','song-poetry','','[]','可憐姬告母，父孰與夫親。',24,'全唐诗/poet.song.225000.json','["可憐姬告母，父孰與夫親。", "能置此一問，未爲愚婦人。"]'),
('fa54682d-37c3-4889-af23-4a5d73838e6d','衛女','林同','宋','宋诗','song-poetry','','[]','歸寧不可得，何以寫吾憂。',24,'全唐诗/poet.song.225000.json','["歸寧不可得，何以寫吾憂。", "不似肥泉水，悠悠淇上流。"]'),
('bdbee68e-c314-4340-acf1-0ef414a3e037','北宮女','林同','宋','宋诗','song-poetry','','[]','妾身期不嫁，至老養雙親。',24,'全唐诗/poet.song.225000.json','["妾身期不嫁，至老養雙親。", "何意趙威后，殷勤問使人。"]'),
('cccd8d01-bfce-4290-929f-2cc2b4f65ce5','秋胡子妻','林同','宋','宋诗','song-poetry','','[]','妾面羞君面，君心異妾心。',24,'全唐诗/poet.song.225000.json','["妾面羞君面，君心異妾心。", "那能不念母，却遺別人金。"]'),
('94d4e714-e1d4-40be-989e-1ae7e6e8b5bc','趙津吏女','林同','宋','宋诗','song-poetry','','[]','儻得代父死，誠非愛妾身。',24,'全唐诗/poet.song.225000.json','["儻得代父死，誠非愛妾身。", "不圖君聘妾，向道有嚴親。"]'),
('6a43998b-663a-4394-b9db-b71261eb7bc0','如姬','林同','宋','宋诗','song-poetry','','[]','底事能令妾，爲君死不辭。',24,'全唐诗/poet.song.225000.json','["底事能令妾，爲君死不辭。", "不思君遣客，報妾父讎時。"]'),
('6cb292d3-50b5-43f9-97c1-5e4d1861d244','緹縈','林同','宋','宋诗','song-poetry','','[]','仁矣文皇詔，悲哉少女書。',24,'全唐诗/poet.song.225000.json','["仁矣文皇詔，悲哉少女書。", "至今民受賜，非但活淳于。"]'),
('4f5e1d05-612e-4495-9c0a-5457106931fe','陳孝婦','林同','宋','宋诗','song-poetry','','[]','妾昔與夫別，夫曾共妾言。',24,'全唐诗/poet.song.225000.json','["妾昔與夫別，夫曾共妾言。", "忍能幸夫死，不復顧姑存。"]'),
('15a356df-9d33-44e3-a95a-6f5be1b613f9','東海孝婦','林同','宋','宋诗','song-poetry','','[]','如何殺一婦，能致旱三年。',24,'全唐诗/poet.song.225000.json','["如何殺一婦，能致旱三年。", "婦孝無知者，知之惟老天。"]'),
('0feb5378-b09b-4bb7-a69b-7cc6245bca99','曹娥','林同','宋','宋诗','song-poetry','','[]','上虞一巫女，名乃至今垂。',24,'全唐诗/poet.song.225000.json','["上虞一巫女，名乃至今垂。", "端的由純孝，非專在好辭。"]'),
('92423ff8-fc93-43cd-b7c6-170609eb0797','梁夫人嬺','林同','宋','宋诗','song-poetry','','[]','能返母萬里，還榮父九原。',24,'全唐诗/poet.song.225000.json','["能返母萬里，還榮父九原。", "可憐帝有母，亦自待人言。"]'),
('ac1e1783-4cd0-4b81-b381-13e43912e991','孔融女','林同','宋','宋诗','song-poetry','','[]','不憂身即死，惟恐死無知。',24,'全唐诗/poet.song.225000.json','["不憂身即死，惟恐死無知。", "儻得從父母，寧非我所期。"]'),
('10173238-ca4f-4bb1-9770-2c4747252d1c','宣文君','林同','宋','宋诗','song-poetry','','[]','難把父書讀，祇因手澤存。',24,'全唐诗/poet.song.225000.json','["難把父書讀，祇因手澤存。", "遺言汝可受，忍使世無聞。"]'),
('ccbec25e-de3f-4abf-b3aa-9085d32a4082','宛陵女子','林同','宋','宋诗','song-poetry','','[]','異哉一女子，獨抱母啼號。',24,'全唐诗/poet.song.225000.json','["異哉一女子，獨抱母啼號。", "非但脫虎口，還能落獸毛。"]'),
('6078cb0b-d40a-47ae-900c-fb0dff6b8423','盧元禮妻','林同','宋','宋诗','song-poetry','','[]','貞孝謚已美，何堪復女宗。',24,'全唐诗/poet.song.225000.json','["貞孝謚已美，何堪復女宗。", "一朝下明詔，千載被流風。"]'),
('85d70ac0-39d4-474e-8258-e4f0bf5b826b','木蘭','林同','宋','宋诗','song-poetry','','[]','謹勿悲生女，均之有至情。',24,'全唐诗/poet.song.225000.json','["謹勿悲生女，均之有至情。", "縈能贖父罪，蘭亦替爺征。"]'),
('05ab368b-2440-4103-ada2-b78e8df13fff','鄭義宗妻','林同','宋','宋诗','song-poetry','','[]','抵死侍姑側，寧知有妾身。',24,'全唐诗/poet.song.225000.json','["抵死侍姑側，寧知有妾身。", "若懷白刃顧，尚得謂之人。"]'),
('73a595bd-1c92-4ff1-895f-2a03c782a032','李孝女','林同','宋','宋诗','song-poetry','','[]','奔喪脫賊手，廬墓至終身。',24,'全唐诗/poet.song.225000.json','["奔喪脫賊手，廬墓至終身。", "此大丈夫事，誰云一婦人。"]'),
('3d2cf0de-2eb0-4082-8816-fcab35dcf832','唐氏婦','林同','宋','宋诗','song-poetry','','[]','姑今病且死，頗愧婦恩深。',24,'全唐诗/poet.song.225000.json','["姑今病且死，頗愧婦恩深。", "但願婦有子，皆如婦用心。"]'),
('423727d4-e328-4419-9fd4-a92cfbc5025d','東夷大連少連','林同','宋','宋诗','song-poetry','','[]','大連少連者，夫子筆之書。',24,'全唐诗/poet.song.225000.json','["大連少連者，夫子筆之書。", "誰謂東夷子，而於喪善居。"]'),
('52154195-414f-4400-831e-d183e82cb1a5','若鞮單于','林同','宋','宋诗','song-poetry','','[]','漢語雜胡語，堪嗤莽太愚。',24,'全唐诗/poet.song.225000.json','["漢語雜胡語，堪嗤莽太愚。", "安知若鞮字，已是孝單于。"]'),
('1848bada-1ea9-4ed2-8eec-9096399dc3a3','休屠王子金日磾','林同','宋','宋诗','song-poetry','','[]','牧馬一胡兒，如何却受遺。',24,'全唐诗/poet.song.225000.json','["牧馬一胡兒，如何却受遺。", "多因漢宮裏，泣拜畫閼氏。"]'),
('c4e651e8-d442-452c-87a5-2f5634f4f6e6','西羌東吾','林同','宋','宋诗','song-poetry','','[]','循循祇自守，何獨此羌然。',24,'全唐诗/poet.song.225000.json','["循循祇自守，何獨此羌然。", "直以父在漢，忍將身犯邊。"]'),
('40f9b208-8ca1-4c36-9996-4a7b8859f4fd','號吾','林同','宋','宋诗','song-poetry','','[]','如何降塞下，不復戀羌中。',24,'全唐诗/poet.song.225000.json','["如何降塞下，不復戀羌中。", "既是能將母，還應知向風。"]'),
('96ce19d0-f134-4658-97c0-7d4b5e17b9cf','百濟王扶餘義慈','林同','宋','宋诗','song-poetry','','[]','夷方雖爾異，天性本然同。',24,'全唐诗/poet.song.225000.json','["夷方雖爾異，天性本然同。", "自昔聞曾子，如今在海東。"]'),
('f0a5a2ff-6ff8-4939-88e7-50cb7a43d9df','扶桑國','林同','宋','宋诗','song-poetry','','[]','不食至七日，能將禮自居。',24,'全唐诗/poet.song.225000.json','["不食至七日，能將禮自居。", "既然嚴像設，亦復奠朝晡。"]'),
('7ea82fce-4463-415a-bff1-0016c6311373','吐谷渾葉延','林同','宋','宋诗','song-poetry','','[]','父讎已屠膾，射草復何爲。',24,'全唐诗/poet.song.225000.json','["父讎已屠膾，射草復何爲。", "豈不念無益，其如罔極悲。"]'),
('d4d7cf5c-72d2-4957-b0a7-1707c92fc0bb','回紇','林同','宋','宋诗','song-poetry','','[]','瞥爾驚吾父，同然拜令公。',24,'全唐诗/poet.song.225000.json','["瞥爾驚吾父，同然拜令公。", "遥知恩義重，恰似與真同。"]'),
('fb4a0e93-9d70-41fa-bc5e-fb3f7d45f355','沙陀阿跌光進','林同','宋','宋诗','song-poetry','','[]','三年不歸寢，至性切於親。',24,'全唐诗/poet.song.225000.json','["三年不歸寢，至性切於親。", "不信沙陀種，還生如此人。"]'),
('dae6d4c3-8822-464a-bde5-573976dfc36e','烏','林同','宋','宋诗','song-poetry','','[]','靈烏噪何許，反哺向中林。',24,'全唐诗/poet.song.225000.json','["靈烏噪何許，反哺向中林。", "人可不如鳥，而無憂母心。"]'),
('6c33593e-68de-41f7-b5f9-17ac99525bfa','鶴','林同','宋','宋诗','song-poetry','','[]','好是鶴鳴陰，居然子和聲。',24,'全唐诗/poet.song.225000.json','["好是鶴鳴陰，居然子和聲。", "休云氣所感，自是物之情。"]'),
('28cbbb0d-6b20-4a83-a03d-e1bfc743e243','燕雀','林同','宋','宋诗','song-poetry','','[]','共母一屋下，寧知屋欲然。',24,'全唐诗/poet.song.225000.json','["共母一屋下，寧知屋欲然。", "不須譏寡智，相哺政堪憐。"]'),
('543de38a-e7b6-41c0-b830-a700f6e6c6b7','虎狼','林同','宋','宋诗','song-poetry','','[]','虎狼不仁也，何乃謂之仁。',24,'全唐诗/poet.song.225000.json','["虎狼不仁也，何乃謂之仁。", "仁之於父子，父子亦相親。"]'),
('1e7c8595-4f9d-4201-995f-dd9529e8beb4','猿','林同','宋','宋诗','song-poetry','','[]','不忍身逃箭，知爲母塞瘡。',24,'全唐诗/poet.song.225000.json','["不忍身逃箭，知爲母塞瘡。", "人心有如此，獸面本何常。"]'),
('e40dfe30-c5eb-4f44-b9ec-08401c6a17f9','犬','林同','宋','宋诗','song-poetry','','[]','食肉隠兩頰，飼母向頹垣。',24,'全唐诗/poet.song.225000.json','["食肉隠兩頰，飼母向頹垣。", "終感主養母，能將死報恩。"]'),
('133c2867-8246-4dea-936b-78d00f72ed4b','羊羔','林同','宋','宋诗','song-poetry','','[]','已分机上肉，誰藏腹下刀。',24,'全唐诗/poet.song.225000.json','["已分机上肉，誰藏腹下刀。", "安知羊不死，乃復自羊羔。"]'),
('df79fdaf-90c5-47ea-9551-b6cddf708aa5','豺獺','林同','宋','宋诗','song-poetry','','[]','曾聞豺祭獸，還見獺陳魚。',24,'全唐诗/poet.song.225000.json','["曾聞豺祭獸，還見獺陳魚。", "人苟不知祭，能如豺獺乎。"]'),
('2d5c95cf-e292-42b9-993a-66f5dcc34429','蛇','林同','宋','宋诗','song-poetry','','[]','似有人傳訃，來從榛莽中。',24,'全唐诗/poet.song.225000.json','["似有人傳訃，來從榛莽中。", "叩頭至流血，垂泣有哀容。"]'),
('71776987-04e8-45d9-8af7-80e2bb871be3','青蚨','林同','宋','宋诗','song-poetry','','[]','子母不相離，何心辦搗蚨。',24,'全唐诗/poet.song.225000.json','["子母不相離，何心辦搗蚨。", "忍能利銅臭，不枉喚錢愚。"]'),
('77f46534-a089-4c6f-8195-9b8941a066bd','偈頌四十一首  其一','釋普寧','宋','宋诗','song-poetry','','[]','迷悟兩門，聖凡二路。',26,'全唐诗/poet.song.225000.json','["迷悟兩門，聖凡二路。", "總與諸人開闢了也，普請一時證入。"]'),
('71df0cba-727e-41eb-b7f7-a4204945dcd0','偈頌四十一首  其二','釋普寧','宋','宋诗','song-poetry','','[]','坐斷千差，當陽烜赫。',24,'全唐诗/poet.song.225000.json','["坐斷千差，當陽烜赫。", "任是須彌燈王，也須望空斫額。"]'),
('45b7fcd3-903d-4276-adba-f5704dac3143','偈頌四十一首  其三','釋普寧','宋','宋诗','song-poetry','','[]','釋迦不出世，四十九年說。',24,'全唐诗/poet.song.225000.json','["釋迦不出世，四十九年說。", "祖師不西來，少林有妙訣。"]'),
('96b3fe12-7223-497f-9d5e-079d4b08c220','偈頌四十一首  其四','釋普寧','宋','宋诗','song-poetry','','[]','披野干皮，作獅子吼。',28,'全唐诗/poet.song.225000.json','["披野干皮，作獅子吼。", "指東爲西，將無作有，驚起法身藏北斗。"]'),
('2954b154-9717-4de1-9355-d066cf02abf0','偈頌四十一首  其五','釋普寧','宋','宋诗','song-poetry','','[]','荷葉團團團似鏡，菱角尖尖尖似錐。',32,'全唐诗/poet.song.225000.json','["荷葉團團團似鏡，菱角尖尖尖似錐。", "風吹柳絮毛毬走，雨打梨花蛺蝶飛。"]'),
('828e7962-8a13-4116-90b6-bdc9da2d78e6','偈頌四十一首  其六','釋普寧','宋','宋诗','song-poetry','','[]','一夏九十日，不覺已過半。',78,'全唐诗/poet.song.225000.json','["一夏九十日，不覺已過半。", "管带牯牛兒，切忌隨物轉。", "緊把鼻頭索，莫放令寬緩。", "如是十二時，時時無間斷。", "收得純熟，斥之不去。", "受人言語，不動不變。", "覿面當機，當機覿面。"]'),
('c75e206d-e9e3-4995-a930-6afc27f9d05d','偈頌四十一首  其七','釋普寧','宋','宋诗','song-poetry','','[]','目前無法，意在目前。',44,'全唐诗/poet.song.225000.json','["目前無法，意在目前。", "東西十萬，南北八千。", "達磨不來東土，二祖不往西天。", "點檢將來，只見一邊。"]'),
('c031978d-8a2a-4732-ba39-83df0fb8a4a2','偈頌四十一首  其八','釋普寧','宋','宋诗','song-poetry','','[]','沒絃琴，指趣深。',34,'全唐诗/poet.song.225000.json','["沒絃琴，指趣深。", "尖新曲調，須遇知音。", "高山流水無窮意，落落斷崖千萬尋。"]'),
('cad36d4a-f089-4b14-9c04-81601ee870bd','偈頌四十一首  其九','釋普寧','宋','宋诗','song-poetry','','[]','寒食清明節，家家拜掃時。',60,'全唐诗/poet.song.225000.json','["寒食清明節，家家拜掃時。", "木人空嘆息，石女泪雙垂。", "惟有林下道人，絕學無爲。", "百不會，百不知。", "拈起少林無孔笛，逆風吹了順風吹。"]'),
('aef39717-17b0-4b58-a288-edf02fe0576b','偈頌四十一首  其一○','釋普寧','宋','宋诗','song-poetry','','[]','諸方安居結制，靈巖結制安居。',36,'全唐诗/poet.song.225000.json','["諸方安居結制，靈巖結制安居。", "雖是一般規矩，於中大有差殊。", "趙州東壁掛葫蘆。"]'),
('943db221-b747-4f3d-9da0-c4edb6b0f25f','偈頌四十一首  其一一','釋普寧','宋','宋诗','song-poetry','','[]','拄杖子，無偏黨。',40,'全唐诗/poet.song.225000.json','["拄杖子，無偏黨。", "遍界不曾藏，通身無影像。", "妖怪盡勦除，佛魔俱掃蕩。", "普天皇道無遮障。"]'),
('6f596843-7919-4bbd-b4a1-ebfafb4a3cd3','偈頌四十一首  其一二','釋普寧','宋','宋诗','song-poetry','','[]','頑處非常放軟頑，偏能陸地要撐船。',56,'全唐诗/poet.song.225000.json','["頑處非常放軟頑，偏能陸地要撐船。", "驀然撐向龍門去，蹤跡不知往那邊。", "幾多望斷空惆悵，亦復嗟嘆泪潸然，安得鸞膠續斷絃。"]'),
('fb3cdfc7-3e88-46f7-a553-2b1f3dcd70ea','偈頌四十一首  其一三','釋普寧','宋','宋诗','song-poetry','','[]','我有一句子，不封亦不樹。',24,'全唐诗/poet.song.225000.json','["我有一句子，不封亦不樹。", "不在舌頭邊，亦非思憶處。"]'),
('9e694943-2ff7-4739-bd83-784eb0a3100b','偈頌四十一首  其一四','釋普寧','宋','宋诗','song-poetry','','[]','拄杖子，化爲龍。',54,'全唐诗/poet.song.225000.json','["拄杖子，化爲龍。", "拏雲攫霧，妙應難窮。", "霈然洪霔，四海皆通。", "五穀結實，萬物歸功。", "鼓腹謳歌忘世事，太陽依舊海門東。"]'),
('c5468926-ab62-4622-9611-5dd99df8f3e5','偈頌四十一首  其一五','釋普寧','宋','宋诗','song-poetry','','[]','直下猶難會，尋言轉更賒。',24,'全唐诗/poet.song.225000.json','["直下猶難會，尋言轉更賒。", "若言佛與祖，特地隔天涯。"]'),
('9a5c8a59-25e5-4e60-b408-3dbb21e6849c','偈頌四十一首  其一六','釋普寧','宋','宋诗','song-poetry','','[]','拆東籬，補西壁。',32,'全唐诗/poet.song.225000.json','["拆東籬，補西壁。", "從空架空，以楔出楔。", "佗時聳壑昂霄，須信不勞餘力。"]'),
('d212d19c-0840-48cd-9de2-e7ae78d370e1','偈頌四十一首  其一七','釋普寧','宋','宋诗','song-poetry','','[]','我此門風，孤危不立。',24,'全唐诗/poet.song.225000.json','["我此門風，孤危不立。", "若是臨濟兒孫，便請單刀直入。"]'),
('db6afebe-a9e3-4696-ae0e-4331a85dada3','偈頌四十一首  其一八','釋普寧','宋','宋诗','song-poetry','','[]','出現在楊州，留錫於此地。',58,'全唐诗/poet.song.225000.json','["出現在楊州，留錫於此地。", "寶塔凌高空，聲光動萬里。", "利物應群機，如月分衆水。", "我來爇瓣香，一瞻一頂禮。", "從教人道自倒還自起。"]'),
('556a662e-4d6c-46a6-9662-d7922e8d4f3f','偈頌四十一首  其一九','釋普寧','宋','宋诗','song-poetry','','[]','向上一路滑，壁立千仞險。',26,'全唐诗/poet.song.225000.json','["向上一路滑，壁立千仞險。", "南禪不立階級，直與當頭坐斷。"]'),
('35a7e8f0-2000-4eae-846d-56b82650fbf7','偈頌四十一首  其二○','釋普寧','宋','宋诗','song-poetry','','[]','折脚鐺，破木杓。',36,'全唐诗/poet.song.225000.json','["折脚鐺，破木杓。", "無柄霸，難摸索。", "橫拈倒用，破二作三。", "正按傍提，七穿八穴。"]'),
('7313c2c3-315c-4817-8078-83c996fa1a90','偈頌四十一首  其二一','釋普寧','宋','宋诗','song-poetry','','[]','心隨萬境轉，轉處實能幽。',39,'全唐诗/poet.song.225000.json','["心隨萬境轉，轉處實能幽。", "隨流認得性，無喜亦無憂。", "山僧官差不自由，只得隨流入流。"]'),
('043f25ce-1d76-4720-8b51-9aca91662262','偈頌四十一首  其二二','釋普寧','宋','宋诗','song-poetry','','[]','東澗水，清且泚。',80,'全唐诗/poet.song.225000.json','["東澗水，清且泚。", "源遠流長，波騰鼎沸。", "從這裏入，不知其幾。", "是則是，只如國一禪師經過梁溪，驀將泗州大聖鼻孔一捏，直得無處出氣。", "爲復壓良爲賤，爲復神通游戲。", "君子可入。"]'),
('8bedcd3b-c24a-4ca0-874a-a49177f3edd9','偈頌四十一首  其二三','釋普寧','宋','宋诗','song-poetry','','["\u897f\u6e56"]','弟應兄呼，自揚家醜。',36,'全唐诗/poet.song.225000.json','["弟應兄呼，自揚家醜。", "倒却剎竿，全機漏逗。", "雖有西湖月如晝，何似南禪鐵苕箒。"]'),
('15f6a42d-e391-40c3-84ff-268268e5202a','偈頌四十一首  其二四','釋普寧','宋','宋诗','song-poetry','','[]','金烏急，玉兔速，百歲光陰一瞬息。',104,'全唐诗/poet.song.225000.json','["金烏急，玉兔速，百歲光陰一瞬息。", "惟有拄杖子，硬葛狚，黑粼皴，勿變遷，無面目。", "三月護生，九旬禁足。", "酌然使得十二時，不被十二時催促。", "任他門外紅塵擾擾，來往憧憧，肥馬碌碌，瘦馬碌碌。", "驀然翻變化爲龍，爲雨爲霖俱莫測。"]'),
('ce4372c3-040f-4f85-aa4a-9a5e7cde946a','偈頌四十一首  其二五','釋普寧','宋','宋诗','song-poetry','','[]','梁渚溪邊下直鈎，波翻浪輥費牽抽。',55,'全唐诗/poet.song.225000.json','["梁渚溪邊下直鈎，波翻浪輥費牽抽。", "六年用盡腕頭力，收卷絲綸恁性遊。", "不著此岸，不著彼岸，不滯中流，欵乃一聲天地秋。"]'),
('673d1a05-1bb6-4ec9-bca6-d356d1567748','偈頌四十一首  其二六','釋普寧','宋','宋诗','song-poetry','','[]','出得油缸入醤缸，通身是口若爲談。',32,'全唐诗/poet.song.225000.json','["出得油缸入醤缸，通身是口若爲談。", "老拳尚有些筋力，拚命來機爲指南。"]'),
('d1ab80d7-fe08-410d-962d-06b671ebf423','偈頌四十一首  其二七','釋普寧','宋','宋诗','song-poetry','','[]','右脇纔生，便放拍盲。',50,'全唐诗/poet.song.225000.json','["右脇纔生，便放拍盲。", "指天指地，獨步縱橫。", "雲門要打殺，建長助掘坑。", "惡種從教不復萌，雖然也是賊過後張弓。"]'),
('09fba521-1fc6-4c7a-b0e9-a46d0fe53941','偈頌四十一首  其二八','釋普寧','宋','宋诗','song-poetry','','[]','昨日晴，今日雨。',96,'全唐诗/poet.song.225000.json','["昨日晴，今日雨。", "春夏交承，時節順序。", "一似林下衲僧，不越規矩。", "三月安居，克期而取。", "西天以蠟人冰，雲峰以鐵彈子。", "建長亦有一條活路，饑則餐，渴則飲，閑則坐，困則眠，以此爲據。", "諸人但任麽參，決不賺忤。"]'),
('df63c4ce-f72e-4b68-9708-bb82cdb0ce64','偈頌四十一首  其二九','釋普寧','宋','宋诗','song-poetry','','[]','解開布袋頭，縱橫得自由。',44,'全唐诗/poet.song.225000.json','["解開布袋頭，縱橫得自由。", "其住也無拘無束，其去也南州北州。", "放牧溈山水牯牛，不風流處也風流。"]'),
('72183b88-7b59-4dd1-9ceb-98fbffadd586','偈頌四十一首  其三○','釋普寧','宋','宋诗','song-poetry','','[]','爲國爲民運此心，果符虔禱獲豐榮。',32,'全唐诗/poet.song.225000.json','["爲國爲民運此心，果符虔禱獲豐榮。", "時清道泰封疆闊，合國歡呼賀太平。"]'),
('339fd9e3-fd0c-478c-97b7-e5e1a111e656','偈頌四十一首  其三一','釋普寧','宋','宋诗','song-poetry','','[]','一塵入正定，諸塵三昧起。',70,'全唐诗/poet.song.225000.json','["一塵入正定，諸塵三昧起。", "諸塵入正定，一塵三昧起。", "三昧與正受，土塊泥裏洗。", "咦，白日堂堂眼見鬼。", "非不非，是不是。", "甲子乙丑海中金，丙午丁未天河水。"]'),
('f80a21f6-46da-457c-9f38-3cec16c161bc','偈頌四十一首  其三二','釋普寧','宋','宋诗','song-poetry','','["\u897f\u6e56"]','南山白額蟲，撞倒太白峰。',70,'全唐诗/poet.song.225000.json','["南山白額蟲，撞倒太白峰。", "直得西湖徹底枯竭，東海怒浪翻空。", "安漢圭峰拊掌，天台尊者槌胸。", "郎忙日本國裏打鼓，大唐國裏撞鐘。", "兄弟添十字，此意孰能窮。"]'),
('6aff4656-0a7e-45e7-9ba2-71f5bc9a2c1b','偈頌四十一首  其三三','釋普寧','宋','宋诗','song-poetry','','[]','同飲龍淵，同依師席。',124,'全唐诗/poet.song.225000.json','["同飲龍淵，同依師席。", "切瑳琢磨，相滋相益。", "分袂東西，各提祖令。", "越漠來投，心膽傾盡。", "執別恰恰一周，千里俯垂輝映。", "舉衆再奉慈光，無異撥雲見日。", "若是向上向下，總將靠之一壁。", "憶得凌霄蠱毒之家，水也不曾沾他一滴。", "阿呵呵，會也麽。", "青山不鎖長飛勢，滄海合知來處高。"]'),
('9d215f45-8731-4b69-b7d0-524f1f940230','偈頌四十一首  其三四','釋普寧','宋','宋诗','song-poetry','','[]','吾本來茲土，傳法救迷情。',24,'全唐诗/poet.song.225000.json','["吾本來茲土，傳法救迷情。", "一花開五葉，結果自然成。"]'),
('5f4daf14-7e85-42a3-8e87-d5d49bdba7fc','偈頌四十一首  其三五','釋普寧','宋','宋诗','song-poetry','','[]','人從天台來，却得西川信。',24,'全唐诗/poet.song.225000.json','["人從天台來，却得西川信。", "報道萬年松，生在石橋頂。"]'),
('1b4ae9c0-3b64-450a-ad5d-859cb7bc1c08','偈頌四十一首  其三六','釋普寧','宋','宋诗','song-poetry','','[]','近得遠來口傳信，報道年來頗安靜。',84,'全唐诗/poet.song.225000.json','["近得遠來口傳信，報道年來頗安靜。", "唯有太白瑞巖翁，撞破虛空有雜碎。", "驚起西川大蓬山上石女淚雙垂，引得扶桑巨福山中木人空嘆息。", "同飲龍淵無義水，手足義重如膠漆。", "斷絃安得鸞膠續。"]'),
('4dc14713-ac44-436c-9c87-72c2c01bfd37','偈頌四十一首  其三七','釋普寧','宋','宋诗','song-poetry','','[]','圓同太虛，無欠無餘。',20,'全唐诗/poet.song.225000.json','["圓同太虛，無欠無餘。", "良由取捨，所以不如。"]'),
('b0114052-085d-41f2-99be-0fa277ebfee5','偈頌四十一首  其三八','釋普寧','宋','宋诗','song-poetry','','[]','冬至寒食一百五，中有一轉平實語。',40,'全唐诗/poet.song.225000.json','["冬至寒食一百五，中有一轉平實語。", "缺齒老胡舉不全，賺他立雪人莽鹵。", "貓兒偏解捉老鼠。"]'),
('ddf177d6-6c0a-400c-a0a4-45f2a29d8e96','偈頌四十一首  其三九','釋普寧','宋','宋诗','song-poetry','','[]','臘月八夜眼見鬼，便開大口說道理。',32,'全唐诗/poet.song.225000.json','["臘月八夜眼見鬼，便開大口說道理。", "若向衲僧門下過，爛槌一頓無疑矣。"]'),
('bacf90dc-818b-47aa-b0a4-7ce087fab80e','偈頌四十一首  其四○','釋普寧','宋','宋诗','song-poetry','','[]','夢中演說六波羅，覺時同別苦問他。',32,'全唐诗/poet.song.225000.json','["夢中演說六波羅，覺時同別苦問他。", "今日最明重演說，更無一字有誵訛。"]'),
('1a6bf4ea-02b7-46e9-9b89-e88e19aea857','偈頌四十一首  其四一','釋普寧','宋','宋诗','song-poetry','','[]','每年三月十八，憶著痛恨入骨。',45,'全唐诗/poet.song.225000.json','["每年三月十八，憶著痛恨入骨。", "巨福山上望凌霄，萬重山海煙波闊。", "謾爇一炷兜羅木，唵，噴噴昻昻。"]'),
('65acc0d0-39c4-42a2-b61c-288f3b5f8542','樗寮字阿彌陀經書偈送最明寺殿','釋普寧','宋','宋诗','song-poetry','','[]','我有大經卷，量等三千界。',48,'全唐诗/poet.song.225000.json','["我有大經卷，量等三千界。", "親付最明殿，祝壽如滄海。", "但願得此經，當下明此心。", "的知胡達磨，元不在少林。"]'),
('d661c892-3116-42ee-9d1f-c173733f056d','最明寺殿契悟說付法偈','釋普寧','宋','宋诗','song-poetry','','[]','我無佛法一字說，子亦無心無所得。',32,'全唐诗/poet.song.225000.json','["我無佛法一字說，子亦無心無所得。", "無說無得無心中，釋迦親見燃燈佛。"]'),
('3ebad927-590d-462c-a5b9-935b10906589','最明寺殿悟道後贈之助道頌五首  其一','釋普寧','宋','宋诗','song-poetry','','[]','老僧初到與三拳，埋恨胸中結此冤。',32,'全唐诗/poet.song.225000.json','["老僧初到與三拳，埋恨胸中結此冤。", "痛恨忽消開正眼，方知吾不妄宣傳。"]'),
('123aa5a9-0130-4440-b9a2-a504cbeb3a15','最明寺殿悟道後贈之助道頌五首  其二','釋普寧','宋','宋诗','song-poetry','','[]','悟了還同未悟時，著衣喫飯順時宜。',32,'全唐诗/poet.song.225000.json','["悟了還同未悟時，著衣喫飯順時宜。", "起居動靜曾無別，始信拈花第二機。"]'),
('dd7c0311-bd2b-44bb-823c-bc0ee262d06b','最明寺殿悟道後贈之助道頌五首  其三','釋普寧','宋','宋诗','song-poetry','','[]','二十一年曾苦辛，尋經討論枉精神。',32,'全唐诗/poet.song.225000.json','["二十一年曾苦辛，尋經討論枉精神。", "驀然摸著娘生鼻，翻笑胡僧弄吻唇。"]'),
('d1b57737-26d0-4bc9-bf90-09ecfef8f198','最明寺殿悟道後贈之助道頌五首  其四','釋普寧','宋','宋诗','song-poetry','','[]','治國治民俱外事，存心存念自工夫。',32,'全唐诗/poet.song.225000.json','["治國治民俱外事，存心存念自工夫。", "心思路絕略觀看，佛也無兮法也無。"]'),
('8040a544-f87d-4dbb-93f8-e576b6a5b39d','最明寺殿悟道後贈之助道頌五首  其五','釋普寧','宋','宋诗','song-poetry','','[]','壬戌十月十六朝，虛空拳踢不相饒。',32,'全唐诗/poet.song.225000.json','["壬戌十月十六朝，虛空拳踢不相饒。", "等閑打破疑團後，大地黄金也合消。"]'),
('f4e0b38f-372c-4679-b770-f4f6b22c1d98','最明夢一善知識教訓堅固參禪醒後親繪供養越兩年值老僧到先來參禮果與夢見一同契悟後捧呈所畫頂相求贊','釋普寧','宋','宋诗','song-poetry','','[]','千煅萬煉工夫熟，感得夢見善知識。',63,'全唐诗/poet.song.225000.json','["千煅萬煉工夫熟，感得夢見善知識。", "力勸加工用行修，果獲契悟心滿足。", "自彰醜惡自涂糊，佛祖仰望俱失色。", "老僧更與添一重，急急如律令勑。"]'),
('fb9d2ca8-be1e-4c5f-bff4-0791b812e74d','偈頌二十一首  其一','釋普寧','宋','宋诗','song-poetry','','[]','檀那夢見大棟梁，高僧羅漢滿雲堂。',64,'全唐诗/poet.song.225000.json','["檀那夢見大棟梁，高僧羅漢滿雲堂。", "慷慨重新鋪蓋就，比之兜率更尤强。", "衲子辦道耐長久，成佛作祖法中王。", "下等愚迷無正念，鎔銅灌口卧鐵床。"]'),
('f185e64f-8f2c-4bb2-9862-5324a4b0b1d3','偈頌二十一首  其二','釋普寧','宋','宋诗','song-poetry','','[]','有處不是有，無處不是無。',24,'全唐诗/poet.song.225000.json','["有處不是有，無處不是無。", "有無不到處，馨香滿道塗。"]'),
('8caa824f-fcb2-40b2-a9fd-fc3334d69344','偈頌二十一首  其三','釋普寧','宋','宋诗','song-poetry','','[]','出水未出水，心疑生暗鬼。',24,'全唐诗/poet.song.225000.json','["出水未出水，心疑生暗鬼。", "鞏縣造茶瓶，一隻三箇嘴。"]'),
('56bacf41-e67e-4a07-aca8-a2ed4e02d197','偈頌二十一首  其四','釋普寧','宋','宋诗','song-poetry','','[]','青州布衫重七斤，由來錯認定盤星。',32,'全唐诗/poet.song.225000.json','["青州布衫重七斤，由來錯認定盤星。", "那知富士山孤峻，到頂須行三日程。"]'),
('4c17208c-48e5-4a20-b555-4a153b4fa166','偈頌二十一首  其五','釋普寧','宋','宋诗','song-poetry','','[]','東望大乘器，區區十萬里。',52,'全唐诗/poet.song.225000.json','["東望大乘器，區區十萬里。", "因這一著錯，累及人斷臂。", "彼錯猶且可，此錯無巴鼻。", "彼錯此錯訴之誰，倒拈鐵笛逆風吹。"]'),
('7b94f038-ae4a-4575-8752-6be360c8cd2b','偈頌二十一首  其六','釋普寧','宋','宋诗','song-poetry','','[]','夜夜明星現，時時兩眼開。',40,'全唐诗/poet.song.225000.json','["夜夜明星現，時時兩眼開。", "如何臘月八，特地嘆奇哉。", "引得隨邪逐惡者，至今一味狗來腮。"]'),
('d6dc02a6-f42d-4be0-91fd-359d1a33697d','偈頌二十一首  其七','釋普寧','宋','宋诗','song-poetry','','[]','無心遊此國，有心復宋國。',32,'全唐诗/poet.song.225000.json','["無心遊此國，有心復宋國。", "有心無心中，通天路頭活。", "拄杖頭邊挑日月。"]'),
('7226d583-9e40-4558-90f3-1fda00daf13a','偈頌二十一首  其八','釋普寧','宋','宋诗','song-poetry','','[]','衲僧門下，活路通天。',28,'全唐诗/poet.song.225000.json','["衲僧門下，活路通天。", "脚頭脚底，能方能圓。", "照顧踏破常住磚。"]'),
('5655a26e-972f-4711-96dc-aa3a8fb52b73','偈頌二十一首  其九','釋普寧','宋','宋诗','song-poetry','','[]','如何是佛殿裏底，無端開口便臭氣。',28,'全唐诗/poet.song.225000.json','["如何是佛殿裏底，無端開口便臭氣。", "掩鼻不及，只得五體投地。"]'),
('bb04c792-dbbb-4321-845e-15323aef5e25','偈頌二十一首  其一○','釋普寧','宋','宋诗','song-poetry','','[]','七佛引其前，維摩接其後。',24,'全唐诗/poet.song.225000.json','["七佛引其前，維摩接其後。", "一盲引衆盲，至今不唧𠺕。"]'),
('0c65e72c-ff88-4729-92bb-414008a39e44','偈頌二十一首  其一一','釋普寧','宋','宋诗','song-poetry','','[]','向上一路，千聖不傳。',20,'全唐诗/poet.song.225000.json','["向上一路，千聖不傳。", "等閑踏著，不直半錢。"]'),
('e608b48e-1f89-43b6-955a-d48ab7f08e9e','偈頌二十一首  其一二','釋普寧','宋','宋诗','song-poetry','','[]','拄杖頭邊，草鞋跟底。',99,'全唐诗/poet.song.225000.json','["拄杖頭邊，草鞋跟底。", "隨緣放曠，隠遁過時。", "豈謂業債難逃，復落他家綣繢，扶病拖泥带水。", "只得豎四橫三，乘時拽取。", "正續山與雲黄山鬭額，爲復是神通游戲。", "爲復是法爾如然。", "不見道，浙東山，浙西水，四海五湖皇化裏。"]'),
('7d50f8df-53c9-46a0-905e-7d810952a8ab','偈頌二十一首  其一三','釋普寧','宋','宋诗','song-poetry','','[]','久嚮雙林，可曾遊歷。',109,'全唐诗/poet.song.225000.json','["久嚮雙林，可曾遊歷。", "及乎到來，果是殊別。", "山環水繞，寺廣人稀。", "內空外空，無彼無此。", "彷彿威音那畔，分明古佛家風。", "不妨按下雲頭，鉢囊暫且高掛。", "坐則同坐，行則同行。", "同苦同甘，同憂同樂。", "必竟事作麽生，但看人情若好，自然喫水也肥。"]'),
('6382e76f-a1b8-477f-bc0b-b1ede7d1f5d0','偈頌二十一首  其一四','釋普寧','宋','宋诗','song-poetry','','[]','破砂盆，漏燈盞。',70,'全唐诗/poet.song.225000.json','["破砂盆，漏燈盞。", "死偷心，滅正眼。", "近之則愈遠，親之則愈疎。", "瞻之在前，忽然在後。", "全明全暗，雙放雙收。", "番復看來，當甚熱大。", "是則也是，只如進前叉手。"]'),
('70c52379-a596-48d1-8eaf-7f964bcf2cae','偈頌二十一首  其一五','釋普寧','宋','宋诗','song-poetry','','[]','一陽來復，暖囘幽谷。',64,'全唐诗/poet.song.225000.json','["一陽來復，暖囘幽谷。", "雲黄山上，喜氣浮空。", "綉水溪頭，疏影含玉。", "老胡不會轉身句，無節目中生節目。", "累及拄杖子，皮膚脫落盡，通身烏律漆。"]'),
('b32674ae-8efe-4aad-babd-1abe98d44071','偈頌二十一首  其一六','釋普寧','宋','宋诗','song-poetry','','[]','雲門一曲，調高千古。',83,'全唐诗/poet.song.225000.json','["雲門一曲，調高千古。", "子細推窮，從來無譜。", "此曲只應天上有，大士得來無本據。", "今日當陽分付，新年諸路化主。", "在處富有知音，遇著知音舉似。", "舉似則不無，且道是何曲調，臘月二十五。"]'),
('1a1ca6cb-cbc8-4947-af25-64cc618c306c','偈頌二十一首  其一七','釋普寧','宋','宋诗','song-poetry','','[]','有處不是有，無處不是無。',24,'全唐诗/poet.song.225000.json','["有處不是有，無處不是無。", "有無不到處，馨香滿道途。"]'),
('a05a466d-5ef0-440c-979c-882239f2eadc','偈頌二十一首  其一八','釋普寧','宋','宋诗','song-poetry','','[]','這箇老漢，軟頑希罕。',52,'全唐诗/poet.song.225000.json','["這箇老漢，軟頑希罕。", "煨而不熟，煮而不爛。", "沒興遭他負累，被陷雲黄苦難。", "怨之不已，恨之不休，且將這箇雪冤讎。"]'),
('721409a8-aa1b-4c03-a664-4d6f3f126d04','偈頌二十一首  其一九','釋普寧','宋','宋诗','song-poetry','','[]','去年十月十七，被命來尸敗席。',198,'全唐诗/poet.song.225000.json','["去年十月十七，被命來尸敗席。", "陳逋弊積如山，中外倉庫赤立。", "勉效佛在世時，持鉢沿門求乞。", "不憚涉險登危，波波爲衆竭力。", "逗到四月十五，恰滿六箇月日。", "諸方禁足安居，雙林豈容禁足。", "領衆展轉求賢，然後求己的實。", "心空及第歸來，和這自己拋擲。", "更有一事告報，古聖言端語的。", "寧可熱鐵纏身，不受信心人衣。", "寧可鎔銅灌口，不受信心人食。", "喫飯忽咬著砂，一生參學事畢。", "若不量彼來處，水也難消一滴。", "且誵訛在什麽處，直待當來問彌勒。"]'),
('a84daf79-07b8-4eae-bb85-9b3b70502e52','偈頌二十一首  其二○','釋普寧','宋','宋诗','song-poetry','','[]','諸方此日，安居禁足。',74,'全唐诗/poet.song.225000.json','["諸方此日，安居禁足。", "雙林難說，禁足安居。", "厨乏聚蠅之糝，廩無隔宿之儲。", "策杖遍叩檀度，免我一衆饑虛。", "休以蠟人爲驗，但願處處逢渠。", "早知今日事，悔不慎當初。"]'),
('37b36913-e2ab-48ab-91a2-393777ecc6cb','偈頌二十一首  其二一','釋普寧','宋','宋诗','song-poetry','','[]','往復落人綣繢間，那知同步不同行。',32,'全唐诗/poet.song.225000.json','["往復落人綣繢間，那知同步不同行。", "當初乍可無容質，別作心腸過一生。"]'),
('87ef262b-6870-4cbe-9bbf-6d17cffbdaea','出山相贊','釋普寧','宋','宋诗','song-poetry','','[]','入山出山，何異何別。',28,'全唐诗/poet.song.225000.json','["入山出山，何異何別。", "六年所成，一時漏泄。", "那堪滿口嚼冰雪。"]'),
('166055ad-1cfc-433d-a2ab-9ed4263e3c65','渡江達磨贊','釋普寧','宋','宋诗','song-poetry','','[]','道箇不識，自生荆棘。',28,'全唐诗/poet.song.225000.json','["道箇不識，自生荆棘。", "曈曈渡江，忍羞面壁。", "頼有神光與雪屈。"]'),
('9b73c372-84bd-4fd5-b3eb-11570fc08d26','寒山拾得贊','釋普寧','宋','宋诗','song-poetry','','[]','指東畫西，眼笑眉垂。',56,'全唐诗/poet.song.225000.json','["指東畫西，眼笑眉垂。", "心似秋月，髮如亂絲。", "吟句不成句，題詩不是詩。", "豐干輕饒舌，敗缺一時知。", "善哉苦哉，敢稱七佛之師。"]'),
('4b26ef69-a16e-4bc4-bdfe-0d416e085114','行道持數珠觀音贊','釋普寧','宋','宋诗','song-poetry','','[]','從聞思修，入三摩地。',36,'全唐诗/poet.song.225000.json','["從聞思修，入三摩地。", "八萬行門，一十九類。", "尋聲救苦越塵沙，一串數珠數不已。"]'),
('9e06582d-616d-417b-846a-91e11b21f639','布袋贊','釋普寧','宋','宋诗','song-poetry','','[]','杖頭挑百億乾坤，布袋貯三千世界。',32,'全唐诗/poet.song.225000.json','["杖頭挑百億乾坤，布袋貯三千世界。", "閙市叢中等箇人，不知誰是知音者。"]'),
('46ed4996-5142-44e6-b9db-88474a4f5d09','普化贊','釋普寧','宋','宋诗','song-poetry','','[]','踢倒飯床，特地乖張。',36,'全唐诗/poet.song.225000.json','["踢倒飯床，特地乖張。", "指空話空，撤顛撤狂。", "木槌拈來換人眼，贏得惡聲滿大唐。"]'),
('2c116aee-ff3e-4458-9244-331df8659d33','魚婦觀音贊','釋普寧','宋','宋诗','song-poetry','','[]','提起活鱍鱍，馬郎亦被惑。',24,'全唐诗/poet.song.225000.json','["提起活鱍鱍，馬郎亦被惑。", "度生雖願重，那知成敗缺。"]'),
('75f1f6a3-215b-42e3-a8ed-d7eb3b0239be','靈照女贊','釋普寧','宋','宋诗','song-poetry','','[]','拈將破笊籬，風前賣與誰。',24,'全唐诗/poet.song.225000.json','["拈將破笊籬，風前賣與誰。", "攙行奪市處，非獨老爺知。"]'),
('2a51e047-1311-46a7-ba56-14394b86a198','無準和尚頂相贊','釋普寧','宋','宋诗','song-poetry','','[]','文武火煨殺人，千衲子恨難伸。',62,'全唐诗/poet.song.225000.json','["文武火煨殺人，千衲子恨難伸。", "五處主法，雙徑兩新。", "內庭敷演，賜號超倫。", "自創正續梵苑，延納雲水高賓。", "將謂多少奇特，依前滿面埃塵。"]'),
('cad99b74-a8f8-4c7a-bb1d-74e043994b9e','義簡禪人畫圓相請贊','釋普寧','宋','宋诗','song-poetry','','[]','圓同太虛，無欠無餘。',61,'全唐诗/poet.song.225000.json','["圓同太虛，無欠無餘。", "良由取捨，所以不如。", "恁麽說話，早是起模畫樣了。", "殊不知纔擬任麽，便不任麽。", "更問如何若何，笑倒嵩山破竈墮。"]'),
('5b97e4ca-696b-4efd-9eed-fbded0791f93','最明寺殿真像贊','釋普寧','宋','宋诗','song-poetry','','[]','掌持國土，天下安堵。',70,'全唐诗/poet.song.225000.json','["掌持國土，天下安堵。", "信向佛法，運心堅固。", "德重丘山，名播寰宇。", "清白傳家，望隆今古。", "參透吾宗，眼眉卓豎。", "末後一機，超佛越祖。", "汝辜負吾，吾辜負汝。"]'),
('a7ffebcc-cd36-470b-b266-34b4a856fe3c','正傳寺住持安東巖請贊','釋普寧','宋','宋诗','song-poetry','','[]','生緣於西蜀，非獨遊日本。',24,'全唐诗/poet.song.225000.json','["生緣於西蜀，非獨遊日本。", "十方國土中，當頭俱坐斷。"]'),
('3bcb6fd2-c316-49a4-975a-6aa2a26bc613','宏海侍者請贊','釋普寧','宋','宋诗','song-poetry','','[]','這川䖃苴，全不仁者。',20,'全唐诗/poet.song.225000.json','["這川䖃苴，全不仁者。", "握起老拳，佛祖也怕。"]'),
('72abc495-1ca0-4a4c-8c4e-9a9a3e0c9711','小師景用請贊','釋普寧','宋','宋诗','song-poetry','','[]','要贊而無德可贊，要駡而無過可駡。',30,'全唐诗/poet.song.225000.json','["要贊而無德可贊，要駡而無過可駡。", "贊與駡不及處，大地而不能載。"]'),
('a3da0c80-9fef-4462-a52d-fdfd06825b73','正因法孫命工繪吾幻質炷禮請贊','釋普寧','宋','宋诗','song-poetry','','[]','箇樣面嘴，阿誰敢擬。',35,'全唐诗/poet.song.225000.json','["箇樣面嘴，阿誰敢擬。", "威凜凜生，氣憤憤地。", "臨濟德山，望風敬畏。", "和蘇嚕之。"]'),
('66ad0890-8313-41d4-828c-96b936af3cc6','無錫劉相幹篤信佛法常來參請自和雪竇罌粟頌來呈老僧即次韻酬之云','釋普寧','宋','宋诗','song-poetry','','[]','一實包含萬點春，收來粒粒是家珍。',32,'全唐诗/poet.song.225000.json','["一實包含萬點春，收來粒粒是家珍。", "些兒圓轉誰能委，唯一身分百億身。"]'),
('51604da9-e27c-45a2-8e5b-7003e7cee8d1','鐵壁','釋普寧','宋','宋诗','song-poetry','','[]','剛然隔斷太虛空，縫罅渾無拶不通。',32,'全唐诗/poet.song.225000.json','["剛然隔斷太虛空，縫罅渾無拶不通。", "頑鈍碓夫覷不破，倩人書處轉乖宗。"]'),
('5fd514b5-a0ac-4e7f-9777-6ac49acae4a4','鐵牛','釋普寧','宋','宋诗','song-poetry','','[]','骨格純剛蹄角全，軒然鼻孔自遼天。',32,'全唐诗/poet.song.225000.json','["骨格純剛蹄角全，軒然鼻孔自遼天。", "不貪陝府欄邊草，肯遍耕翻祖父田。"]'),
('7b024b02-03bf-4dd3-a4f7-6b9642677477','海月','釋普寧','宋','宋诗','song-poetry','','[]','金波涌出爛銀盆，黑白虧盈湛不痕。',32,'全唐诗/poet.song.225000.json','["金波涌出爛銀盆，黑白虧盈湛不痕。", "莫謂清波無透路，珊瑚枝上影團團。"]'),
('0ab82092-2d90-4b9f-b4f1-d753b23b7289','竹溪','釋普寧','宋','宋诗','song-poetry','','[]','空服高心耐歲寒，滔滔聲價沒遮攔。',32,'全唐诗/poet.song.225000.json','["空服高心耐歲寒，滔滔聲價沒遮攔。", "自從南北分枝派，攪動江西十八灘。"]'),
('e721fe74-4973-4027-a2ca-a66626bd5def','雪竇前堂音座寮有煉指行人求頌','釋普寧','宋','宋诗','song-poetry','','[]','未徹根源肯便休，煉磨三種愈精修。',32,'全唐诗/poet.song.225000.json','["未徹根源肯便休，煉磨三種愈精修。", "發輝自己光明藏，抹過俱胝一指頭。"]'),
('73fd6626-3ce4-4a48-b989-f618ff416dc0','寫華嚴經求頌','釋普寧','宋','宋诗','song-poetry','','[]','破一微塵出此經，因該果海果該因。',32,'全唐诗/poet.song.225000.json','["破一微塵出此經，因該果海果該因。", "無端却被管城子，名句文俱錯指陳。"]'),
('684e32bd-5958-4950-adf6-93bc3f5f9fec','畫髑髏檐人我檐者求頌','釋普寧','宋','宋诗','song-poetry','','[]','自從塵劫至于今，執著無明人我心。',32,'全唐诗/poet.song.225000.json','["自從塵劫至于今，執著無明人我心。", "驀忽眼睛俱突出，乾坤大地孰知音。"]'),
('4980882b-c010-4043-a060-86ad2a81e3bc','栽松道者','釋普寧','宋','宋诗','song-poetry','','[]','栽培得地，節操蒼然。',36,'全唐诗/poet.song.225000.json','["栽培得地，節操蒼然。", "死而復活，身後身前。", "楖𣗖橫肩阿剌剌，再來不直半分錢。"]'),
('6f454174-4327-4d1a-b2c2-25d867e7e5f3','亮知客','釋普寧','宋','宋诗','song-poetry','','[]','主中賓句驗來端，四海禪流總被瞞。',32,'全唐诗/poet.song.225000.json','["主中賓句驗來端，四海禪流總被瞞。", "鐵磨機輪難比擬，逢人即出舌翻瀾。"]'),
('6b5ffce8-f0c4-47c2-be95-069aa794d389','南洲','釋普寧','宋','宋诗','song-poetry','','[]','贍部那邊沙際間，鬨然魔子恣縱橫。',32,'全唐诗/poet.song.225000.json','["贍部那邊沙際間，鬨然魔子恣縱橫。", "周金剛带不平氣，勘破却從潭上行。"]'),
('6b7685da-cd62-4abd-b2e3-ad21c45f272a','龜山禱雨','徐夢發','宋','宋诗','song-poetry','','[]','久困焦熬裏，持香謁二禪。',48,'全唐诗/poet.song.225000.json','["久困焦熬裏，持香謁二禪。", "會留一宿覺，了得寸心緣。", "鶴識小溪路，鐘聞上界天。", "龍湫分勺水，法海遍三千。"]'),
('534c1508-5795-4f66-8b87-d3d0a4a71a58','支提禪寺','徐夢發','宋','宋诗','song-poetry','','[]','來謁支提古道場，幾年袍錦韻猶香。',64,'全唐诗/poet.song.225000.json','["來謁支提古道場，幾年袍錦韻猶香。", "芙蓉夢裏僧趺坐，薝蔔林中佛放光。", "禪語了參一宿覺，塵緣頓悟半生忙。", "若分座下龍王水，免使春田待插秧。"]'),
('893135cd-be98-4318-9b48-fcc73ec01944','鳳山禪寺','徐夢發','宋','宋诗','song-poetry','','[]','百役紅塵吏，過門一解鞍。',48,'全唐诗/poet.song.225000.json','["百役紅塵吏，過門一解鞍。", "頻來無事幹，孤坐有山看。", "留月不掩戶，招風長倚欄。", "馬嘶催去路，吾道尚盤桓。"]'),
('995636c1-1400-453d-9fd1-87deceae4047','超覽亭','徐夢發','宋','宋诗','song-poetry','','[]','壬子歲二月，亭成始宴賓。',48,'全唐诗/poet.song.225000.json','["壬子歲二月，亭成始宴賓。", "扁題原用舊，輪奐喜更新。", "遠眺江逾碧，靜觀山自春。", "亭邊山更好，一洗簿書塵。"]'),
('cb71d34c-a2c6-43fa-b5a6-7f338e8dece3','挽胡季昭  其一','李庭芝','宋','宋诗','song-poetry','','[]','綠鬢兩科好，丹心一片忠。',48,'全唐诗/poet.song.225000.json','["綠鬢兩科好，丹心一片忠。", "言言關國體，蹇蹇匪渠躬。", "誰謂鴛行底，能持鯁論公。", "象臺死得所，萬古憶清風。"]'),
('6864f08c-c1ae-4d08-bab9-4eda4265d8f8','挽胡季昭  其二','李庭芝','宋','宋诗','song-poetry','','[]','玉李當春孟，公書以訃聞。',48,'全唐诗/poet.song.225000.json','["玉李當春孟，公書以訃聞。", "但期同氣骨，不作異鄉墳。", "豈料鱗音後，俄傳蝶夢云。", "想教寧越水，恨不識朱雲。"]'),
('2c3f4d70-8da9-4501-8051-4e1795c4e86b','遊大滌','張濡','宋','宋诗','song-poetry','','[]','危樓拱翠出層空，畫棟朱欄縹緲中。',32,'全唐诗/poet.song.225000.json','["危樓拱翠出層空，畫棟朱欄縹緲中。", "客散月明風露下，一奩天棘伴絲桐。"]'),
('8bddd445-1b3e-4c65-86ef-f32be0855478','和回山人榴皮題壁舊韻','張濡','宋','宋诗','song-poetry','','[]','芒鞋記踏青猶軟，野徑縈紆雪尚餘。',32,'全唐诗/poet.song.225000.json','["芒鞋記踏青猶軟，野徑縈紆雪尚餘。", "走筆鋟珉增媿色，可無換穀一篇書。"]'),
('79724b9e-8c9d-4333-a760-ac258e4a0249','湖上別墅','張濡','宋','宋诗','song-poetry','','[]','弱柳舒眉學遠山，四山斜嚲綠雲鬟。',32,'全唐诗/poet.song.225000.json','["弱柳舒眉學遠山，四山斜嚲綠雲鬟。", "平湖如鑑一回照，西子明妝濃淡間。"]'),
('52fe9c32-fccf-4342-881d-afed511b53e1','浯溪讀中興頌','李芾','宋','宋诗','song-poetry','','[]','羯鼓梨園跡已荒，斯文猶在日星光。',32,'全唐诗/poet.song.225000.json','["羯鼓梨園跡已荒，斯文猶在日星光。", "我來細拂青苔石，不憶三郎憶漫郎。"]'),
('813da2bd-e4ab-456a-ad68-dfec2579c3ea','題考功印紙','曾如驥','宋','宋诗','song-poetry','','[]','謹將節義二字，結果印紙一宗。',28,'全唐诗/poet.song.225000.json','["謹將節義二字，結果印紙一宗。", "了却神遊何處，澄江明月清風。"]'),
('1f928e84-f22e-4c13-b58f-5fb7cc613ec7','絕命詩','鄧得遇','宋','宋诗','song-poetry','','[]','宋室忠臣，鄧氏孝子。',50,'全唐诗/poet.song.225000.json','["宋室忠臣，鄧氏孝子。", "不忍偷生，寧甘溺死。", "彭咸故居，乃吾潭府。", "屈公子平，乃吾伴侶。", "優哉悠哉，吾得其所。"]'),
('7a23fd43-efc8-4934-864c-b51c2e4cf7a9','桐江曉泊','劉瀾','宋','宋诗','song-poetry','','[]','風蕭蕭，冰瑟瑟，淡烟空濛冠朝日。',32,'全唐诗/poet.song.225000.json','["風蕭蕭，冰瑟瑟，淡烟空濛冠朝日。", "灘頭枯木如畫出，鸜鵒飛來添一筆。"]'),
('973c9c77-4005-4127-95c7-06c12a7108d6','夜訪侃直翁','劉瀾','宋','宋诗','song-poetry','','[]','疏瓴亂見星，危坐冷無燈。',48,'全唐诗/poet.song.225000.json','["疏瓴亂見星，危坐冷無燈。", "索句髭先白，餐蔬貌欲青。", "棲禽翻麓雪，墮栗破溪冰。", "昨夜中峰頂，同看海日升。"]'),
('8c3bc58e-e317-41b6-8aaf-2e245f3ca976','句','劉瀾','宋','宋诗','song-poetry','','[]','東風半綠官圩草，西日遥紅別岸山。',16,'全唐诗/poet.song.225000.json','["東風半綠官圩草，西日遥紅別岸山。"]'),
('03d603ad-42b3-43ad-ad7b-47cbb5240137','句  其一','林喬','宋','宋诗','song-poetry','','[]','斗州無頓閒身處，時向梅花走一遭。',16,'全唐诗/poet.song.225000.json','["斗州無頓閒身處，時向梅花走一遭。"]'),
('6ab8d5e5-89c2-4ea9-99b9-b9d3018efc16','句  其二','林喬','宋','宋诗','song-poetry','','[]','醮壇夜朝斗在目，石室晝卧雲生胸。',16,'全唐诗/poet.song.225000.json','["醮壇夜朝斗在目，石室晝卧雲生胸。"]'),
('4e4c9043-b257-4e92-9374-72524db6c1f1','明妃','程鳴鳳','宋','宋诗','song-poetry','','[]','漢宮粉黛應無數，明妃却向氈城路。',64,'全唐诗/poet.song.225000.json','["漢宮粉黛應無數，明妃却向氈城路。", "自憐傾國不用金，翻被一生顔色誤。", "世間那有真妍媸，明妃馬上休傷悲。", "不信但看奇男子，多少塵埋未見知。"]'),
('d844d646-7a3e-44be-b453-8f068d3fee4d','晦菴亭','程鳴鳳','宋','宋诗','song-poetry','','[]','古來何物支乾坤，除四書外旁無門。',160,'全唐诗/poet.song.225000.json','["古來何物支乾坤，除四書外旁無門。", "晦翁乘風遊混淪，天宇掃掃浮雲昏。", "周程扶起周孔尊，隻手閘斷狂瀾奔。", "當時正氣橫八垠，猶爾不免遭群喧。", "曾幾何日班廷鴛，曉夢有栩枌榆村。", "翁已仙去誰招魂，有亭渠渠波沄沄。", "風烟苔徑新屐痕，滕侯肯堂之弟昆。", "溪山荏苒更寒暄，空餘碧樹吟霜猿。", "人間興廢誰能論，桑田可變海可翻。", "翁之所恃無有焉，斯文不死道常存。"]'),
('6542349b-48f9-4a75-a388-1d1800d7aa53','楊歷巖','程鳴鳳','宋','宋诗','song-poetry','','[]','銀河底穿不可塞，一瀉砰砰下空碧。',80,'全唐诗/poet.song.225000.json','["銀河底穿不可塞，一瀉砰砰下空碧。", "峰高雲邃源荒茫，但見巖飛練千尺。", "我來導之赴蒼壑，流出凌江散天澤。", "餘波直赴黄木灣，颶卷鼇翻浪花白。", "竟從海若膏乾坤，豈但梅邊沃甘液。"]'),
('d9ccc0fd-65a4-4cfd-a5a0-2d4ccc53c7bc','題陳少陽先生上書稿後','趙時瓈','宋','宋诗','song-poetry','','[]','胡馬昔長驅，高屋建瓴水。',144,'全唐诗/poet.song.225000.json','["胡馬昔長驅，高屋建瓴水。", "權奸誤國家，和議甘骫骳。", "遂令九廟尊，冒沒在棘枳。", "带甲百餘萬，一嘯自披靡。", "堂堂諫議公，屹若頹波砥。", "叩閽斥時宰，不惜用一死。", "此死不足道，聞者自興起。", "一木支大厦，於時不可爾。", "使早定大計，何物摩壁壘。", "可憐紹興間，賻贈官其子。", "我得覩遺稿，感慨寧已矣。", "千載凜如生，作者書于紙。"]'),
('ea71aef6-e3b0-49ff-9e3d-0a92206edbd9','句','王實之','宋','宋诗','song-poetry','','[]','碧鷄金馬非吾事，白鷺青原欠子詩。',16,'全唐诗/poet.song.225000.json','["碧鷄金馬非吾事，白鷺青原欠子詩。"]'),
('8375c803-2991-4d54-9675-f947dd80c297','元夕','李彭老','宋','宋诗','song-poetry','','[]','斜陽盡處蕩輕煙，輦路東風入管絃。',64,'全唐诗/poet.song.225000.json','["斜陽盡處蕩輕煙，輦路東風入管絃。", "五夜好春隨步暖，一年明月打頭圓。", "香塵掠粉翻羅带，蜜炬籠綃鬭玉鈿。", "人影漸稀花露冷，踏歌聲度曉雲邊。"]'),
('e0878c94-5b50-406a-8b4a-ff6960fb4007','賈秋壑故居','李彭老','宋','宋诗','song-poetry','','[]','瑶房錦榭曲相通，能幾番春事已空。',32,'全唐诗/poet.song.225000.json','["瑶房錦榭曲相通，能幾番春事已空。", "惆悵舊時吹笛處，隔窗風雨剝青紅。"]'),
('42a8dd16-ff9a-4532-baa7-b8cc3a815d11','白際嶺下即目','汪若楫','宋','宋诗','song-poetry','','[]','白際摩天秀，秋光滿蓼汀。',48,'全唐诗/poet.song.225000.json','["白際摩天秀，秋光滿蓼汀。", "山呈金字面，田畫井文形。", "夜出螢相照，更闌鷄可聽。", "杉松柯不改，點染四時青。"]'),
('fc4d33b1-b81b-408d-bed4-079a59e9c58d','開窗','汪若楫','宋','宋诗','song-poetry','','[]','草色侵書綠，依山多得陰。',24,'全唐诗/poet.song.225000.json','["草色侵書綠，依山多得陰。", "月高猿挂樹，驚起夜棲禽。"]'),
('9cfa9a0c-f089-437a-a948-101590563c47','夜坐','汪若楫','宋','宋诗','song-poetry','','[]','鑪煨榾柮煙容冷，酒瀉茅柴春色輕。',32,'全唐诗/poet.song.225000.json','["鑪煨榾柮煙容冷，酒瀉茅柴春色輕。", "夜坐不眠人悄悄，梅梢隨月繞窗行。"]'),
('9316ebdd-69e4-4daa-9632-40ff49517206','久雨','汪若楫','宋','宋诗','song-poetry','','[]','連連春雨幾黄昏，溪岸人家水近門。',32,'全唐诗/poet.song.225000.json','["連連春雨幾黄昏，溪岸人家水近門。", "借問人家水曾落，竹林枝上看風痕。"]'),
('53380f5a-5c30-4c2b-8ae4-496aac4e2def','門前松棚','汪若楫','宋','宋诗','song-poetry','','[]','突兀山邊屋數間，每嫌斜照上闌干。',32,'全唐诗/poet.song.225000.json','["突兀山邊屋數間，每嫌斜照上闌干。", "當門只得添松蓋，未到秋來夜已寒。"]'),
('a9f625c4-7844-45d1-b2e7-f98988656335','青山','汪若楫','宋','宋诗','song-poetry','','[]','萬木驚秋各自殘，蛩聲扶砌訴新寒。',32,'全唐诗/poet.song.225000.json','["萬木驚秋各自殘，蛩聲扶砌訴新寒。", "西風不是吹黄落，要放青山與客看。"]'),
('5b4af795-07dc-45cf-99a5-22224a12bbdd','淳祐壬子王正人謁仙薦薌有感而題','趙善浥','宋','宋诗','song-poetry','','[]','企仰仙巖歲已深，此行一見即知音。',64,'全唐诗/poet.song.225000.json','["企仰仙巖歲已深，此行一見即知音。", "水簾不卷非朝夕，芝石長生到古□。", "孤鶴來迎疑識面，片雲飛去出無□。", "相逢總是旌陽侶，喚起先生問劍□。"]'),
('9b76531d-304f-4589-a641-435bf0cbc788','諷州守','劉炎','宋','宋诗','song-poetry','','[]','未到桃源來，長憶出家景。',24,'全唐诗/poet.song.225000.json','["未到桃源來，長憶出家景。", "及到桃源了，還是鑑中影。"]'),
('351fa71b-ab85-433b-9339-7cb34dc8cd68','和鍾守宴建昌耋老','蘇某','宋','宋诗','song-poetry','','[]','使君尊老致聃彭，躋彼公堂醉兕觥。',64,'全唐诗/poet.song.225000.json','["使君尊老致聃彭，躋彼公堂醉兕觥。", "祝饐俾觀親禮節，縱談猶說舊昇平。", "厖眉昔有商山皓，尚齒當年洛社英。", "盛事歡傳旴水上，賡歌歸美屬儒生。"]'),
('079a7ffc-ac4c-40e0-b839-60603a7e8711','題東老庵','張衡','宋','宋诗','song-poetry','','[]','東老遺風且百年，鄉評猶嘆子孫賢。',64,'全唐诗/poet.song.225000.json','["東老遺風且百年，鄉評猶嘆子孫賢。", "金丹數滿三千行，玉笈名留十八仙。", "座上杯盤由好客，鼎中饘粥且隨緣。", "相逢咸恨匆匆去，絕勝空回訪戴船。"]'),
('af95b143-2347-4c6d-9b99-449161cedc03','榴皮題壁','朱景行','宋','宋诗','song-poetry','','[]','白酒延賓出自如，收書養性務三餘。',32,'全唐诗/poet.song.225000.json','["白酒延賓出自如，收書養性務三餘。", "山人醉吐驚人句，却向東庵素壁書。"]'),
('1c26e0f6-2387-49ea-ac94-c96a873e5312','白龍洞磨崖','史少南','宋','宋诗','song-poetry','','[]','一自凌空降節飛，日瞻華表望翁歸。',64,'全唐诗/poet.song.225000.json','["一自凌空降節飛，日瞻華表望翁歸。", "今猶香氣浮丹竈，時有仙韶殷翠微。", "青鳥山深藏宿霧，白猿洞敞納晨暉。", "榴房桃李年年實，底事游人遇者稀。"]'),
('08e16c79-8eda-4542-bbd9-cc8ae6bb541f','春暉亭爲櫸川子賦','王奕','宋','宋诗','song-poetry','','[]','昔人念親心何如，喻彼百草蒙春暉。',160,'全唐诗/poet.song.225000.json','["昔人念親心何如，喻彼百草蒙春暉。", "一川含綠草方長，滿地落紅春已歸。", "草欲報春春忽改，子欲養親親不待。", "嗟哉物爾人亦然，對草無言淚如海。", "陽春有脚還復來，今年花謝明年開。", "慈親一去不復見，畫圖空寫春風面。", "櫸川有子思報親，結茅竹亭留白雲。", "親恩難酬春易過，獨倚欄干怨春暮。", "寄言孝子須惜時，流光暗促親顔移。", "春盤薦脆須及早，莫待酒澆墳上草。"]'),
('aa931fa0-62cc-4cf1-9ac3-3f5198e25b16','寶香院','王奕','宋','宋诗','song-poetry','','[]','山如螺髻塔如簪，三面江環一徑深。',64,'全唐诗/poet.song.225000.json','["山如螺髻塔如簪，三面江環一徑深。", "曉霧拂巖凝蜃氣，夜潮歸壑聽龍吟。", "戀涼人坐臨流石，带暝禽投隔岸林。", "獨憾寶香名未稱，只應喚作小江心。"]'),
('53af9b43-f3e2-4269-b4bf-c39da2154864','觀潮閣','王奕','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','南岸客來過北岸，浙山盡處見閩山。',32,'全唐诗/poet.song.225000.json','["南岸客來過北岸，浙山盡處見閩山。", "清秋井邑棋枰裏，落日汀洲畫軸間。"]'),
('922ec0ea-0100-42c9-bc95-1e8043d46e17','仙華重午','張森','宋','宋诗','song-poetry','','[]','空山值端午，采蒲南澗濱。',144,'全唐诗/poet.song.225000.json','["空山值端午，采蒲南澗濱。", "蒲生裹白石，澗水清粼粼。", "蟠根寸九節，服食能通真。", "采之不盈掬，土潔含芳辛。", "行行登絕境，有花如車輪。", "奇哉世莫識，持扣山中人。", "山人耳垂肩，羽佩青衣巾。", "乘飈控玄鶴，汎景下蒼岷。", "我行意其仙，再拜詢所因。", "仙人攬花笑，見爾還千春。", "語我勿復道，倏去無留塵。", "歸來有餘歎，三嚥華池津。"]'),
('d3c7cc36-96bc-4cc0-a288-0ed725c10ff5','贈逍遥子','蔡元厲','宋','宋诗','song-poetry','','[]','身在逍遥境，開庵寓此身。',48,'全唐诗/poet.song.225000.json','["身在逍遥境，開庵寓此身。", "紅塵不到處，白日獨閒人。", "月滿雲山夜，花留玉洞春。", "坐中無俗客，猿鶴故相親。"]'),
('1812956d-92a3-43ab-ac46-b86faa8eb7f8','孤青峰','蔡元厲','宋','宋诗','song-poetry','','[]','琳館松扉白晝扃，驂鸞人去已冥冥。',64,'全唐诗/poet.song.225000.json','["琳館松扉白晝扃，驂鸞人去已冥冥。", "天開遠畫樓臺古，地得遺丹草木靈。", "萬壑野雲晴釀雨，一池秋水夜涵星。", "麻姑仙馭今何在，檻外孤峰晚更青。"]'),
('3ac7a7cb-72b6-4292-9609-b1ed9bf7032c','中閣','蔡元厲','宋','宋诗','song-poetry','','[]','萬仞仙山插太空，山腰依約見蓬宮。',64,'全唐诗/poet.song.225000.json','["萬仞仙山插太空，山腰依約見蓬宮。", "人寰隔絕無煙到，洞府深沉有路通。", "石罅生雲埋柱礎，海光浮日照簾櫳。", "野僧齋罷凭欄久，千里秋毫一望中。"]'),
('f7fa09bf-471a-4f42-9106-a09c7adb5526','彩雲軒','蔡元厲','宋','宋诗','song-poetry','','[]','洞府神仙此是家，麻姑曾駐五雲車。',32,'全唐诗/poet.song.225000.json','["洞府神仙此是家，麻姑曾駐五雲車。", "峰前三尺寒泉水，猶有白蓮開舊花。"]'),
('1fe71a98-2e7c-403c-ac5b-79abb61da42a','遺履軒','蔡元厲','宋','宋诗','song-poetry','','[]','仙客相從往玉都，軒前惟見老松枯。',32,'全唐诗/poet.song.225000.json','["仙客相從往玉都，軒前惟見老松枯。", "春來試問梁間燕，還是當時舊履無。"]'),
('552f849e-cc81-46dc-a2df-eeb9081e99de','白雲庵  其一','逍遥子','宋','宋诗','song-poetry','','[]','山居常與白雲俱，小築東軒著藥爐。',32,'全唐诗/poet.song.225000.json','["山居常與白雲俱，小築東軒著藥爐。", "消遣客魔須底物，竹間葉葉有靈符。"]'),
('ffe00725-389c-4ba4-88c7-4532232193c0','白雲庵  其二','逍遥子','宋','宋诗','song-poetry','','[]','泉流東畔是蓬萊，我愛青山爲展開。',32,'全唐诗/poet.song.225000.json','["泉流東畔是蓬萊，我愛青山爲展開。", "獨倚瘦筇誰是伴，白雲日晚自歸來。"]'),
('a906c1a6-f231-4ace-b163-e38a620f1885','白雲庵  其三','逍遥子','宋','宋诗','song-poetry','','[]','洞底菖蒲綠作坡，松根况有茯苓多。',32,'全唐诗/poet.song.225000.json','["洞底菖蒲綠作坡，松根况有茯苓多。", "自能飽飯太平日，不學式微歌浩歌。"]'),
('3515ee5d-2f38-460b-8d4a-aa9977e98148','白雲庵  其四','逍遥子','宋','宋诗','song-poetry','','[]','蟻窠得意從渠計，螳翳忘言息我機。',32,'全唐诗/poet.song.225000.json','["蟻窠得意從渠計，螳翳忘言息我機。", "寒盡山庵無歷日，野花啼鳥又春歸。"]'),
('2b49f71f-4c99-4879-b3ea-acf72df2c9b3','茶庵','逍遥子','宋','宋诗','song-poetry','','[]','道人宴坐碧山阿，啄木敲門擬客過。',32,'全唐诗/poet.song.225000.json','["道人宴坐碧山阿，啄木敲門擬客過。", "吾境本無妖魅事，日長翻有睡爲魔。"]'),
('bd214dbc-2d3b-429f-98e1-a701cb56a636','羅浮茶','逍遥子','宋','宋诗','song-poetry','','[]','活水仍將活火煎，茶經妙處莫虛傳。',32,'全唐诗/poet.song.225000.json','["活水仍將活火煎，茶經妙處莫虛傳。", "陸顛所在閑題品，未試羅浮第一泉。"]'),
('46b404fe-2dfe-4983-b487-bd4d2f95f526','遊清源洞','釋圓悟','宋','宋诗','song-poetry','','[]','清旦尋幽洞，攀躋有同遊。',120,'全唐诗/poet.song.225000.json','["清旦尋幽洞，攀躋有同遊。", "霧雨藏諸峰，萬竅響颼颼。", "樹杪飛磴懸，巖外見客舟。", "蘚藤垂翠琰，風葉隨清流。", "百丈崖班駁，千尺木聳修。", "烏啼暘谷曉，雲淡海城秋。", "莓苔蝕丹竈，山房花竹幽。", "疎烟生墟落，遠水浮汀洲。", "朝斗空壇在，昇仙往事悠。", "倚闌吟未就，歸屐少遲留。"]'),
('f89d5bdb-28e3-4688-9f91-3fbf494fc9a9','山中四首  其一','釋圓悟','宋','宋诗','song-poetry','','[]','飛瀑掛高崖，幽禽響虛谷。',48,'全唐诗/poet.song.225000.json','["飛瀑掛高崖，幽禽響虛谷。", "憐此一片景，借得數椽屋。", "澗木卧槎牙，巖花散芳馥。", "策杖從所之，偶到南山麓。"]'),
('0bd03d85-7231-4936-bfbf-d88e14dbf6ac','山中四首  其二','釋圓悟','宋','宋诗','song-poetry','','[]','疎林過微雨，西嶺收殘暉。',48,'全唐诗/poet.song.225000.json','["疎林過微雨，西嶺收殘暉。", "草露濕我屨，松風吹我衣。", "坐久四山暝，吟餘獨鳥飛。", "歸來不知晚，蘿月盈窗扉。"]'),
('e7a819ee-1d9b-4b79-9c15-543ac4954650','山中四首  其三','釋圓悟','宋','宋诗','song-poetry','','[]','雅懷無所拘，偶行度前崗。',48,'全唐诗/poet.song.225000.json','["雅懷無所拘，偶行度前崗。", "長松發佳色，澄潭閟幽光。", "而我亦何幸，於此得相羊。", "低頭心語口，茲遊那可忘。"]'),
('50ed08b4-1053-4b59-9b9a-16e4f1d2dee1','山中四首  其四','釋圓悟','宋','宋诗','song-poetry','','[]','暝色歛平川，雲歸日已夕。',48,'全唐诗/poet.song.225000.json','["暝色歛平川，雲歸日已夕。", "閒行信杖藜，倦坐憇苔石。", "花亦滿意紅，草自無心碧。", "吾亦樂吾年，人生不滿百。"]'),
('9c158e26-2015-4122-b059-33d6cfd5a957','海雲閣','釋圓悟','宋','宋诗','song-poetry','','[]','天風來海門，驚浪作飛雨。',48,'全唐诗/poet.song.225000.json','["天風來海門，驚浪作飛雨。", "岸雲過已盡，隴樹青可數。", "掛帆鷗鳥外，清吟正凝佇。", "欲去猶未能，漁燈粲烟渚。"]'),
('f3c19e43-667c-4dcb-af07-3e43f40f6861','重遊清源洞','釋圓悟','宋','宋诗','song-poetry','','[]','此地今重到，藤蘿長碧陰。',48,'全唐诗/poet.song.225000.json','["此地今重到，藤蘿長碧陰。", "緬思仙去後，長有客來吟。", "出鳥江濤白，連雲嶺樹深。", "杖藜宜少駐，靈跡尚堪尋。"]'),
('d314ac41-6675-4584-bd95-01a981d927e3','小立','釋圓悟','宋','宋诗','song-poetry','','[]','小立當清曉，一筇吟影孤。',48,'全唐诗/poet.song.225000.json','["小立當清曉，一筇吟影孤。", "蘭香和霧濕，竹老带藤枯。", "野水流將合，春山淡欲無。", "雨晴猶未卜，勞爾鵓鳩呼。"]'),
('1e12a428-85cd-4f91-858d-03dffbb22a73','晚渡','釋圓悟','宋','宋诗','song-poetry','','[]','橋巷低臨水，數家深掩門。',48,'全唐诗/poet.song.225000.json','["橋巷低臨水，數家深掩門。", "路窮生寂寞，人渡更黄昏。", "風色占帆席，潮痕認柳根。", "岸回林影暝，漁火滿沙村。"]'),
('567db8f8-4127-43c0-a067-f8b6e1a4ad8f','遊靜真觀','釋圓悟','宋','宋诗','song-poetry','','[]','古觀門幽寂，來遊亦夙緣。',48,'全唐诗/poet.song.225000.json','["古觀門幽寂，來遊亦夙緣。", "林堪巢老鶴，壇可禮真仙。", "秋晚寒生屋，雨深苔印磚。", "舊藏多御賜，應識尚留傳。"]'),
('5364ce6e-55a9-4737-97a1-3952743ab660','題泉州張許祠','釋圓悟','宋','宋诗','song-poetry','','[]','泉與睢陽隔，事聞猶涕零。',48,'全唐诗/poet.song.225000.json','["泉與睢陽隔，事聞猶涕零。", "人雖死忠義，祠自活英靈。", "壞砌寒雲聚，空庭古柏青。", "功名見信史，何必更碑銘。"]'),
('e332d0dd-3809-4d82-9c33-1a5f65f188a7','和胡教授山庵見訪歸韻','釋圓悟','宋','宋诗','song-poetry','','[]','因赴山中約，歸途带暝痕。',48,'全唐诗/poet.song.225000.json','["因赴山中約，歸途带暝痕。", "禽聲沉衆樹，人影背孤村。", "霧起寒城裏，江流古岸根。", "行吟多得句，知欲與誰論。"]'),
('0f47539b-9d5b-4cf3-a63f-7686fe2fbdff','大帽山','釋圓悟','宋','宋诗','song-poetry','','[]','衆山皆弭伏，獨讓此峰尊。',48,'全唐诗/poet.song.225000.json','["衆山皆弭伏，獨讓此峰尊。", "絕頂時猶雨，中林晝亦昏。", "逆風松勢偃，觸石水聲喧。", "定有幽棲者，何因得晤言。"]'),
('508b14bd-25be-4ef5-bef9-5839dc26c7dd','山中夜歸','釋圓悟','宋','宋诗','song-poetry','','[]','一鶴候柴關，林空境自閒。',48,'全唐诗/poet.song.225000.json','["一鶴候柴關，林空境自閒。", "竹房秋後凍，病叟夜深還。", "樹密疑無路，月明猶在山。", "幽居便所適，已是十年閒。"]'),
('48371df1-ff1d-4616-bd3e-35c1605219b5','瑞興寺','釋圓悟','宋','宋诗','song-poetry','','[]','路僻今蕪翳，寒厨尚起烟。',48,'全唐诗/poet.song.225000.json','["路僻今蕪翳，寒厨尚起烟。", "僧依三佛住，門與數峰連。", "雨潤苔封塔，年深竹覆泉。", "創時靈異事，猶有斷碑傳。"]'),
('8f430fa3-9aa1-4369-ab3d-be64faa07ec6','真人洞','釋圓悟','宋','宋诗','song-poetry','','[]','捫葛敲幽戶，空山得遍觀。',48,'全唐诗/poet.song.225000.json','["捫葛敲幽戶，空山得遍觀。", "雲離朝拜石，苔積上昇壇。", "秋晚澗聲澀，月明松影寒。", "真人不可遇，誰復此燒丹。"]'),
('f50da015-5e1f-4508-9dfe-e5de6feb1067','和黄瑞玉山庵','釋圓悟','宋','宋诗','song-poetry','','[]','偶尋孤隠處，幽僻遠腥葷。',48,'全唐诗/poet.song.225000.json','["偶尋孤隠處，幽僻遠腥葷。", "結屋聊依石，栽松却傍墳。", "山深長霧雨，海近渺風雲。", "不必稱昏聵，自然疎見聞。"]'),
('58893095-7f72-4514-8926-f1c141a6872d','趙山神祠','釋圓悟','宋','宋诗','song-poetry','','[]','山中雖隱跡，名被世人知。',48,'全唐诗/poet.song.225000.json','["山中雖隱跡，名被世人知。", "無策欲干主，有詩還立祠。", "水雲通別渚，枳槲蔭空墀。", "多少能吟者，焚香爲拂碑。"]'),
('9ee5aa90-7ef0-40b6-8c42-8ccbe93b268e','題秦君亭','釋圓悟','宋','宋诗','song-poetry','','[]','昔只爲吟隠，偶然依佛居。',48,'全唐诗/poet.song.225000.json','["昔只爲吟隠，偶然依佛居。", "路逢陰壑盡，雲抱曉巖虛。", "亭在因人重，山深與世疎。", "倘懷名利念，到此欲何如。"]'),
('cab01643-d4d4-4a17-a966-8700d971e6a5','承天寺尋勤上人','釋圓悟','宋','宋诗','song-poetry','','[]','古寺多陳迹，幽花祇自開。',48,'全唐诗/poet.song.225000.json','["古寺多陳迹，幽花祇自開。", "凈無秋後暑，遠絕市中埃。", "苔色侵碑石，松陰蔽月臺。", "山人遲未至，欲去重徘徊。"]'),
('a31dcf62-2cf3-4a58-9db3-d8e67a1fda57','次姜秦祠和胡教授韻','釋圓悟','宋','宋诗','song-poetry','','[]','曉謁崇祠霧靄深，行藏因識二賢心。',64,'全唐诗/poet.song.225000.json','["曉謁崇祠霧靄深，行藏因識二賢心。", "榻前自有孤忠疏，林下誰賡招隠吟。", "寂寂精廬蒼蘚入，堂堂遺像暗塵侵。", "客中莫致生芻奠，聊汲山泉薦菊斟。"]'),
('8c491077-5d3f-41bc-ba42-93478635b6f3','題寶山寺二首  其一','釋圓悟','宋','宋诗','song-poetry','','[]','寓此曾三夏，重來隔五年。',24,'全唐诗/poet.song.225000.json','["寓此曾三夏，重來隔五年。", "溪山亦良是，懷想轉凄然。"]'),
('1d84aa9d-179b-45ad-91a2-3954b761cc8f','題寶山寺二首  其二','釋圓悟','宋','宋诗','song-poetry','','[]','去臘應差暖，今春定有寒。',24,'全唐诗/poet.song.225000.json','["去臘應差暖，今春定有寒。", "澗梅花半樹，侵曉又凋殘。"]'),
('28cf3cde-c51f-434e-819c-c9264722b3c7','宿友人白雲庵三首  其一','釋圓悟','宋','宋诗','song-poetry','','[]','不到歲時久，重來人事疎。',24,'全唐诗/poet.song.225000.json','["不到歲時久，重來人事疎。", "掃雲僧亦去，誰伴主翁居。"]'),
('a3d5b220-9554-4bf2-b9e0-7429a6b69eb8','宿友人白雲庵三首  其二','釋圓悟','宋','宋诗','song-poetry','','[]','萬籟夜俱寂，蒲團清可禪。',24,'全唐诗/poet.song.225000.json','["萬籟夜俱寂，蒲團清可禪。", "林疎窗過月，巖遠竹通泉。"]'),
('9140d9d1-8884-474f-804b-8d1724454e40','宿友人白雲庵三首  其三','釋圓悟','宋','宋诗','song-poetry','','[]','城裏秋猶熱，山中寒已濃。',24,'全唐诗/poet.song.225000.json','["城裏秋猶熱，山中寒已濃。", "紫檀時小炷，危坐聽晨鍾。"]'),
('593336be-fb0e-41a2-b09b-716324cb4da6','送壁上人歸承天寺','釋圓悟','宋','宋诗','song-poetry','','[]','城寺思歸興忽生，又携筇杖出雲扃。',32,'全唐诗/poet.song.225000.json','["城寺思歸興忽生，又携筇杖出雲扃。", "月明後夜空山裏，繞屋泉聲只自聽。"]'),
('01c45cd6-e957-4361-a749-7319c65b84b5','方海豐詩境樓分賦得春風','釋圓悟','宋','宋诗','song-poetry','','[]','暖襲遊人陌上塵，不知花信幾番新。',32,'全唐诗/poet.song.225000.json','["暖襲遊人陌上塵，不知花信幾番新。", "莫教吹到荼䕷處，吹到荼䕷是晚春。"]'),
('ca193fa9-5e98-40dc-bf79-2478af901790','寄方俊甫','釋圓悟','宋','宋诗','song-poetry','','[]','市橋勞送別，轉影又經時。',48,'全唐诗/poet.song.225000.json','["市橋勞送別，轉影又經時。", "幾度月圓夜，獨行誰共時。", "菊寒開欲遍，書遠到應遲。", "西瀑成庵未，幽樓莫負期。"]'),
('0694b6de-1c34-435c-b3c2-7bb8838305db','句','釋圓悟','宋','宋诗','song-poetry','','[]','獨憐萬木凋零後，屹立風霜慘澹中。',16,'全唐诗/poet.song.225000.json','["獨憐萬木凋零後，屹立風霜慘澹中。"]'),
('818a3d11-39bd-4790-a551-d8779974e968','內司毀林建寺','淳祐士人','宋','宋诗','song-poetry','','[]','合抱長材卧壑深，于今惟恨不空林。',32,'全唐诗/poet.song.225000.json','["合抱長材卧壑深，于今惟恨不空林。", "誰知廣厦千斤斧，斲盡人間孝子心。"]'),
('1ab8856b-ad4f-4e04-bbcb-a66e0f481f59','二吳謠','淳祐民謠','宋','宋诗','song-poetry','','[]','大蜈蚣，小蜈蚣，盡是人間業毒蟲。',32,'全唐诗/poet.song.225000.json','["大蜈蚣，小蜈蚣，盡是人間業毒蟲。", "夤緣扳附有百足，若使飛天能食龍。"]'),
('91684057-dbc6-4527-9680-39257a05dff8','都門送杜樞院','區仕衡','宋','宋诗','song-poetry','','[]','赫赫中興業，黼扆咨明輔。',144,'全唐诗/poet.song.225000.json','["赫赫中興業，黼扆咨明輔。", "鋒車召黄巖，端笏拜西府。", "昔簉講筵班，倏接儀曹武。", "庶幾進讜言，衮職萬一補。", "璚琚厠珷玞，楩柟雜榛楛。", "鏡幾祈聖哲，厦構謀梁柱。", "云何夢傅時，而乃與噲伍。", "指圖玩金甌，進箴驕玉斧。", "旦夕尚逡巡，調劑竭肝腑。", "志竟不可諧，潔身謝鵷羽。", "道豈榮抽簪，思恒記銘釜。", "公行且居東，衮歸謁朱戶。"]'),
('6e503bc5-76e7-4ac0-8ce0-63d85a5e1c43','黄愷劉黻趙蕃王元野會講祐國僧舍','區仕衡','宋','宋诗','song-poetry','','[]','城角曉方罷，齋鐘時一鳴。',84,'全唐诗/poet.song.225000.json','["城角曉方罷，齋鐘時一鳴。", "良候屬春鶑，求友來嚶嚶。", "吾儕二三子，簪盍懷同聲。", "相期辨初志，視履規安行。", "道豈講解得，學以磨琢精。", "釋氏辨一心，且不蘄修名。", "齊盟共商求，勉旃在明誠。"]'),
('1be3e2e9-ea7e-430b-85dd-c30d8becfc40','聞徐右史暴亡','區仕衡','宋','宋诗','song-poetry','','[]','議論風生神采端，一身不保更論官。',32,'全唐诗/poet.song.225000.json','["議論風生神采端，一身不保更論官。", "泉臺此恨誰能訴，雪涕空山白日寒。"]'),
('d557f046-5b9e-416b-99c9-b0f27ee9a88d','酬呂監簿叔朝垂示試草','區仕衡','宋','宋诗','song-poetry','','[]','禮樂三千不可聞，彤墀諸草似劉蕡。',32,'全唐诗/poet.song.225000.json','["禮樂三千不可聞，彤墀諸草似劉蕡。", "莫嗟起部官猶左，尺疏公田頼有君。"]'),
('4bd475ef-cde1-41db-a029-fdbb25dbc40f','祭酒慈溪公以月令勸講兼示諸生感事有作','區仕衡','宋','宋诗','song-poetry','','[]','按月明堂令，齋居古自稽。',48,'全唐诗/poet.song.225000.json','["按月明堂令，齋居古自稽。", "四時曾不忒，七政已能齊。", "禮向經帷奏，箋來學省題。", "元龜何用卜，伯起在關西。"]'),
('fe5d794b-170d-47a4-8d14-24c10ec97150','送劉聲伯赴南安軍羈置','區仕衡','宋','宋诗','song-poetry','','[]','鳳山君出早，馬廄我來遲。',48,'全唐诗/poet.song.225000.json','["鳳山君出早，馬廄我來遲。", "盤辟分齋日，流涕伏闕時。", "謫堪栽嶺樹，愁莫賦江蘺。", "橫浦看前輩，應劉鐵漢詩。"]'),
('415fd602-2db3-4233-9207-b44342c44848','寄趙仲白先輩','區仕衡','宋','宋诗','song-poetry','','[]','章臺杜牧之，長安孟東野。',24,'全唐诗/poet.song.225000.json','["章臺杜牧之，長安孟東野。", "憶君飛筆時，何處木蘭下。"]'),
('61ad02f3-0fab-46b9-a17d-7d4941ef1d7c','觀參寥手書','區仕衡','宋','宋诗','song-poetry','','[]','鵰飛鷙舉百篇詩，誰是浮屠玅總師。',32,'全唐诗/poet.song.225000.json','["鵰飛鷙舉百篇詩，誰是浮屠玅總師。", "若把貫休齊己論，風流惟有大蘇知。"]'),
('8f15f1f8-5702-4e33-b629-0fb1f8f948fc','喜聲伯謫還','區仕衡','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','生還今日寸心明，客淚初收恨亦平。',64,'全唐诗/poet.song.225000.json','["生還今日寸心明，客淚初收恨亦平。", "豈有安危關一疏，不知流逐到諸生。", "錢塘江上船猶待，玉枕山前屋未成。", "畎畝餘忠劉子政，也應全不爲修名。"]'),
('507d5389-d419-4129-9c2d-c0d6a518b8a3','贈稠長老','區仕衡','宋','宋诗','song-poetry','','[]','雙樹林間結草庵，拈花一笑拜瞿曇。',32,'全唐诗/poet.song.225000.json','["雙樹林間結草庵，拈花一笑拜瞿曇。", "玄風橡栗餐亭午，堂下門徒且放參。"]'),
('a315a0db-d782-454e-b94b-e62b19f774d2','建昌憩李尚書山房','區仕衡','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','舊里鳴珂一下車，蓬山西觀更誰如。',64,'全唐诗/poet.song.225000.json','["舊里鳴珂一下車，蓬山西觀更誰如。", "木天清夢何人到，花雨空林有客居。", "樓迥更堪看蠡澤，雲深猶自護匡廬。", "高齋曲館新增色，讀盡尚書萬卷餘。"]'),
('414ebda0-ca23-4a9a-a3ed-09baedd12d13','過金壇遇劉宰','區仕衡','宋','宋诗','song-poetry','','[]','故人逢傲吏，問驛下西關。',48,'全唐诗/poet.song.225000.json','["故人逢傲吏，問驛下西關。", "製錦誰能似，鳴琴爾自閑。", "京江三國地，斗野五州山。", "去矣繁霜鬢，烟波照白綸。"]'),
('6c31c45b-122b-422d-b429-1c50c7e08c1a','答趙宗白宣州寄詩次韻','區仕衡','宋','宋诗','song-poetry','','[]','三載樟亭信到遲，偏勞雙鯉寄相思。',64,'全唐诗/poet.song.225000.json','["三載樟亭信到遲，偏勞雙鯉寄相思。", "玄暉有興期頻訂，太白曾游亦自奇。", "顧我嘗爲秋圃客，知君不廢敬亭詩。", "未須更道澄江練，只候飛鳬上赤墀。"]'),
('1e0520db-58d6-4472-b7ca-8d578a749ead','與客西湖上感事','區仕衡','宋','宋诗','song-poetry','','["\u897f\u6e56"]','湖頭雙槳藕花新，五嫂魚羹麯院春。',32,'全唐诗/poet.song.225000.json','["湖頭雙槳藕花新，五嫂魚羹麯院春。", "只道西陵松柏下，繁臺賓客更何人。"]'),
('7e70c9c7-bdde-4d2f-973d-f299a8e01fa3','聞張山翁入黄鵠山','區仕衡','宋','宋诗','song-poetry','','[]','采薇黄鵠嶺，投迹去無蹤。',24,'全唐诗/poet.song.225000.json','["采薇黄鵠嶺，投迹去無蹤。", "我亦從今逝，浮雲四百峰。"]'),
('ebe03368-b756-4ca9-be0d-f7d3463ae7c8','蕭葉二子夜過','區仕衡','宋','宋诗','song-poetry','','[]','褐衣曾替衮衣愁，肉食誰知藿食憂。',32,'全唐诗/poet.song.225000.json','["褐衣曾替衮衣愁，肉食誰知藿食憂。", "斬馬尚方無可借，夜深燈下看吳鉤。"]'),
('c30ebb62-8a7e-45ec-9e43-0b61b38272e9','胡生行','區仕衡','宋','宋诗','song-poetry','','[]','君不見平陵班仲升，君不見句章闞德潤。',165,'全唐诗/poet.song.225000.json','["君不見平陵班仲升，君不見句章闞德潤。", "二子傭書日苦貧，投筆誦經總才雋。", "又不見二子之後有胡生，寸管從人落魄行。", "往往自詫骨非賤，口述二子功與名。", "鑿空絕域稱使者，孝廉爲郎補中舍。", "都鄉拜爵金印持，定遠封侯玉門射。", "胡生果是大耳兒，蛟龍尺水自有時。", "長安乞米齒編貝，且得待詔聊免饑。", "不能持釣富春澤，只解校文天祿閣。", "丈夫豈必終落魄，他時人認傭書客。"]'),
('36c80510-28a7-4d32-b9dd-5d56ad5b68ca','書事','區仕衡','宋','宋诗','song-poetry','','[]','南渡衣冠廢蒯緱，中原盡載向湖游。',64,'全唐诗/poet.song.225000.json','["南渡衣冠廢蒯緱，中原盡載向湖游。", "胡塵不謂飛滇海，鬼火何因暗鄂州。", "竟使兵家勞策畫，到今國是計恩仇。", "草茅死未忘哀憤，豈但燕雲恨白溝。"]'),
('f66b9d9c-a630-4121-b873-6b72f3bfc1e3','還家','區仕衡','宋','宋诗','song-poetry','','[]','芻蕘計已非，戇直得全稀。',48,'全唐诗/poet.song.225000.json','["芻蕘計已非，戇直得全稀。", "久病畏風露，深居思蕨薇。", "豹藏寧是隠，鳥倦早知歸。", "但有黔婁婦，猶堪老布衣。"]'),
('5a7c359b-6365-411a-9332-77da563713a5','游曹溪六祖寺','區仕衡','宋','宋诗','song-poetry','','[]','智藥曾過此，溪源掬水香。',48,'全唐诗/poet.song.225000.json','["智藥曾過此，溪源掬水香。", "西天傳鷲至，南海見龍藏。", "菩薩一心竟，伽梨六代長。", "千年法珠在，持得照迷方。"]'),
('80c7ab2f-3a87-46be-8b7d-a891b0c5cec8','登西樵後即往羅浮山','區仕衡','宋','宋诗','song-poetry','','[]','大科百丈興翛然，東向朱明七洞天。',64,'全唐诗/poet.song.225000.json','["大科百丈興翛然，東向朱明七洞天。", "躡級修衢通絕巘，鑿空靈竇架飛烟。", "鳳毛五色天巖上，竹篆千秋石室前。", "兩入名山勞蠟屐，安期于世竟能仙。"]'),
('da92c6e8-b05b-4df3-aa40-d943c784dd69','石竹花','區仕衡','宋','宋诗','song-poetry','','[]','風摇衡浦岸邊涼，露結江皋葉上霜。',32,'全唐诗/poet.song.225000.json','["風摇衡浦岸邊涼，露結江皋葉上霜。", "小玉移來窗檻裏，不勝愁思滿瀟湘。"]'),
('0510a090-ad5f-4b59-b699-329375436b3a','長林館','區仕衡','宋','宋诗','song-poetry','','[]','司空修史王官谷，貞白藏書句曲山。',32,'全唐诗/poet.song.225000.json','["司空修史王官谷，貞白藏書句曲山。", "我愧汗青無日就，深林空自掩柴關。"]'),
('222ebf16-5194-4e0a-9635-b09ae74d3b28','鄭寺丞鄧山長來訪林中','區仕衡','宋','宋诗','song-poetry','','[]','喧傳彩鷁下江干，村北村南稚子看。',64,'全唐诗/poet.song.225000.json','["喧傳彩鷁下江干，村北村南稚子看。", "呼酒咄嗟欣有客，住山寥落幸無官。", "不慚居士新藤帽，亦醉田家老瓦盆。", "君愛幽居尋舊好，幾來林下共清歡。"]'),
('fb3b8a6b-4d0a-4e04-8df3-648ef7fbfe08','雨中','區仕衡','宋','宋诗','song-poetry','','[]','蓬窗竹戶小園東，濕盡殘紅又淺紅。',32,'全唐诗/poet.song.225000.json','["蓬窗竹戶小園東，濕盡殘紅又淺紅。", "羨殺烏棲深樹穩，豆花籬落雨聲中。"]'),
('04d8d2dd-d5ac-4abe-941c-7d266d18bab6','五十','區仕衡','宋','宋诗','song-poetry','','[]','早衰方五十，短髮已成翁。',48,'全唐诗/poet.song.225000.json','["早衰方五十，短髮已成翁。", "客向閒居謝，詩因老病工。", "殘更啼絡緯，細雨落梧桐。", "明日晴當出，看山興未窮。"]'),
('330c0cba-3eff-4036-9ad2-3f05b9940d8b','柴門','區仕衡','宋','宋诗','song-poetry','','[]','豈少安危事，柴門獨倚樓。',48,'全唐诗/poet.song.225000.json','["豈少安危事，柴門獨倚樓。", "溪纔通舴艋，林已叫鉤輈。", "歸鬢霜俱落，冥心水不流。", "荆軻何用詠，劍術轉堪羞。"]'),
('5fe5abdc-a3e3-4f5b-b1ac-d6b0569ca094','嶺南大雪','區仕衡','宋','宋诗','song-poetry','','[]','海凍珊瑚萬里沙，炎方六出盡成花。',32,'全唐诗/poet.song.225000.json','["海凍珊瑚萬里沙，炎方六出盡成花。", "洛陽縱有行春令，誰問袁安處士家。"]'),
('29080f26-43ef-4897-ab6e-c7fa7eb4df64','讀景炎福州詔書','區仕衡','宋','宋诗','song-poetry','','[]','多難興邦海艦移，忽逢祀夏配天時。',32,'全唐诗/poet.song.225000.json','["多難興邦海艦移，忽逢祀夏配天時。", "小臣不死留雙眼，東向行都望六師。"]'),
('f6f04eb0-6afb-4ce5-826a-21ed8a723278','太玉洞聽琴','劉黻','宋','宋诗','song-poetry','','[]','無絃不成聲，有絃多失真。',84,'全唐诗/poet.song.225000.json','["無絃不成聲，有絃多失真。", "真聲在何所，和陶方寸春。", "文操惜已遠，孔壇嗟復陳。", "所以桑濮響，鄭衛波嬴秦。", "詎知幽谷間，迺聞太古淳。", "游魚出春水，鳴鶴橫霜晨。", "休羨廣陵秘，是雅皆怡神。"]'),
('aa102828-398c-4da6-aa3f-ea6c1720dc03','接家書','劉黻','宋','宋诗','song-poetry','','[]','朝朝聽來鴻，來鴻一何邈。',84,'全唐诗/poet.song.225000.json','["朝朝聽來鴻，來鴻一何邈。", "秋往冬又至，爾鴻胡來遲。", "凝眸屢東眺，飛雲渺天角。", "薄晚雲四低，來鴻似微雀。", "習習遠近人，尺書墜猶玉。", "亟啟讀平安，字字發天樂。", "殷勤謝來鴻，相過勿憚數。"]'),
('09a8632a-f4af-4da6-98af-80437de2e425','中興更化詩','劉黻','宋','宋诗','song-poetry','','[]','東南天一隅，誰起銅駝思。',216,'全唐诗/poet.song.225000.json','["東南天一隅，誰起銅駝思。", "雁蕩山之臞，匕飯悲黍離。", "矯首中興期，儒風昌四維。", "陰霾苦凝沍，光景幾逶遲。", "鴟鴞騰惡音，蛇虺紛剝脂。", "忠憤發夜氣，歷歷排姦辭。", "黎明叫閶闔，骨鯁蒼旻知。", "陽噓一脈春，萬宇同掀眉。", "睿智覺今是，廟斷消前非。", "疇昔兩揆賢，燭照朋邪欺。", "化絃易新調，活著扶危機。", "孽蜮遁妖迹，鳴鳳覽德輝。", "聾聵一甦醒，皇運興炎基。", "耿耿忠孝圖，炳炳恢復規。", "有志竟成事，失機將奚爲。", "布帛可禦寒，穀粟能療饑。", "盤錯見利器，疾病知良醫。", "今日墜悠邈，千古羞塗碑。"]'),
('8ab8c664-d8a1-4ff1-a85b-a72591c1dfe6','悼孫龍坡居士','劉黻','宋','宋诗','song-poetry','','[]','世教嗟蕪棘，獨立狷者儔。',72,'全唐诗/poet.song.225000.json','["世教嗟蕪棘，獨立狷者儔。", "寄隠萬卷林，不知霜滿頭。", "抗論異端息，觀志天爵修。", "一室即著庭，聖賢時與酬。", "編摩發雲漢，千古芸香留。", "毋云食報邈，諸郎稼方收。"]'),
('1944e6ed-fd27-4f2e-ac35-53bf7175f938','前廡兩學錄罷職公堂求經明行修之士充員時蜀人楊時發當其選楊君以賤姓名薦或謂余求之蜀人董□行越人俞季淵永嘉陳行之咸以爲不然余亦自揆焉而記以詩云','劉黻','宋','宋诗','song-poetry','','[]','汲古綆懼絕，植德根懼斸。',60,'全唐诗/poet.song.225000.json','["汲古綆懼絕，植德根懼斸。", "繩樞守窮賤，旦旦天境續。", "防意如長城，視身等良玉。", "禰薦非吾榮，臧毀詎吾辱。", "暗漏但勿欺，人心勝明燭。"]'),
('56381d50-e5f9-4005-8343-4c8f1be82af9','挽新昌俞夫人母','劉黻','宋','宋诗','song-poetry','','[]','我與令子交，道味見顔色。',72,'全唐诗/poet.song.225000.json','["我與令子交，道味見顔色。", "乃知貽教來，諄諄及岐嶷。", "世多諛墓文，令子序其實。", "範身唯禮閑，齊家本天則。", "子哀難盡書，母德更何極。", "寒風號古林，慈烏繞珉刻。"]'),
('c0abda91-3da6-436b-8ba5-2c87aee71ed1','寄徐子蒼','劉黻','宋','宋诗','song-poetry','','[]','洙泗千載孤，師友道已寂。',84,'全唐诗/poet.song.225000.json','["洙泗千載孤，師友道已寂。", "柯山風雪間，古韻響金石。", "予生眇云晚，志苦毛髮赤。", "大道惟一中，如渴饑飲食。", "智過愚不及，均之失天則。", "虛舟發真機，戶庭滿春色。", "印之賢聖言，充然乃有得。"]'),
('475b51b2-53ae-4e01-a9ea-e4ee32c7ddcb','風水','劉黻','宋','宋诗','song-poetry','','[]','不雨五十日，一雨生意回。',156,'全唐诗/poet.song.225000.json','["不雨五十日，一雨生意回。", "詎料雨復癡，日日聞震雷。", "中元節倏屆，巨飈恣喧豗。", "故挽水倒流，能撼山欲摧。", "掀茅與揚沙，境境人號哀。", "餘禾墊西甽，大木橫荒垓。", "芝田逮楠溪，廛井歸丘萊。", "飄骸填港匯，悲魄棲山隈。", "吁嗟今之人，瘥札相轆轠。", "籲天豈耄昏，靜□□□□。", "積乖必致盭，養燼終成炲。", "造化一感應，予奪何心哉。", "未聞豳詩官，租稅星火催。"]'),
('32decc49-9113-4d78-9b04-06c886b1f1fb','癸丑九月苦雨和宋飲冰韻','劉黻','宋','宋诗','song-poetry','','[]','旱潦苦傷稼，景象難休休。',108,'全唐诗/poet.song.225000.json','["旱潦苦傷稼，景象難休休。", "老農早夜祝，願見虞與周。", "彌望淚欲滴，相對如楚囚。", "蒼天叫不應，空使霜白頭。", "市廛强喧飾，村落多闃幽。", "僂指千載間，曾無三兩秋。", "竈冷蛙産釜，甕閒埃積蒭。", "長此更不已，菜色淪荒丘。", "陽精赫陰霾，庶寬漆室憂。"]'),
('e15efdbc-d23d-4c82-b9cc-c1a08a4dc267','代壽徐意一參政','劉黻','宋','宋诗','song-poetry','','[]','東南仁氣氳堪輿，武夷相望鍾真儒。',160,'全唐诗/poet.song.225000.json','["東南仁氣氳堪輿，武夷相望鍾真儒。", "考亭西山接伊洛，戶庭坦蕩除榛蕪。", "意一先生續正傳，剛以直養軻其徒。", "端平御史凜風節，歷歷抗疏誅姦諛。", "愛君憂國根性天，實與名稱名非沽。", "藝祖所謂社稷臣，四海歡呼登政途。", "津梁善類植泰道，柱石明堂開遠模。", "丹心炳炳照白髮，力扶國是消民瘉。", "共期聖祉登嵩華，長使廊廟聞都俞。", "黎元翹首望太平，願斡聖化還唐虞。"]'),
('3dd681f8-f0a4-4c52-9ae7-15b4278bd2f7','哭藝堂湯先生','劉黻','宋','宋诗','song-poetry','','[]','天地之性人爲貴，四體百骸仁義具。',240,'全唐诗/poet.song.225000.json','["天地之性人爲貴，四體百骸仁義具。", "先生領之皇降初，繇稚及耆全故步。", "深居獨觀昭曠原，學不師傳能自悟。", "真貧不撓萬境融，實行已熟群□□。", "深衣褒带山澤癯，經史百家羅府庫。", "東南清敘知幾何，見謂生賢扶世數。", "申公不召老丘園，共惜烟霞早成痼。", "予嘗北面承至言，如立明堂聞大濩。", "是時年方二十三，自歎摳趨已云暮。", "詎知窮餓驅遠遊，倏忽五年疏杖屨。", "世界剝爛志士稀，稽首斯文獨終慕。", "家書一幅來雁山，報言先生溘朝露。", "肝腸欲斷聲欲瘖，六月悲風起荒圃。", "先生諒與混沌游，魂魄聰明還太素。", "生兮無辱死有榮，虎護龍居老師墓。"]'),
('28387c19-337d-4c04-9c11-03470f16cb97','焦溪茶','劉黻','宋','宋诗','song-poetry','','[]','上猶石磑天下無，霏霏吐出焦溪腴。',112,'全唐诗/poet.song.225000.json','["上猶石磑天下無，霏霏吐出焦溪腴。", "龜泉二湛康廬如，瓦鼎纔跳魚眼珠。", "顧我常苦書腸枯，一汲河潤九里餘。", "山精木怪不作魔，澆過秦論風生裾。", "幾回喚醒眉山蘇，詩句零落樵與漁。", "向非朔洛角植黨，焦溪安得聲價俱。", "似聞東觀羅遺逸，煩君寄上圖經書。"]'),
('295d06f7-f204-4526-a28b-f70f21898a55','東坡竹石','劉黻','宋','宋诗','song-poetry','','[]','坡翁北歸留戲筆，數竹離奇生磈石。',128,'全唐诗/poet.song.225000.json','["坡翁北歸留戲筆，數竹離奇生磈石。", "世如有鳳必先知，碌碌凡禽誰得識。", "風不聲兮月不影，山僧笑我移枯瘠。", "嶺阯每苦烟瘴深，烟瘴何曾禍忠直。", "天使無垢來此邦，要與坡翁發真跡。", "大書特書等傲岸，方寸一虛隘八極。", "何年移植蓬萊宮，清風逼人寒半壁。", "枝可磨，葉可摘，石上根，祗如昔。"]'),
('72a262f3-c01b-4a6a-8d72-20c5812469b5','用韻酬胡編校','劉黻','宋','宋诗','song-poetry','','[]','詩成斷肝腑，寄我光焰長。',72,'全唐诗/poet.song.225000.json','["詩成斷肝腑，寄我光焰長。", "貞女守閒寂，志士多悲傷。", "烟雲起寒嶼，風雨喧夕窗。", "憂時付酒斚，惜日惟書斚。", "頤養匪丹汞，坤德明黄裳。", "羨君富奇植，獨榦難爲芳。"]'),
('b2ac2939-0fe5-49ab-9940-67942bc47fe1','追和淵明貧士詩七首  其一','劉黻','宋','宋诗','song-poetry','','[]','貧士何所營，但知貧可依。',72,'全唐诗/poet.song.225000.json','["貧士何所營，但知貧可依。", "日月照不盡，朝暮常分暉。", "水瘦魚自躍，林寒鳥亦飛。", "紛紛苦多求，此境誰同歸。", "石田久不種，難免良夜饑。", "饑本士之常，獨抱嫠婦悲。"]'),
('c8c2dd33-0e2b-4209-8a7d-852da25df2ac','追和淵明貧士詩七首  其二','劉黻','宋','宋诗','song-poetry','','[]','把書不釋手，非志冕與軒。',72,'全唐诗/poet.song.225000.json','["把書不釋手，非志冕與軒。", "昔有董仲舒，三載不窺園。", "道味歸肝脾，遑恤厨無烟。", "家貧未爲貧，有書足可研。", "寤寐千載心，俗子難與言。", "勿歎師友寂，日日親聖賢。"]'),
('5caab97f-e6d0-4117-8f86-2e3d73680e8a','追和淵明貧士詩七首  其三','劉黻','宋','宋诗','song-poetry','','[]','高山與流水，妙趣歸之琴。',72,'全唐诗/poet.song.225000.json','["高山與流水，妙趣歸之琴。", "吾媿學未成，匪歎無知音。", "但向胸中會，毋勞指下尋。", "種菊或可茹，得酒聊復斟。", "窮達非所期，動靜一以欽。", "發爲琴之聲，邈矣天地心。"]'),
('dd95f126-f2d9-4ff3-b516-8aff4a9ed0cc','追和淵明貧士詩七首  其四','劉黻','宋','宋诗','song-poetry','','[]','平生抱狷介，深愧唾面婁。',72,'全唐诗/poet.song.225000.json','["平生抱狷介，深愧唾面婁。", "蒿萊常閉門，與世疏應酬。", "奈何世患稔，鯁鯁如馬周。", "顛頓亦良苦，饑羸非所憂。", "皇路益以榛，忍作寒蟬儔。", "口禍渺無際，困辱祗自求。"]'),
('59721740-861d-4225-9d07-ab502396d189','追和淵明貧士詩七首  其五','劉黻','宋','宋诗','song-poetry','','[]','靜對松竹枝，一塵無相干。',72,'全唐诗/poet.song.225000.json','["靜對松竹枝，一塵無相干。", "飲酒不至醉，讀書匪求官。", "畦瘠多種菊，采采亦可餐。", "衣冠背時樣，筆硯同歲寒。", "但求聖賢心，肯效兒女顔。", "紛紛往來者，笑我柴門關。"]'),
('e67e70ff-6774-4fd1-80ba-1dd931546908','追和淵明貧士詩七首  其六','劉黻','宋','宋诗','song-poetry','','[]','人生特寄耳，何往非萍蓬。',72,'全唐诗/poet.song.225000.json','["人生特寄耳，何往非萍蓬。", "世挾智反愚，予謂拙乃工。", "淵明有姱節，高邁疏與龔。", "大抵豪傑士，所見自略同。", "簞瓢非遂窮，軒冕豈真通。", "倘不達至理，冥霧將奚從。"]'),
('97e385b0-f131-4bb9-8902-83455b63d6c6','追和淵明貧士詩七首  其七','劉黻','宋','宋诗','song-poetry','','[]','扁舟溯西江，忽抵梅花州。',72,'全唐诗/poet.song.225000.json','["扁舟溯西江，忽抵梅花州。", "二忠儼遺像，予愧非其儔。", "肝膽照冰雪，要亦狷者流。", "言直不砭時，掇禍貽親憂。", "山禽似相盼，來往疑勸酬。", "闃坐生萬感，矯首觀前修。"]'),
('40682517-e6d3-4a43-9ed5-6792caedb7b1','兀兀棲精廬','劉黻','宋','宋诗','song-poetry','','[]','兀兀棲精廬，青山日相對。',204,'全唐诗/poet.song.225000.json','["兀兀棲精廬，青山日相對。", "靜照年少非，動虞壯士悔。", "耕鋤計已晚，畚築力猶耐。", "夜卧司馬衾，晨餐魯直菜。", "自計清廟修，誰知圜壁壞。", "人情春水波，世事寒雲態。", "直道叢百謫，孤蹤繞群吠。", "拘纍僒形骸，憂危積肝肺。", "逢人口即瘖，出戶足如礙。", "周程儼範模，劉張遺謦欬。", "滌垢學歸愚，達增務韜晦。", "志苦秋不磨，髮白春匪載。", "採菊聊傾觴，延蘭可紉佩。", "官餽乏三月，家書隔千載。", "楚語欲聽慣，峒關驚未潰。", "冥冥瘴霧間，冋冋靈光在。", "莫揮感時淚，山水怡吾愛。"]'),
('10c2a815-f202-4628-8350-86d5eb73ab75','和張無垢胡澹庵二先生清江亭記  其一','劉黻','宋','宋诗','song-poetry','','[]','一靜心境融，飛躍昭上下。',72,'全唐诗/poet.song.225000.json','["一靜心境融，飛躍昭上下。", "大道元不磨，人情自榮謝。", "兩翁投遐荒，浩然獨餘暇。", "悲此當道狐，羞彼立仗馬。", "命義俯仰間，誰復論冬夏。", "一笑清江濱，瓦杯勝瓊斚。"]'),
('0547ec9e-8137-440d-97bb-a6aa16d459ff','和張無垢胡澹庵二先生清江亭記  其二','劉黻','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','丙子復丙辰，居然百載下。',72,'全唐诗/poet.song.225000.json','["丙子復丙辰，居然百載下。", "青山招我來，寒燠任更謝。", "寤寐古人心，處變亦如暇。", "紛紛艷孔張，翕翕嘖賈馬。", "世道長江流，何人屹中夏。", "漆室空興嗟，且酌宜城斚。"]'),
('4606c877-c9f5-40a0-86ae-6752756b65fb','寄時天彝','劉黻','宋','宋诗','song-poetry','','[]','亭亭萬木林，古柏集新翠。',60,'全唐诗/poet.song.225000.json','["亭亭萬木林，古柏集新翠。", "凌厲雪與霜，不凋自天粹。", "清廟嗟欲頹，誰堪棟梁器。", "之材百世珍，造物巧相遺。", "予抱憂國心，相逢喜忘寐。"]'),
('99272ad2-f9a5-448c-a120-01a7bec2b548','草','劉黻','宋','宋诗','song-poetry','','[]','萬卉爭獻奇，小草亦足貴。',60,'全唐诗/poet.song.225000.json','["萬卉爭獻奇，小草亦足貴。", "四時春不斷，可識天地意。", "穉子謹勿斲，葉葉含元氣。", "人皆訝姑息，姑息特細事。", "祗恐生道滅，形色鼎中沸。"]'),
('a192cddb-894f-49f4-815f-8535389dcd7d','菜','劉黻','宋','宋诗','song-poetry','','[]','鋤荒種新雨，擢秀美且艷。',60,'全唐诗/poet.song.225000.json','["鋤荒種新雨，擢秀美且艷。", "生理未羞窄，採擷足飫饜。", "每擅筐筥芳，湘以鹽與釅。", "舌根多嗜珍，味爾乃針砭。", "充之宇宙間，境境浩無欠。"]'),
('5d0c659a-01c4-4928-b07c-b77c2e69d2a7','夏夜','劉黻','宋','宋诗','song-poetry','','[]','青燈人語寂，池塘響蛙蛤。',24,'全唐诗/poet.song.225000.json','["青燈人語寂，池塘響蛙蛤。", "孤坐如老禪，門開風自闔。"]'),
('d7758b4f-34d0-47db-b503-1d3c61ba1b2f','謝惠笋','劉黻','宋','宋诗','song-poetry','','[]','饑腸數日吼，往往茄莧爭。',72,'全唐诗/poet.song.225000.json','["饑腸數日吼，往往茄莧爭。", "幽人盼寂寥，餉我慈竹萌。", "斑斑未離䙀，白下莫與京。", "寒泉煮青茆，手調玉版羹。", "招僧招不來，貰酒乃獨烹。", "茄莧避三舍，紙帳午夢寧。"]'),
('d7587412-269b-4709-9bd5-11dd8b841398','月','劉黻','宋','宋诗','song-poetry','','[]','天公屬月爲眼睛，曉夜不息天中行。',64,'全唐诗/poet.song.225000.json','["天公屬月爲眼睛，曉夜不息天中行。", "癡人習見圓復缺，謂此眼睛非長明。", "渠思一照千古白，奚分朔望陰與晴。", "彼昏病癡苦營營，以月視之蠅在罌。"]'),
('1cac4d99-d448-4fbb-903c-d80007a79fa0','贈江山人','劉黻','宋','宋诗','song-poetry','','[]','相山如相人，不論肥與瘠。',48,'全唐诗/poet.song.225000.json','["相山如相人，不論肥與瘠。", "神氣參有無，毫釐千里隔。", "今古非茫茫，山骨水爲液。", "誰歟璞輅翁，眼爲天地碧。"]'),
('141fac81-e09b-4c11-912f-25fdb26a0938','和紫陽先生感興詩二十首  其一','劉黻','宋','宋诗','song-poetry','','[]','至理根一初，精微實高廣。',72,'全唐诗/poet.song.225000.json','["至理根一初，精微實高廣。", "寄之形氣中，今來齊古往。", "衆曜列太空，環侍惟斗仰。", "變化妙不測，虛靈本常朗。", "井坐識易陋，簾窺學云罔。", "靜玩感興篇，剖陳如指掌。"]'),
('af69d557-6234-402b-866f-9c5968a5e0c7','和紫陽先生感興詩二十首  其二','劉黻','宋','宋诗','song-poetry','','[]','陰陽著太極，萬化惟一中。',48,'全唐诗/poet.song.225000.json','["陰陽著太極，萬化惟一中。", "權衡迭軒輊，樞紐相始終。", "人受命以生，今古穉耄同。", "彼昏自不覺，安用尤聵聾。"]'),
('4c7ca2f5-a1ca-43cf-a891-1223665e1cab','和紫陽先生感興詩二十首  其三','劉黻','宋','宋诗','song-poetry','','[]','仰觀復俯察，上下融真機。',72,'全唐诗/poet.song.225000.json','["仰觀復俯察，上下融真機。", "元氣無奇耦，魚躍鳶自飛。", "神聖奠中域，靜動心勿違。", "天地斂諸躬，照以日月輝。", "遜志納衆有，先慮周萬微。", "胞與豈不夥，游泳皇極歸。"]'),
('15cb62ec-867b-40bd-aa4f-d2b480146322','和紫陽先生感興詩二十首  其四','劉黻','宋','宋诗','song-poetry','','[]','造化洩元秘，河洛圖書出。',72,'全唐诗/poet.song.225000.json','["造化洩元秘，河洛圖書出。", "龜龍亦何心，以靈乃受役。", "微旨竟先天，妙用普經國。", "三聖受心印，執中數語畢。", "詁學長枝蔓，往往膠陳迹。", "偉哉千載下，元公指無極。"]'),
('77f027cd-284e-47df-b2c3-d29da9e98191','和紫陽先生感興詩二十首  其五','劉黻','宋','宋诗','song-poetry','','[]','文盛起太息，姬壤半淪夷。',96,'全唐诗/poet.song.225000.json','["文盛起太息，姬壤半淪夷。", "仁積天所親，道喪人已離。", "霸圖迭雄長，明詛興自茲。", "王綱久不競，覽卷空涕洏。", "日月照干戈，風雨撼璧珪。", "仲尼不夢周，世道無復爲。", "元氣日以薾，荏苒朝露悲。", "嫠婦抱隠憂，忠矣非知機。"]'),
('84e7469b-d207-4be7-a3b3-98ba79200238','和紫陽先生感興詩二十首  其六','劉黻','宋','宋诗','song-poetry','','[]','宇宙浩無際，主靜即其綱。',120,'全唐诗/poet.song.225000.json','["宇宙浩無際，主靜即其綱。", "靜非寂以槁，密運治乃良。", "公明闓晏燦，忠慤消彊梁。", "山河帝居壯，日月天德光。", "八荒囿一和，此界均彼疆。", "鴟鴞息晝鳴，鳳凰梧桐翔。", "黔黎歌爾極，逢掖趨大方。", "皇風播品物，道闢淑運昌。", "樞機不盈握，妙斡見弛張。", "奈何動志靜，反袂千古傷。"]'),
('55d77563-332b-41df-ab27-e9e48eb5690a','和紫陽先生感興詩二十首  其七','劉黻','宋','宋诗','song-poetry','','[]','我聞嬴秦氏，威力橫提封。',120,'全唐诗/poet.song.225000.json','["我聞嬴秦氏，威力橫提封。", "北方迤長城，中土銷春風。", "阡陌鞅肆孽，簡編斯造凶。", "民命眇以墜，天勢巍且崇。", "中焦痼成痞，怨氣蟠壤穹。", "炎漢一洗之，詎詫百戰功。", "規模納群策，意度恢大公。", "約法止三章，赤子歸包容。", "溺冠膠餘習，莫致商山翁。", "過魯嘗蕆祠，猶足醒昏蒙。"]'),
('09c3cb23-6a69-48a1-8c18-3c8a472a8590','和紫陽先生感興詩二十首  其八','劉黻','宋','宋诗','song-poetry','','[]','東都黨錮禍，機阱深九淵。',72,'全唐诗/poet.song.225000.json','["東都黨錮禍，機阱深九淵。", "標榜起俊厨，接踵沈黄泉。", "西園久握爵，龍門昧幾先。", "忠魂招不返，炎祚孰以綿。", "諒矣文君癡，猶覬冷燼然。", "吁嗟萬鈞壓，一綫那能牽。"]'),
('e9df174c-101c-4d58-a493-1b2c357f49e6','和紫陽先生感興詩二十首  其九','劉黻','宋','宋诗','song-poetry','','[]','坤輿載五嶽，乾象垂三光。',72,'全唐诗/poet.song.225000.json','["坤輿載五嶽，乾象垂三光。", "太極宰元化，俯仰無低昂。", "一理貫萬有，形色皆停當。", "晉風競清談，幽眇誇輝煌。", "坐銷白晝盡，狐兔睨其旁。", "天地亦爲愁，何但頹偏方。"]'),
('992b3176-a3ee-4624-8641-e13608fb3b2c','和紫陽先生感興詩二十首  其一○','劉黻','宋','宋诗','song-poetry','','[]','立朝觀大節，炳炳在行己。',72,'全唐诗/poet.song.225000.json','["立朝觀大節，炳炳在行己。", "李唐號多才，屹立整頹紀。", "前狄後有韓，高風世仰止。", "孤忠翼正祚，大論闢非禮。", "老榦挺冬嶺，明魄浸秋水。", "均抱扶世心，勳學豈殊軌。"]'),
('eecd403f-4893-4936-b4f0-f7a9e25d075a','和紫陽先生感興詩二十首  其一一','劉黻','宋','宋诗','song-poetry','','[]','默觀羲聖書，先天著復坤。',72,'全唐诗/poet.song.225000.json','["默觀羲聖書，先天著復坤。", "畫畫妙理具，森立河圖文。", "宇宙斡生意，日月寧辭奔。", "乘承著不息，反窮性存存。", "透彼名利關，洞此道義門。", "用功不精密，頻復何由敦。"]'),
('47e13125-6d17-4c9b-9239-4a097081c2bb','和紫陽先生感興詩二十首  其一二','劉黻','宋','宋诗','song-poetry','','[]','詩道發金石，世苦壁聽訛。',48,'全唐诗/poet.song.225000.json','["詩道發金石，世苦壁聽訛。", "正色落芻蕘，一掬真意多。", "衆竅本虛寂，其如天籟何。", "不悟康衢謠，不識黍離歌。"]'),
('e407f109-00fa-4fa5-8442-257c5b1d0263','和紫陽先生感興詩二十首  其一三','劉黻','宋','宋诗','song-poetry','','[]','禮樂節性情，工夫貴深省。',72,'全唐诗/poet.song.225000.json','["禮樂節性情，工夫貴深省。", "愛親篤冰履，酬世尚錦絅。", "勿任忘與助，一敬收衆騁。", "威儀筋骸束，趣味精神領。", "相彼屋漏中，森若指見炳。", "窮達付天分，靈光勿隨境。"]'),
('35ee0c6d-6a67-43a7-81f6-4b5dd2d003a3','和紫陽先生感興詩二十首  其一四','劉黻','宋','宋诗','song-poetry','','[]','書法嚴貶褒，明辨邪正根。',48,'全唐诗/poet.song.225000.json','["書法嚴貶褒，明辨邪正根。", "寒暑自迭禪，日星常與存。", "浮雲豈不翳，昭晰誰其昏。", "筆削匪爛報，執拗開亂原。"]'),
('aa31bd9d-d0e2-4447-ae29-5bff4b6e6097','和紫陽先生感興詩二十首  其一五','劉黻','宋','宋诗','song-poetry','','[]','仙佛各有門，託言深入山。',72,'全唐诗/poet.song.225000.json','["仙佛各有門，託言深入山。", "一探寂滅宗，一透鉛汞關。", "菩提悟非樹，刀圭詫靈丹。", "槁形付塵幻，蛻骨沖飛翰。", "咄咄亦奇事，詎憚力到難。", "儒先著明訓，整轡皇路安。"]'),
('4c11ab37-0c88-4366-93d2-9415c9ca1177','和紫陽先生感興詩二十首  其一六','劉黻','宋','宋诗','song-poetry','','[]','智巧役一世，往往悲古愚。',72,'全唐诗/poet.song.225000.json','["智巧役一世，往往悲古愚。", "觸蠻榮利場，白日事浮虛。", "情流失固有，意騖希本無。", "相與龍斷登，獨不捷徑趨。", "是非遂倒植，大道歸糊塗。", "發憤中夜思，猶有未亡書。"]'),
('c7d03c76-6b55-4a1c-8da6-1ed4a1682541','和紫陽先生感興詩二十首  其一七','劉黻','宋','宋诗','song-poetry','','[]','扶輿播清淑，何代不毓才。',72,'全唐诗/poet.song.225000.json','["扶輿播清淑，何代不毓才。", "森森萬壑松，盍厚拱把培。", "蒙養正性存，臨教大義開。", "嗟哉古道息，習氣少已乖。", "區區黄冊子，所事惟奪魁。", "戶庭且得色，斯文何望哉。"]'),
('17bd207f-34ea-4ffc-be6b-2bce068b2106','和紫陽先生感興詩二十首  其一八','劉黻','宋','宋诗','song-poetry','','[]','人生戒悠悠，早已闇大方。',96,'全唐诗/poet.song.225000.json','["人生戒悠悠，早已闇大方。", "卓爾志有立，不墜炎與涼。", "孫弟浹閭里，孝愛充室堂。", "應對動以恪，操存靜而莊。", "見善如乘珠，視惡如釜湯。", "毫釐貴明辨，造次宜謹詳。", "勿謂居壯年，光陰隙駒忙。", "窮理養夜氣，任運爲沈翔。"]'),
('97311083-c97e-436d-92a5-34b0623ee3a2','和紫陽先生感興詩二十首  其一九','劉黻','宋','宋诗','song-poetry','','[]','交游重金石，里巷毋泛尋。',72,'全唐诗/poet.song.225000.json','["交游重金石，里巷毋泛尋。", "胸中抱明鏡，妍醜不相侵。", "熱交但以貌，冷交惟其心。", "勢利易苟合，道義難力任。", "詠春發真趣，邀月開凡襟。", "夷險祇一節，雞鳴風雨林。"]'),
('38f31686-7293-47e3-8f65-86b8a822edbb','和紫陽先生感興詩二十首  其二○','劉黻','宋','宋诗','song-poetry','','[]','聖人不可見，猶幸聞緒言。',72,'全唐诗/poet.song.225000.json','["聖人不可見，猶幸聞緒言。", "萬古宇宙立，一脈理義溫。", "專門鑿私智，百家起豗喧。", "太陽炳離照，坐收烟霧昏。", "魯語本非略，軻書豈爲繁。", "資之歲月深，左右皆逢原。"]'),
('35858f77-4a65-454a-b670-c119dc0e004f','送茶','劉黻','宋','宋诗','song-poetry','','[]','我得新焙珍如金，持以餉君將我心。',112,'全唐诗/poet.song.225000.json','["我得新焙珍如金，持以餉君將我心。", "縱無龍文與棋局，白雲一椀搜書林。", "玉川不作陸羽沈，茫茫世上誰知音。", "曇濟道人亦復往，八公山頂留荒岑。", "我生與渠似有分，一日不見幾成瘖。", "檳榔是弟橄欖兄，大抵苦澀味乃深。", "車聲出鼎策奇雋，書窗靜坐聞山禽。"]'),
('a7f53780-caf3-41bd-9165-dd8b0f831106','悼使君趙計院','劉黻','宋','宋诗','song-poetry','','[]','我作壽公詩，倏聞公已古。',204,'全唐诗/poet.song.225000.json','["我作壽公詩，倏聞公已古。", "道路涕行人，田閭愕農父。", "謂公肫肫仁，潤澤溢橫浦。", "穀我艱爾振，寇我驚爾撫。", "涉我病爾梁，役我殫爾宇。", "冬我瘴爾雪，夏我魃爾雨。", "飲鄉羅俎豆，建學闈儀矩。", "善政襲西都，文風被東魯。", "闔一郡三邑，擔簦白繡斧。", "草木爲動色，禽魚亦掀舞。", "誰趣玉樓文，竟奪鯉城主。", "人物落曉星，如公不多數。", "豈但賀白倫，端與間平伍。", "我崎嶇遠來，不絕命如縷。", "凄風守憔悴，暖意勤噢咻。", "我生特蝗粟，公死即傾柱。", "顧我莫贖公，龍德嗇下土。"]'),
('03274f23-e08d-466e-9904-1fc9de6b3b53','矻矻何所思','劉黻','宋','宋诗','song-poetry','','[]','矻矻何所思，一默照群妄。',72,'全唐诗/poet.song.225000.json','["矻矻何所思，一默照群妄。", "門外風雨深，山鳥亦不訪。", "有書足遮眼，寤寐古人樣。", "菜根清苦趣，木朽支離狀。", "深衣持夜香，往往禦烟瘴。", "矯首知己賢，大有蒼生望。"]'),
('60465706-e2f8-48cd-a2c7-e24bafd08355','餞傅理掾','劉黻','宋','宋诗','song-poetry','','[]','一郡一理掾，橫浦爲之宗。',120,'全唐诗/poet.song.225000.json','["一郡一理掾，橫浦爲之宗。", "青青草不枯，曾識無極翁。", "遂寧起鼻祖，陸續書問通。", "乃今有耳孫，力學追遐蹤。", "潔靜二湛水，峭介雙秀峰。", "平反幾春意，坐令古犴空。", "政最復政最，匪詫赫赫功。", "庭草色若何，還與慶曆同。", "歸歟浩無怍，扁舟驚輕篷。", "邦民再見公，繡斧番禺東。"]'),
('1cb6ef8d-c94a-4f5d-ad06-2c3a031696a1','寄與權器之二友','劉黻','宋','宋诗','song-poetry','','[]','鴻鈞盎一宇，何物非生意。',108,'全唐诗/poet.song.225000.json','["鴻鈞盎一宇，何物非生意。", "輪囷得此剝，而有此憔悴。", "根蠹聚螾蛭，榦古禦魑魅。", "旦旦斧斤尋，九殞特其易。", "飛鳥不敢棲，何哉蓊蔚芘。", "風雨極震凌，霜雪苦顛躓。", "天地大父母，榮枯均厚施。", "腐植産靈芝，至美終不閟。", "桃李信春妍，奈何骨嫵媚。"]'),
('7fd622ab-f670-4842-ab03-bafa64dea3f1','秋心','劉黻','宋','宋诗','song-poetry','','[]','秋日日苦短，秋夜夜苦長。',72,'全唐诗/poet.song.225000.json','["秋日日苦短，秋夜夜苦長。", "長短不易晷，處厄心自傷。", "秋風獨有聲，葉葉闖我窗。", "秋月豈無情，隙隙窺我床。", "苒苒寒事迫，孰整衾與裳。", "故鄉隔萬山，籬菊那能芳。"]'),
('ecca3f60-5344-4dc5-be66-79e627ada425','城中有高樹','劉黻','宋','宋诗','song-poetry','','[]','城中有高樹，與我相爲鄰。',48,'全唐诗/poet.song.225000.json','["城中有高樹，與我相爲鄰。", "薄味生古道，靜坐疏今人。", "淵明酷愛菊，張翰勤思蓴。", "蓴菊我何有，一杯天地春。"]'),
('7212fadb-442a-42fb-a95b-3eacf9483e29','避寇','劉黻','宋','宋诗','song-poetry','','[]','戊午九月十，洶洶群寇生。',288,'全唐诗/poet.song.225000.json','["戊午九月十，洶洶群寇生。", "疋枹與赤水，參會童石氓。", "烹牛飫兇豎，剚人諂妖靈。", "長驅無齟齬，四境騰沸羹。", "野廬競趨察，廛市爭奔城。", "啼號震暮夜，陰氣昏冥冥。", "携持半箱筥，扛舁及甕罌。", "雞豕頭駢闐，脅息驚吞聲。", "宇內同一胞，何事起攙槍。", "據險惡氛聚，血牙餘種獰。", "原嶺迤巢穴，習鬭惟輕生。", "擲首視爲戲，揭竿誰敢攖。", "父老謂曩日，草竊恣橫行。", "郡將出奇計，一勦諸峒平。", "老熊痛已定，悍虎謀方興。", "若非急討捕，終難保桑耕。", "官兵駐大曷，警報馳飛星。", "探旗逼軍旅，登城羅義丁。", "菱角隠阨塞，松明通曉更。", "山前號令肅，鈴閣籌算精。", "疋馬熟往來，老穉倚以寧。", "溪潛鱗且遁，林散翼亦驚。", "顧予久放逐，逢此增伶俜。", "夜寢不忍睫，朝餐何所營。"]'),
('ca17750e-ee45-430b-8458-12be88e3f06b','雪屋爲吳夢蟾賦','劉黻','宋','宋诗','song-poetry','','[]','一廬天地寬，玉雪照四壁。',60,'全唐诗/poet.song.225000.json','["一廬天地寬，玉雪照四壁。", "天風吹不摇，夜半響鐵笛。", "彼美人無眠，梅花對岑寂。", "訪戴獨回舟，破蔡誰草檄。", "靜坐斂逸氣，中邊透虛白。"]'),
('c8bc4c30-6708-4b7c-ad6d-cf4ecbe4a92e','平寇','劉黻','宋','宋诗','song-poetry','','[]','西江十二州，自昔聞寇警。',288,'全唐诗/poet.song.225000.json','["西江十二州，自昔聞寇警。", "按圖覽上游，峒俗號最梗。", "嗜殺等兒戲，縱掠恣狼獷。", "右通崆峒東，左接梅花嶺。", "郴桂貫肘腋，相據易馳騁。", "巢穴聚一邑，流毒烈四境。", "寶祐戊午春，童石肆不靜。", "蔓延及夏秋，養成癰在頸。", "聚落焦山寨，廛市空竈井。", "田野寂牛鳴，道路息人影。", "焚劫不可計，聞問已先哽。", "太守趙大夫，一念切救拯。", "符移密有置，紀律務森整。", "憲鈐選精銳，薙獮赫弄梃。", "兇醜惡已貫，屠擄勢猶逞。", "提兵總郡將，指授疾雷霆。", "直擣姜坑屯，鋒交生死頃。", "夾擊馳若神，賊潰亂奔町。", "輜重委荆棘，纍纍殊首領。", "義丁群搜山，擒械半雄猛。", "天俾殲其渠，陽精遂昭炳。", "窠蜂果何號，花獸亦終穽。", "顧汝宇宙同，乃甘犬羊並。", "如醉復飲酒，亡生不知醒。"]'),
('717e2b7b-5bc4-432c-8daa-7500e3ee079c','詠月追和韓昌黎韻','劉黻','宋','宋诗','song-poetry','','[]','初秋十五夕，皓月來滄溟。',240,'全唐诗/poet.song.225000.json','["初秋十五夕，皓月來滄溟。", "白鷺與共色，烏鵲能踐靈。", "逢掖覓桂蔭，孩提窺兔形。", "涼氣浄餘暑，浮光滑青冥。", "列宿各韜彩，腐草休衒螢。", "浩蕩靈槎泛，瑩潔仙掌泠。", "門靜送佳客，窗虛照群經。", "佛閣高低見，譙更遠近聆。", "竹風摇瑣碎，花影列娉婷。", "靜坐禪安室，閒行詩繞庭。", "銀河占米價，璇象認文星。", "何處笛傳浦，誰家酒散亭。", "深閨悲蟋蟀，逆旅愬蓬萍。", "水闊平連素，山低遠抹青。", "有心齊肘腋，無計得輪停。", "八蜡神司社，方諸溜納瓶。", "魚翻波可樂，禽警露頻聽。", "歷歷天疑近，沈沈夜不扃。", "廣寒非寂寞，沙界遍輝熒。", "盈闕天之理，堯階任落蓂。"]'),
('55b7fdf3-ea95-474c-bd36-5f8088cd8de2','餞李叔飛赴劉朔齋招','劉黻','宋','宋诗','song-poetry','','[]','五侯之鯖紫駝峰，鹿鹿鬭鬬難爭雄。',80,'全唐诗/poet.song.225000.json','["五侯之鯖紫駝峰，鹿鹿鬭鬬難爭雄。", "世多果腹鮮知味，北斗以南推朔翁。", "桂林延入蓮花叢，相邀皓月烹清風。", "詎羨鮓麋與胹熊，座有一珍羣品空。", "舂容樽俎須却戎，海戢鯨波列上功。"]'),
('c778b773-2e95-4a71-acb7-d3adbdb0d162','六友詩寄林景雲留壽國林道初俞季淵 靜友','劉黻','宋','宋诗','song-poetry','','[]','靜友性不凡，惟嗜土石瘦。',48,'全唐诗/poet.song.225000.json','["靜友性不凡，惟嗜土石瘦。", "與草似無瘉，於吾如有舊。", "抱獨足養真，韜芳何深茂。", "清風苦好事，揄揚古今宙。"]'),
('37205d36-a936-48c7-9b38-a48b5a2a75da','六友詩寄林景雲留壽國林道初俞季淵 直友','劉黻','宋','宋诗','song-poetry','','[]','直友古耐交，莫問三兩箇。',48,'全唐诗/poet.song.225000.json','["直友古耐交，莫問三兩箇。", "玉立君子姿，足以警吾惰。", "虛心內有容，勁節老無挫。", "荒遠親舊違，得汝乃自賀。"]'),
('00c29c4c-e7a5-45c2-87a2-2a7d929f0178','六友詩寄林景雲留壽國林道初俞季淵 浄友','劉黻','宋','宋诗','song-poetry','','[]','浄友何亭亭，修潔得自性。',48,'全唐诗/poet.song.225000.json','["浄友何亭亭，修潔得自性。", "本生淤泥中，乃與玉同瑩。", "一浄消萬暑，特立起群敬。", "色香非色香，是謂花之聖。"]'),
('b830fb5c-c732-400c-9d98-182a2b8a19d0','六友詩寄林景雲留壽國林道初俞季淵 高友','劉黻','宋','宋诗','song-poetry','','[]','高友住山中，無心涉塵圃。',48,'全唐诗/poet.song.225000.json','["高友住山中，無心涉塵圃。", "山中有明月，明月照棲鷺。", "幽人眠不成，披衣起閒步。", "相得靜無際，勿訝秦官污。"]'),
('10499e91-07c8-4205-a5fe-e54b643530ae','六友詩寄林景雲留壽國林道初俞季淵 節友','劉黻','宋','宋诗','song-poetry','','[]','節友獨愛秋，相得匪遲暮。',48,'全唐诗/poet.song.225000.json','["節友獨愛秋，相得匪遲暮。", "受氣惟至正，睟見黄與素。", "飽諳風露味，甘守烟霞痼。", "如何千載人，僅一淵明遇。"]'),
('c5ead176-7912-43d6-9838-f6170327b085','六友詩寄林景雲留壽國林道初俞季淵 清友','劉黻','宋','宋诗','song-poetry','','[]','清友天賦完，歲晚樹獨暖。',48,'全唐诗/poet.song.225000.json','["清友天賦完，歲晚樹獨暖。", "粲此白玉英，瑟彼清廟瓚。", "香自根中來，冰雪匪壓斷。", "一見一回老，殷勤呼茗椀。"]'),
('89385ecd-8896-4458-9bac-bdf5f8191e69','還譚鳴玉北枝稿','劉黻','宋','宋诗','song-poetry','','[]','天下惟此花，渠町南與北。',48,'全唐诗/poet.song.225000.json','["天下惟此花，渠町南與北。", "有翁號北枝，似惋宇宙塞。", "紛紛紅紫蹊，陽春豈不力。", "枝北春雖遲，今古冰霜特。"]'),
('cdb0cca3-2b7e-4867-86bc-4b96114ee5f3','贈鍾春谷星學','劉黻','宋','宋诗','song-poetry','','[]','五星聚東井，老人現端門。',108,'全唐诗/poet.song.225000.json','["五星聚東井，老人現端門。", "總是太平象，渾儀妙用存。", "巖傅本騎箕，執築付無言。", "一旦寄霖雨，夜夢形至尊。", "試問古馮相，此數如何論。", "太乙照西蜀，子午斜谷昏。", "毘陵星霣石，田里春風溫。", "穹壤一理氣，理爲氣之根。", "步推尋其元，太極昭乾坤。"]'),
('501ea212-5a7b-49cb-8c5d-08a39291d0b8','餞湖南趙提舉','劉黻','宋','宋诗','song-poetry','','["\u8861\u5c71"]','丹湖偉人維南城，胸有老范真甲兵。',216,'全唐诗/poet.song.225000.json','["丹湖偉人維南城，胸有老范真甲兵。", "挈來庾江鎮魚壘，坐令□□□無驚。", "峒獠習鬭不識機，亦以出草爲常程。", "痛勦根株讋群鬨，方知弄梃不如耕。", "吾皇詔趣度湘水，溪蠻辟易梟休聲。", "玉節清風肅九郡，清風肅處春風生。", "邦民借寇欲斷橋，願公爲我誅鯢鯨。", "邦民愛公欲植棠，願公爲我銷欃槍。", "愛旗獵獵羅道左，竹馬截鐙兒童爭。", "我爲峒寇特區區，更有西江狡謀成。", "蜀危纍卵淮破甑，聲東擊西誰拄撐。", "二矛重弓列御屏，衡山雲起瀟湘清。", "指日南城障東南，托天半壁一柱擎，願摩浯石歌中興。"]'),
('3f60fbae-38ce-46af-b83f-5f93446431ae','古興和饒雲峰韻  其一','劉黻','宋','宋诗','song-poetry','','[]','貧婦守蓬藋，顦顇無顔姿。',132,'全唐诗/poet.song.225000.json','["貧婦守蓬藋，顦顇無顔姿。", "挈瓶養公姑，肯涉山徑蹊。", "夫君昵浮響，疏越成暌離。", "家欠蠶織具，茹苦寧力支。", "叫天天不應，聽彼風雨迷。", "明月古玄鏡，清夜長分輝。", "見月如見君，此道惟心知。", "造化毋群動，一耦仍一奇。", "得耦固有分，失意吾何悲。", "綠髮已改色，素節難轉移。", "君有內覺時，伯牙逢子期。"]'),
('cb7c7bd5-dbe0-47e1-ad87-1a63915d21f1','古興和饒雲峰韻  其二','劉黻','宋','宋诗','song-poetry','','[]','賤妾命猶紙，青燈傍低牆。',132,'全唐诗/poet.song.225000.json','["賤妾命猶紙，青燈傍低牆。", "群艷逞春嬌，半葉難言芳。", "手織補天線，五色生輝光。", "主家不顧盼，內美誰鋪張。", "妾命痛在身，病痞非病狂。", "滴滴肝胃泣，奚暇宮樣妝。", "層陰閣深燠，雨露膠雪霜。", "猶記承恩時，曾不一餉忘。", "忠勸勿飲酒，□恕乃溢觴。", "妾心諒安往，勿飲君壽長。", "渠知滄海深，難以升斗量。"]'),
('aa931800-c543-4bd7-8dcd-e8c76578c59a','聞陳正學理琴','劉黻','宋','宋诗','song-poetry','','[]','聞君整琴待秋風，我欲從之魂夢通。',160,'全唐诗/poet.song.225000.json','["聞君整琴待秋風，我欲從之魂夢通。", "素麻髣髴蒼髯翁，揚休山立崆峒東。", "淚痕猶濕龍門桐，有曲無音悲天公。", "猗蘭未冷拘幽濃，那知斯道將遂窮。", "山矸石爛冥感叢，枝蜩盤蠅迭相雄。", "兩耳年來怪不聰，群哇擾雜安於聾。", "煩君爲我調怔忡，流泉隠隠深澗中。", "春溫廉折各不同，聲雖在指意在胸。", "雲飄柳絮風入松，恍然樓閣坐虛空。", "伯牙所知何必鍾，白鶴飛來采芹宮。"]'),
('52c2daeb-e3aa-42dc-9960-10013ef6505f','梅使君守橫浦擒寇閔雨','劉黻','宋','宋诗','song-poetry','','[]','猛虎久負嵎，吞噬草木痏。',168,'全唐诗/poet.song.225000.json','["猛虎久負嵎，吞噬草木痏。", "流毒烈贛吉，一呼蜂蝟起。", "老天福黔黎，雪村鎮梅壘。", "指授討捕略，前驅謝張李。", "火箭窮其巢，推算捷如駛。", "露布星火馳，餘獰悉披靡。", "大暑熾焚惔，心薌焫一縷。", "甘澤隨車至，咸曰雪村雨。", "人事天道協，除惡乃臻媺。", "洞落洗腥穢，生意從此始。", "雞豚醉秋社，老農自相語。", "生長子復孫，一飯不安匕。", "南人今不反，合爪鯉城主。", "願緩除書來，德風遍田里。"]'),
('861f5026-8cfd-4a23-b4e0-fe8fa192d217','喜雨呈趙使君','劉黻','宋','宋诗','song-poetry','','[]','閏餘五月即六月，一雨不來天欲裂。',192,'全唐诗/poet.song.225000.json','["閏餘五月即六月，一雨不來天欲裂。", "邦侯赤心走群望，喚醒癡龍睡時節。", "雷車風馭相後先，甘霔連天聲未歇。", "茅檐靜聽老農語，今歲夐與他年別。", "烟瘴壓低曾見雪，晴未兼旬雨復咽。", "區區枯草寧有知，孕出靈芝光吐結。", "邦侯求仁求此心，表裏不欺天地徹。", "爲霖何暇蜥藏甕，占雲已喜鸛鳴垤。", "斗頓溪流高一尺，盡與疲氓洗炎熱。", "晚禾獵獵實方腴，早稻津津香已馝。", "饑者可飽飽者逸，深夜城簫響清絕。", "持此豐年還聖主，願同何武歌休烈。"]'),
('cab4c104-5f1a-43a3-b202-2f9dafbb1266','與李叔夔錢子雲同遊興教寺約齊都巡','劉黻','宋','宋诗','song-poetry','','[]','古寺壞壁存菩提，又有達磨蒼龍如。',128,'全唐诗/poet.song.225000.json','["古寺壞壁存菩提，又有達磨蒼龍如。", "我來問訊若舊知，宇宙中間真蘧廬。", "朋儕邂逅誰親疏，秋風相對一笑醵。", "杯行草草復徐徐，山僧野朴談古初。", "謂元城老當此居，浩歎不足歌繼之。", "滿庭燦燦木芙蕖，疑是萊柏鄧栟櫚。", "人多病俗不可醫，天欲廢道還從渠。", "儒生腹大能幾圍，但教盛酒勿盛書。"]'),
('8e11968a-84a1-4e62-b5fb-74c43d302cf0','和酬張梅野','劉黻','宋','宋诗','song-poetry','','[]','郭行載酒相挈提，躡根探窟天津如。',128,'全唐诗/poet.song.225000.json','["郭行載酒相挈提，躡根探窟天津如。", "相逢何必皆親知，天地許大猶吾廬。", "矯首梅澗跡若疏，舂容婉畫妨清醵。", "詩如琴絃分疾徐，驚我一聲聾聵初。", "蕭蕭白日金仙居，東西求仲時從之。", "靜對夕陽搴紅蕖，或聽夜雨鄰翠櫚。", "國步孔棘須神醫，縱有鵲醯誰信渠。", "風傳西事方解圍，願君勿藏圯上書。"]'),
('32383c4e-ceb7-4f64-9b94-902adfd60e49','和譚學士見寄','劉黻','宋','宋诗','song-poetry','','[]','大道久磔裂，啾啾夸毗子。',192,'全唐诗/poet.song.225000.json','["大道久磔裂，啾啾夸毗子。", "彷彿皮毛鮮，孰探古人髓。", "我亦坐茲疾，默闃照非是。", "束身雲瘴鄉，凡論悉掩耳。", "夢不到伊傅，志惟高角綺。", "人生駒過隙，鹿鹿何時已。", "耽書夜不睡，省事日高起。", "疏苧寒亦燠，硬菜苦猶美。", "非忘漆室憂，莫救沙界痏。", "生死不可料，何哉爲泰否。", "佛祖顯雲封，道源開嶺趾。", "誰云築底邦，亶爲通德里。", "廬陵有可人，訪梅一至此。", "扣我理義關，無言但心只。", "新篇發天趣，步驟古詩史。", "窮通從所擇，柔舌與剛齒。"]'),
('3a27cc25-39af-43a0-b081-ea931863eb85','一舸','劉黻','宋','宋诗','song-poetry','','[]','一舸泛漭沆，風濤正掀舞。',60,'全唐诗/poet.song.225000.json','["一舸泛漭沆，風濤正掀舞。", "駕空赫魚龍，沈浮未知所。", "同舟一性命，俱父父母母。", "倚門望兒歸，天亦諒辛苦。", "胡爲託笑言，射影學溪弩。"]'),
('bc0d7f0f-d74c-4e4f-b6ce-25a0b84bd75a','猩猩行','劉黻','宋','宋诗','song-poetry','','[]','肩髮肖人形，言語劇機警。',72,'全唐诗/poet.song.225000.json','["肩髮肖人形，言語劇機警。", "罝罣不可招，幽曠從馳騁。", "胡爲所嗜偏，遇醪即首肯。", "染指疑含沙，浸淫歸酩酊。", "蹀履意欲歡，孰知墮深穽。", "鄙哉酣爵人，白頭猶未醒。"]'),
('30eeebe5-f816-444b-82e7-cf8756a2a15d','畏虎行','劉黻','宋','宋诗','song-poetry','','[]','於菟伏林薄，樵者遠斤斧。',60,'全唐诗/poet.song.225000.json','["於菟伏林薄，樵者遠斤斧。", "寧甘骨肉饑，毋蹈爪牙苦。", "山居聚落消，十室九閉戶。", "形影自相弔，祝神爲驅禍。", "獸毒猶可逃，急征罄罍鬴。"]'),
('e9762c19-134c-4830-9b3b-fec2c69fd74b','董孝子行','劉黻','宋','宋诗','song-poetry','','[]','嵊有董孝子，父病刲其肝。',156,'全唐诗/poet.song.225000.json','["嵊有董孝子，父病刲其肝。", "肝還猶可刲，一念充之難。", "遺體戒毀傷，此毀乃爲完。", "蕭條村落區，四顧藥餌艱。", "親病日且革，不療何由安。", "有父始有身，無父身奚存。", "裂肝粥以進，果獲急證寬。", "嗟哉古道闃，天紀紛夷殘。", "訟讟滓官府，縣尹悲溢顔。", "惓惓敦教化，各各還根元。", "邑民以孝聞，莫喻心所歡。", "大篇述梗概，詎侈詞藻繁。", "託之剡山川，千古禮義宣。"]'),
('5509f514-5c96-4402-b59b-8b35def945cc','戍婦吟','劉黻','宋','宋诗','song-poetry','','[]','月色暗還明，鄰家砧杵聲。',48,'全唐诗/poet.song.225000.json','["月色暗還明，鄰家砧杵聲。", "有衣難寄遠，無衣不關情。", "冰合長沙渡，霜枯細柳營。", "北征人未返，鴻雁又南征。"]'),
('6d400308-24ef-4d81-8abb-e01c17e0d8cc','和趙寺丞憶鶴吟','劉黻','宋','宋诗','song-poetry','','[]','既名仙者物，何恙亦沈冥。',48,'全唐诗/poet.song.225000.json','["既名仙者物，何恙亦沈冥。", "弔月憐孤影，埋雲惜瘦形。", "琴中空作操，詩外不消銘。", "葉落鳴皋處，猶疑昨夜聽。"]'),
('1fd58c2b-a0ac-4d37-b2a9-224d8e22fe09','三十一歲吟','劉黻','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','三十一年鴻蕩癯，隻影流落長江湄。',96,'全唐诗/poet.song.225000.json','["三十一年鴻蕩癯，隻影流落長江湄。", "耐寒忍苦還力饑，寤寐千古聖賢書。", "有時理到意獨會，有時慾動心如癡。", "有時目睫交宇宙，有時咫尺生藩籬。", "有時開口邈豪傑，有時瞑目慚嬰兒。", "堅凝力量在深省，但守瀟瀟風雨雞。"]'),
('17ec584a-1b53-4d1b-84d3-589a55bebdc4','丙辰吟','劉黻','宋','宋诗','song-poetry','','[]','熙寧歲丙辰，海內厄安石。',120,'全唐诗/poet.song.225000.json','["熙寧歲丙辰，海內厄安石。", "慶元歲丙辰，僞學禁如織。", "寶祐復丙辰，衣冠墮荆棘。", "龍蛇數云惡，鄭玄炳先識。", "諸生不齚舌，投荒誠予職。", "鵂鶹號屋頭，鼯鼠攪牀側。", "雲集膚已粟，日出汗欲赤。", "瘴癘半南州，可軒靠神力。", "所寓乃略同，蒼苔共岑寂。", "丙辰自丙辰，焚香且讀易。"]'),
('af0fd632-6f03-4315-907a-fac77c8c1ec8','五窮吟','劉黻','宋','宋诗','song-poetry','','[]','智學文交與命窮，瘴江風雨值衰翁。',32,'全唐诗/poet.song.225000.json','["智學文交與命窮，瘴江風雨值衰翁。", "昌黎送別勞三揖，何似檀欒一笑中。"]'),
('9ef46ac0-a1fa-493b-b67c-7c2976015204','四不吟','劉黻','宋','宋诗','song-poetry','','[]','大寒風雨暑不出，公會坐廣醵不赴。',32,'全唐诗/poet.song.225000.json','["大寒風雨暑不出，公會坐廣醵不赴。", "我奉遺體投遐荒，相爾室中胡不懼。"]'),
('03ac7b8d-dc60-4697-896b-a1fb16e6a684','六無吟','劉黻','宋','宋诗','song-poetry','','[]','食無肉兮出無友，居無室兮病無醫。',32,'全唐诗/poet.song.225000.json','["食無肉兮出無友，居無室兮病無醫。", "冬無炭兮夏無泉，祠有坡翁慰我思。"]'),
('6797caef-dd33-4d6b-99e2-07c1c3d35e7b','田家吟','劉黻','宋','宋诗','song-poetry','','[]','舊穀未沒新穀登，家家擊壤含歡聲。',96,'全唐诗/poet.song.226000.json','["舊穀未沒新穀登，家家擊壤含歡聲。", "慚愧今年雨水足，隻雞斗酒相逢迎。", "豪家征斂縱獰隸，單巾大帕如蠻兵。", "索錢沽酒不滿欲，大者羅織小者驚。", "穀有揚簸實亦簸，鉅斛凸概謀其贏。", "詎思一粒復一粒，盡是農人汗血成。"]'),
('c614d318-f077-401f-95d9-4b1ce231cfee','四十吟三首  其一','劉黻','宋','宋诗','song-poetry','','[]','四十年來父子情，吁嗟今日任飄零。',64,'全唐诗/poet.song.226000.json','["四十年來父子情，吁嗟今日任飄零。", "雖慚負米供三釜，莫悔傾籯教一經。", "飲水西江甘冷味，炷香南極祝高齡。", "白雲縱隔三千里，詩禮朝朝似過庭。"]'),
('a4395a99-b444-4bb2-b3e6-c27f25723248','四十吟三首  其二','劉黻','宋','宋诗','song-poetry','','[]','四十年來兄弟情，渠渠天理境中行。',64,'全唐诗/poet.song.226000.json','["四十年來兄弟情，渠渠天理境中行。", "形如鶴瘦困書癖，志不蠅營守筆耕。", "庭燎獻箴知聖主，臺評飛劾到諸生。", "阿奴抑鬰休嫌拙，門戶如冰耐拄撐。"]'),
('96aeda52-1dde-4bd6-b098-b72fcdfff15d','四十吟三首  其三','劉黻','宋','宋诗','song-poetry','','[]','四十年來朋友情，朱絃疏越最希聲。',64,'全唐诗/poet.song.226000.json','["四十年來朋友情，朱絃疏越最希聲。", "閒思白日同天樂，每向清宵坐月明。", "世事只隨漚起滅，故交不趁木枯榮。", "早知黨禍今如織，祇合漁樵老此生。"]'),
('79384870-d533-499e-8125-bb4cd67986f2','寄菊廬舅氏','劉黻','宋','宋诗','song-poetry','','[]','文章時不偶，鬢影想蒼蒼。',48,'全唐诗/poet.song.226000.json','["文章時不偶，鬢影想蒼蒼。", "抱劍客千里，憶家書數行。", "草萊荒菊圃，風雨冷詩堂。", "若問求安策，東歸策最長。"]'),
('aa10653a-aa28-4b2e-95cc-fe8555f64bbb','過白沙','劉黻','宋','宋诗','song-poetry','','[]','出郭纔數里，片景盡漁家。',48,'全唐诗/poet.song.226000.json','["出郭纔數里，片景盡漁家。", "夜靜惟聞犬，潮平不見沙。", "寒風欺槿葉，淡月讓蘆花。", "世路幾銷歇，一翁常施茶。"]'),
('d2027746-b18e-4208-8aa0-9a51a283fc8c','題花巖','劉黻','宋','宋诗','song-poetry','','[]','厭聽朝雞唱，歸來覓柳栽。',48,'全唐诗/poet.song.226000.json','["厭聽朝雞唱，歸來覓柳栽。", "半山張錦繡，一水隔塵埃。", "尋壑疑無路，看潮別有臺。", "仙人不可見，孤鶴夜深迴。"]'),
('4bdb67e9-6474-4de0-b5f2-d3e71898329f','淮上','劉黻','宋','宋诗','song-poetry','','[]','翠華南渡後，此地獨防秋。',48,'全唐诗/poet.song.226000.json','["翠華南渡後，此地獨防秋。", "明月家家淚，西風處處愁。", "鼓鼙寒出塞，烽火夜分樓。", "征戰何時息，長河萬古流。"]'),
('e909cbe8-b5cd-422e-9af0-e11c627145d9','訪石門洞','劉黻','宋','宋诗','song-poetry','','[]','洞中誰是主，一樹野桃開。',48,'全唐诗/poet.song.226000.json','["洞中誰是主，一樹野桃開。", "仙駕青牛去，瀑疑碧漢來。", "門閒雲闔闢，山好客徘徊。", "已擬歸休日，臨溪築釣臺。"]'),
('8e2336ec-5f1b-43dd-8ede-4ed683e573be','登舟西郭別城友','劉黻','宋','宋诗','song-poetry','','[]','久靜還思動，離觴江上斟。',48,'全唐诗/poet.song.226000.json','["久靜還思動，離觴江上斟。", "文章關世道，科目壞人心。", "門掩溪雲早，舟橫野水深。", "清猿不解事，應向故山尋。"]'),
('e7e26fbf-7707-443b-a271-ed2da3311245','賦漁村晚照','劉黻','宋','宋诗','song-poetry','','[]','自許同漁者，築廬雲水鄉。',48,'全唐诗/poet.song.226000.json','["自許同漁者，築廬雲水鄉。", "利名俱是幻，鷗鷺亦相忘。", "古塔明秋樹，歸舟動夕陽。", "臨流不盡意，何必問瀟湘。"]'),
('d2838a6d-02bd-4185-8268-188ce844cb77','冷泉亭','劉黻','宋','宋诗','song-poetry','','[]','兩峰相對立，佛屋住中央。',48,'全唐诗/poet.song.226000.json','["兩峰相對立，佛屋住中央。", "有水地偏潔，無風心自凉。", "林虛猿應谷，人定月歸廊。", "造物餘清供，山梔一樹香。"]'),
('f007d781-f583-4cd7-9878-f3d39409cbdd','寄馮賀州','劉黻','宋','宋诗','song-poetry','','[]','鳴鳳起朝陽，斯文氣脈昌。',48,'全唐诗/poet.song.226000.json','["鳴鳳起朝陽，斯文氣脈昌。", "諫書留北闕，詩筆化南荒。", "湖柳生新意，岡梅續舊芳。", "相期功行遠，何但說龔黄。"]'),
('9113591d-88f1-4c3c-8525-b8e5654f5c46','靈巖','劉黻','宋','宋诗','song-poetry','','[]','千巖圍一寺，入境便無塵。',48,'全唐诗/poet.song.226000.json','["千巖圍一寺，入境便無塵。", "古木猶知己，高崖若正人。", "山靈袪虎跡，石髓幻龍身。", "上有通天竅，民愁獨未伸。"]'),
('41b9c46c-b741-4169-8380-5cffce7abc93','大龍湫','劉黻','宋','宋诗','song-poetry','','[]','總是佳山水，龍居又不同。',48,'全唐诗/poet.song.226000.json','["總是佳山水，龍居又不同。", "神明專一壑，氣勢壓群雄。", "派想從天落，湫疑與海通。", "高秋看不厭，宴坐雨聲中。"]'),
('efbe060c-5d6b-4811-9201-b1c38360cb5b','斗山接待','劉黻','宋','宋诗','song-poetry','','[]','雲水無南北，幾人相往還。',48,'全唐诗/poet.song.226000.json','["雲水無南北，幾人相往還。", "井深應接海，石顯爲開山。", "佛塔寒流上，漁帆夕照間。", "何當脫塵鞅，分石伴僧閒。"]'),
('971437d0-18b2-42f1-9002-130f74fdf117','和朱運筦郊行','劉黻','宋','宋诗','song-poetry','','[]','扁舟隨處泊，山影動清波。',48,'全唐诗/poet.song.226000.json','["扁舟隨處泊，山影動清波。", "柳惜春風老，花嗔宿雨多。", "野棋驚鶴夢，僧磬答漁歌。", "靈運經行地，今年幾度過。"]'),
('8603742f-e9d6-4309-96c7-111aad692870','永春道中呈賈九','劉黻','宋','宋诗','song-poetry','','[]','永春春不斷，桑柘滿林丘。',48,'全唐诗/poet.song.226000.json','["永春春不斷，桑柘滿林丘。", "雲薄無多雨，山清即是秋。", "淺沙寒立鷺，小逕晚歸牛。", "不慣同爲客，逢人問宿頭。"]'),
('dd70f515-68e0-43ec-9f5c-d9028e6a4602','臘雪','劉黻','宋','宋诗','song-poetry','','[]','八窗唯一色，穉子詫天花。',48,'全唐诗/poet.song.226000.json','["八窗唯一色，穉子詫天花。", "不稔已多歲，無寒能幾家。", "山川增古老，宇宙頓奢華。", "凍坐無他事，呼松自煮茶。"]'),
('4b383f69-61c1-4596-b3f4-67fe6740a046','東皋','劉黻','宋','宋诗','song-poetry','','[]','天然巖壑怪，官況此中閒。',48,'全唐诗/poet.song.226000.json','["天然巖壑怪，官況此中閒。", "臺閣人烟上，闌干樹影間。", "引泉歸月沼，分菊上秋山。", "咫尺神仙洞，聽笙忘却還。"]'),
('5a5e93cf-dd0f-4e8b-93ff-5dc4d94c4b42','滄浪閣爲王憲使賦','劉黻','宋','宋诗','song-poetry','','[]','獨得蕭臺趣，心清不受塵。',48,'全唐诗/poet.song.226000.json','["獨得蕭臺趣，心清不受塵。", "我多臨水屋，誰是濯纓人。", "波渺涵天闊，沙渟印月真。", "忘機有鷗鷺，渾不厭相親。"]'),
('4915434f-ea51-407f-8ceb-d3934a86e8ea','游長渠石洞','劉黻','宋','宋诗','song-poetry','','[]','六月訪古壑，衣巾全似秋。',48,'全唐诗/poet.song.226000.json','["六月訪古壑，衣巾全似秋。", "多無百年壽，能得幾番遊。", "泛酒月流硤，聽笙雲滿樓。", "相忘有樵者，來往共夷猶。"]'),
('b772376f-53c0-4848-bc75-b45bba686176','遊靈巖天竺','劉黻','宋','宋诗','song-poetry','','[]','秋氣飽林壑，清曠悅所性。',48,'全唐诗/poet.song.226000.json','["秋氣飽林壑，清曠悅所性。", "山禽不避人，野猿亦從命。", "臨流悟世情，過剎知民病。", "論交慎勿忘，森森古松勁。"]'),
('f40ee89f-7b33-4dc0-bfdf-c96b8f6b1d9a','賦頑石坐寄中上人','劉黻','宋','宋诗','song-poetry','','[]','一日復一日，坐來空世塵。',48,'全唐诗/poet.song.226000.json','["一日復一日，坐來空世塵。", "清潭常見月，老木不知春。", "室靜佛爲證，山深石作鄰。", "莫詢門外路，風雨暗荆榛。"]'),
('c330d1eb-d9c4-4eb4-87c4-46e193dec81e','哭菊廬舅氏','劉黻','宋','宋诗','song-poetry','','[]','舅甥三十年，生別且潸然。',48,'全唐诗/poet.song.226000.json','["舅甥三十年，生別且潸然。", "書落雁來處，病深秋到邊。", "故人傷遠道，孤子伴歸船。", "定有焚黄日，西山松樹阡。"]'),
('3cc0b669-b582-42f4-acae-5258f99128af','賦鹿巖賈司理所築懷京臺','劉黻','宋','宋诗','song-poetry','','[]','銅駝無萬里，長憶再遊難。',48,'全唐诗/poet.song.226000.json','["銅駝無萬里，長憶再遊難。", "歲月英雄老，山河草木寒。", "夢隨歸雁遠，愁頼酒杯寬。", "寂寞先朝事，斜陽莫倚闌。"]'),
('89504d60-c4b2-48fb-a9b1-669ff336aad7','趙墳','劉黻','宋','宋诗','song-poetry','','[]','客愁同路入，行不盡青松。',48,'全唐诗/poet.song.226000.json','["客愁同路入，行不盡青松。", "水去成雙瀑，山來豎一峰。", "土墳存舊壘，木主上新封。", "勿謂尋龍貴，蒼姬積在農。"]'),
('50cfba5d-c713-4070-b332-9f6919acb7ef','剡縣呈何視履','劉黻','宋','宋诗','song-poetry','','[]','剡爲山水宅，中有隠淪居。',48,'全唐诗/poet.song.226000.json','["剡爲山水宅，中有隠淪居。", "未續戴逵贊，閒尋支遁書。", "雲深丹井遠，城老古州餘。", "何事頻來往，愧看人釣魚。"]'),
('98542f0d-ec0d-42db-ad4c-ff0f044128d9','寄解性存','劉黻','宋','宋诗','song-poetry','','[]','相望纔咫尺，會面若登天。',48,'全唐诗/poet.song.226000.json','["相望纔咫尺，會面若登天。", "破屋人多厭，空山月獨憐。", "未貧猶有易，屢旱却無田。", "時到青松下，西風伴鶴眠。"]'),
('3c94186f-1af4-4629-911a-12284422d3f4','思弟','劉黻','宋','宋诗','song-poetry','','[]','久客知秋早，近湖秋更多。',48,'全唐诗/poet.song.226000.json','["久客知秋早，近湖秋更多。", "以予眠不穩，知汝夜難過。", "歲儉山空粟，門閒路沒莎。", "歸期毋太晚，親老鬢俱皤。"]'),
('ba7bd920-bdfd-45f7-bac1-9170843af00d','寄繆景文','劉黻','宋','宋诗','song-poetry','','[]','髫年聞俊發，兩歲喜相過。',48,'全唐诗/poet.song.226000.json','["髫年聞俊發，兩歲喜相過。", "薄俗交游少，清談警處多。", "巷深留虎跡，樹老集禽窠。", "無計買鄰住，青銅誰共磨。"]'),
('099ec7e7-6d10-4107-8a0f-0c624c6b31a4','南山龍門','劉黻','宋','宋诗','song-poetry','','[]','山椒誰立石，人說有龍居。',48,'全唐诗/poet.song.226000.json','["山椒誰立石，人說有龍居。", "此地終招隠，何年定結廬。", "雲封秋嶂老，瀑倒夕林虛。", "不似膺門峻，爲謀恐未疏。"]'),
('ef783c5e-1bf8-4f6e-b50e-036b540853cb','旱','劉黻','宋','宋诗','song-poetry','','[]','一雨連三月，當秋乃亢晴。',48,'全唐诗/poet.song.226000.json','["一雨連三月，當秋乃亢晴。", "不知老天意，何忍悞民生。", "川竭無雲起，山涼有月明。", "憂時心欲折，空聽海鱓聲。"]'),
('af8a9e35-a08c-4c94-a923-1e549b01d555','牛頭庵次王九山憲使韻','劉黻','宋','宋诗','song-poetry','','[]','有此投閒處，群山繞地圖。',48,'全唐诗/poet.song.226000.json','["有此投閒處，群山繞地圖。", "聲名出朝士，笑語樂樵夫。", "招鶴松爲主，開泉月作模。", "猶嫌居欠僻，來往是征途。"]'),
('371055bf-b85b-4911-9dff-b6305df9a334','遊太玉峰','劉黻','宋','宋诗','song-poetry','','[]','一秋吟不盡，才拙媿黄花。',48,'全唐诗/poet.song.226000.json','["一秋吟不盡，才拙媿黄花。", "極目皆成市，論心有幾家。", "淡交期白髮，清話證丹砂。", "却憶分携處，寒林集暮鴉。"]'),
('e7b6a6e2-ee86-4cdf-a034-34fa338f6a0d','白石洞','劉黻','宋','宋诗','song-poetry','','[]','片石立雲端，群峰向下看。',48,'全唐诗/poet.song.226000.json','["片石立雲端，群峰向下看。", "夜壇星斗近，秋閣洞天寒。", "泉滴疑傳漏，人危怯倚闌。", "降魔孤劍在，却並御書安。"]'),
('9a2b95a5-192f-4626-84de-e9dec3bff3f8','溪上翁','劉黻','宋','宋诗','song-poetry','','[]','問年知近百，傴僂合龜形。',48,'全唐诗/poet.song.226000.json','["問年知近百，傴僂合龜形。", "不理兒孫事，惟占水旱星。", "慣醫閒施草，貰酒自携瓶。", "勸世行方便，何消念佛經。"]'),
('ac10d252-59aa-41bc-872f-372656274791','寄朱德卿','劉黻','宋','宋诗','song-poetry','','[]','世事何拘束，清吟祗羨君。',48,'全唐诗/poet.song.226000.json','["世事何拘束，清吟祗羨君。", "半窗聽夜雨，一雁叫秋雲。", "壁潤琴音澀，山寒酒力分。", "何時野堂上，重與看騷文。"]'),
('f0c4ec3e-6f92-4592-82c7-5450875659fb','出邑','劉黻','宋','宋诗','song-poetry','','[]','出邑欣逢友，不知三嶺遥。',48,'全唐诗/poet.song.226000.json','["出邑欣逢友，不知三嶺遥。", "雲深山失樹，月上海生潮。", "縣小官租急，年荒酒戶銷。", "且尋僧舍泊，第一免喧囂。"]'),
('debb882e-fc54-4a64-aa9e-05f5a20c095d','西際','劉黻','宋','宋诗','song-poetry','','[]','一徑寒松老，因來采茯苓。',48,'全唐诗/poet.song.226000.json','["一徑寒松老，因來采茯苓。", "水禽鳴杞澗，野鹿卧椶亭。", "瀑近雲根濕，仙遺石井靈。", "守廬青道者，不厭客頻經。"]'),
('28f76eba-672e-46af-b586-d5519beb7a09','臘月六日見雪','劉黻','宋','宋诗','song-poetry','','[]','一冬長是暖，見雪獨精神。',48,'全唐诗/poet.song.226000.json','["一冬長是暖，見雪獨精神。", "田野眠方穩，湖山認不真。", "衆禽憂失樹，孤客喜忘貧。", "只此嚴凝氣，中含造化仁。"]'),
('c1a791ea-8466-4075-ac72-632d805ee64f','暮春寄友','劉黻','宋','宋诗','song-poetry','','[]','春歸無路尋，烟水一村深。',48,'全唐诗/poet.song.226000.json','["春歸無路尋，烟水一村深。", "中酒易成癖，惜花空用心。", "嫩芻青引犢，新樹綠藏禽。", "每念離鄉友，經年不寄吟。"]'),
('e4fac873-5a13-4efa-ac6a-4aa0f828ebba','過柘溪得西字','劉黻','宋','宋诗','song-poetry','','[]','晴雨春無定，東風忽轉西。',48,'全唐诗/poet.song.226000.json','["晴雨春無定，東風忽轉西。", "地肥桑眼大，天暖麥鬚齊。", "食頓尋幽所，舟行畏惡溪。", "野禽如避客，飛上半山啼。"]'),
('fb0de1ee-fb3c-4d9e-bbc4-8a9c47ba1401','西湖','劉黻','宋','宋诗','song-poetry','','["\u897f\u6e56"]','滄波混碧空，楊柳路皆通。',48,'全唐诗/poet.song.226000.json','["滄波混碧空，楊柳路皆通。", "列岫疑奔馬，新橋學跨虹。", "東風香跡滿，西日樂聲叢。", "總是游觀者，幽人趣不同。"]'),
('28b38fca-6b74-476f-a6f9-2ec683d8a1d7','掃松','劉黻','宋','宋诗','song-poetry','','[]','西原百五日，寂寞故松阡。',48,'全唐诗/poet.song.226000.json','["西原百五日，寂寞故松阡。", "挑飯瘞黄土，酹觴焚紙錢。", "烟林窺老狖，雨島哭蠻鵑。", "舊植亭前桂，一年高一年。"]'),
('318521d4-6db5-4402-9e14-5428e2cdb6d9','朱菊山汪眉山會宿蕭寺','劉黻','宋','宋诗','song-poetry','','[]','共遊溪上寺，因得話詩緣。',48,'全唐诗/poet.song.226000.json','["共遊溪上寺，因得話詩緣。", "客鬢添新雪，梅花似去年。", "疏鐘含暮雨，古木带寒烟。", "後會知難定，分題廢夕眠。"]'),
('98967350-8e02-46b5-8c48-7e3cdb0c7c6a','題吟所','劉黻','宋','宋诗','song-poetry','','[]','爲吟新搆屋，喧寂一溪分。',48,'全唐诗/poet.song.226000.json','["爲吟新搆屋，喧寂一溪分。", "洗竹夜留月，開門朝放雲。", "佛藏孤塔見，虎嘯別山聞。", "予喜頻來此，幽情爾共云。"]'),
('25cb711e-2e4d-4de4-89df-557a155991a0','仁靜山房爲孫君賦','劉黻','宋','宋诗','song-poetry','','[]','一廬含萬象，古意在聽琴。',48,'全唐诗/poet.song.226000.json','["一廬含萬象，古意在聽琴。", "雖有種瓜事，却無鋤草金。", "山幽馴野鹿，樹老带巢禽。", "自得延生法，從渠事養心。"]'),
('b7869728-0b9c-4663-abf2-3fb522b3934b','見東閣','劉黻','宋','宋诗','song-poetry','','[]','大唐詩派遠，今復有唐人。',48,'全唐诗/poet.song.226000.json','["大唐詩派遠，今復有唐人。", "慎吐冰霜句，恐妨天地春。", "閉門惟嗜古，養鶴亦甘貧。", "未識孤高貌，梅花想逼真。"]'),
('f6af2e72-594b-4f73-b116-493e63b08014','悼許氏柔則','劉黻','宋','宋诗','song-poetry','','[]','青青北山柏，蒼蒼南山松。',48,'全唐诗/poet.song.226000.json','["青青北山柏，蒼蒼南山松。", "屬彼冰雪姿，無言意趣同。", "造物何冥冥，摧以頭夜風。", "傷心復傷心，忍聽風中鐘。"]'),
('def26d67-f951-4cd0-99ed-968a616575e6','輓陳太傅','劉黻','宋','宋诗','song-poetry','','[]','由來安澹泊，人歎歷官遲。',48,'全唐诗/poet.song.226000.json','["由來安澹泊，人歎歷官遲。", "兩邑猶思宰，諸生共哭師。", "文名如日在，心事只天知。", "未竟經綸業，傳家有桂枝。"]'),
('f2229833-b956-4767-882a-cb4ef33d11dc','賦林氏集雲庵','劉黻','宋','宋诗','song-poetry','','[]','雲入此山深，余常拄屨行。',48,'全唐诗/poet.song.226000.json','["雲入此山深，余常拄屨行。", "客樵分茗處，碑磧半苔侵。", "地僻終招隠，池清獨照心。", "順寧皆是道，謹勿厭書林。"]'),
('1d99ae7c-f96a-49a4-b614-586bbe606009','別修門','劉黻','宋','宋诗','song-poetry','','[]','曉發別修門，湖山霧氣昏。',48,'全唐诗/poet.song.226000.json','["曉發別修門，湖山霧氣昏。", "百年培正脈，今日罪忠言。", "死節關宗社，生還頼聖恩。", "問天天不語，願及見親存。"]'),
('eb9e8344-f7a6-4270-822f-ec45ab06b9ba','過富陽','劉黻','宋','宋诗','song-poetry','','[]','是非終有定，世路苦多屯。',48,'全唐诗/poet.song.226000.json','["是非終有定，世路苦多屯。", "山色難留客，江湖亦送人。", "牛羊寒日晚，桑柘一陽新。", "早悟深矰繳，山中合隠淪。"]'),
('a6364c93-6284-493b-aabd-ce0b3e337d88','呈贛守陳千峰先生','劉黻','宋','宋诗','song-poetry','','[]','此行灘最險，猶幸拜先生。',48,'全唐诗/poet.song.226000.json','["此行灘最險，猶幸拜先生。", "身與天俱遠，心惟月共明。", "家書何日到，世路幾時平。", "歲晚嗟寥落，春風獨滿城。"]'),
('05db3101-80e5-4e92-843a-80ef7bef306f','別聞益謙大有','劉黻','宋','宋诗','song-poetry','','[]','歲事十分九，吾爲梅嶺行。',48,'全唐诗/poet.song.226000.json','["歲事十分九，吾爲梅嶺行。", "人皆憂路滑，天獨惜霜晴。", "公論無今古，忠臣有死生。", "玉溪一杯酒，話別若無情。"]'),
('24a8bf14-d905-45ef-87ea-fb4a31f70742','二月十五日遊興教寺','劉黻','宋','宋诗','song-poetry','','[]','一僧癯似竹，結坐對觀音。',48,'全唐诗/poet.song.226000.json','["一僧癯似竹，結坐對觀音。", "但見夕陽過，不知春事深。", "茗芳留野客，樹老集巢禽。", "卓錫泉千古，泠然照此心。"]'),
('767c5b48-5e83-406e-9ce2-7fcff4943269','橫浦十詠 周程三先生書院','劉黻','宋','宋诗','song-poetry','','[]','千載斯文冷，先生以道鳴。',48,'全唐诗/poet.song.226000.json','["千載斯文冷，先生以道鳴。", "山川師友趣，日月弟兄情。", "門靜一松在，源深雙浦橫。", "兒童游里巷，猶喜說周程。"]'),
('9b2b0400-58a5-4751-9d4a-e3339cc006a6','橫浦十詠 二忠堂','劉黻','宋','宋诗','song-poetry','','[]','斯道今猶古，相望百載間。',48,'全唐诗/poet.song.226000.json','["斯道今猶古，相望百載間。", "孤忠如白日，遺像對青山。", "寂寞吾儒事，崎嶇世路艱。", "聖朝仁脈在，先後慘生還。"]'),
('826ee2c6-d7b5-44c6-b0da-d414b2c8ef73','橫浦十詠 橫浦','劉黻','宋','宋诗','song-poetry','','[]','地與崆峒接，中多隠者韜。',48,'全唐诗/poet.song.226000.json','["地與崆峒接，中多隠者韜。", "山腰僧寺小，水口古榕高。", "粗石草木瘦，細民衣食勞。", "予來無一事，吟荇補離騷。"]'),
('601f69fc-94b0-4eab-955d-8ca70ac71ece','橫浦十詠 湛泉','劉黻','宋','宋诗','song-poetry','','[]','境僻遠塵跡，湛然風雨林。',48,'全唐诗/poet.song.226000.json','["境僻遠塵跡，湛然風雨林。", "一泉通地脈，千古照人心。", "灌菊增花蘤，煎茶得味深。", "石渠纔此爾，誰向道山尋。"]'),
('b86dccf1-8004-4976-ac80-8a2f8975a1a8','橫浦十詠 賢女祠','劉黻','宋','宋诗','song-poetry','','[]','山崦人家聚，路旁賢女祠。',48,'全唐诗/poet.song.226000.json','["山崦人家聚，路旁賢女祠。", "不移初嫁志，寧殞及笄時。", "古木有生意，清潭即舊知。", "吾宗女猶爾，況復號男兒。"]'),
('0be66b2a-a78d-41ef-a926-588ca5373a68','橫浦十詠 梅嶺','劉黻','宋','宋诗','song-poetry','','[]','曲江曾鑿險，梅嶺到今誇。',48,'全唐诗/poet.song.226000.json','["曲江曾鑿險，梅嶺到今誇。", "何代移來樹，幾人羞此花。", "誅茅新佛屋，蓋竹半樵家。", "冷煖分南北，誰興世道嗟。"]'),
('b91d5c69-4cd8-4fb4-988e-2fccad201000','橫浦十詠 六祖','劉黻','宋','宋诗','song-poetry','','[]','碓頭功行滿，非意祖師名。',48,'全唐诗/poet.song.226000.json','["碓頭功行滿，非意祖師名。", "世事春風過，禪心夜月明。", "清泉靈石竇，老鉢鎮山城。", "冷看梅花笑，紛紛事送迎。"]'),
('f679b2b9-8431-4532-b8f6-38b306efeeb8','橫浦十詠 東坡祠','劉黻','宋','宋诗','song-poetry','','[]','何年海上還，坐鎮此山川。',48,'全唐诗/poet.song.226000.json','["何年海上還，坐鎮此山川。", "筆硯歸京闕，衣冠带瘴烟。", "一生忠膽在，萬古黨名傳。", "吾道多流落，西風問老天。"]'),
('7ae6159b-27e4-4164-8e59-9899db60ad88','橫浦十詠 寶界寺','劉黻','宋','宋诗','song-poetry','','[]','城中惟一寺，僧老雪盈頭。',48,'全唐诗/poet.song.226000.json','["城中惟一寺，僧老雪盈頭。", "曾識神仙到，仍多諫議游。", "鍾聞香火夕，碑隠桂杉秋。", "可惜高堂上，雙趺石不留。"]'),
('047885ef-8498-45ce-ba7e-149a699aac08','橫浦十詠 解太尉墓','劉黻','宋','宋诗','song-poetry','','[]','檜肉不可食，但增忠義悲。',48,'全唐诗/poet.song.226000.json','["檜肉不可食，但增忠義悲。", "焚香臨決日，扼腕議和時。", "偃月人何在，凌烟草亦知。", "曾聞無垢語，刊入墓頭碑。"]'),
('db1902c1-3072-4812-8461-9e4f76e0b19f','思西弟','劉黻','宋','宋诗','song-poetry','','[]','棲棲梅嶺下，禁足老僧如。',48,'全唐诗/poet.song.226000.json','["棲棲梅嶺下，禁足老僧如。", "白髮雙親淚，青燈一紙書。", "應門猶看汝，强飯莫思予。", "何事成乖隔，低頭媿荷鋤。"]'),
('383b627a-a8aa-4f81-ac2f-6bf9d1de86df','夜氣','劉黻','宋','宋诗','song-poetry','','[]','夜氣不盈握，浩然天地清。',48,'全唐诗/poet.song.226000.json','["夜氣不盈握，浩然天地清。", "風行石不動，雲走月常明。", "陋巷顔回樂，深山大舜耕。", "此心無旦晝，萬物自生生。"]'),
('4a20255c-ae85-4e59-a16f-7ffb9aa6ceea','次酬吳仙尉張都監游興教寺','劉黻','宋','宋诗','song-poetry','','[]','野寺坐寥閴，跫然聞足音。',48,'全唐诗/poet.song.226000.json','["野寺坐寥閴，跫然聞足音。", "四山經雨過，六月似秋深。", "燈靜窺饑鼠，鐘清悟宿禽。", "元城今已遠，共此白雲心。"]'),
('9bdc392f-7b1d-47e3-9547-ccebb06fb9cd','次酬胡編校','劉黻','宋','宋诗','song-poetry','','[]','癯然同旦過，一飯鼓魚音。',48,'全唐诗/poet.song.226000.json','["癯然同旦過，一飯鼓魚音。", "對俗情全懶，忘言道亦深。", "斜陽浮野馬，明月照棲禽。", "誰續梅花賦，相期鐵石心。"]'),
('8d9298bd-8a06-44a7-bd17-aa273c46f92b','壽胡編校','劉黻','宋','宋诗','song-poetry','','[]','嶺根逢誕日，相對意如何。',48,'全唐诗/poet.song.226000.json','["嶺根逢誕日，相對意如何。", "直道遭時少，清貧得壽多。", "仙茅丹已熟，鄰秫味方和。", "休說南冠事，窮通付浩歌。"]'),
('b41a1731-251e-4b97-9342-ec5f86110db6','和康節三詩 安分','劉黻','宋','宋诗','song-poetry','','[]','所寓即爲鄉，蕭蕭竹護房。',48,'全唐诗/poet.song.226000.json','["所寓即爲鄉，蕭蕭竹護房。", "山中觀造化，世上任炎涼。", "鷃莫攀鵬大，鳬難比鶴長。", "榮枯從墮地，全不著商量。"]'),
('31830178-9e15-43b7-a594-dbaf53527e1f','和康節三詩 晨起','劉黻','宋','宋诗','song-poetry','','[]','一日事在寅，晨興宜自今。',48,'全唐诗/poet.song.226000.json','["一日事在寅，晨興宜自今。", "天澄萬古氣，人醒半生心。", "殘月留僧閣，寒烟度石林。", "營營何所得，白髮易相尋。"]'),
('ad8ce210-e726-4da6-a754-22e7997086f3','和康節三詩 聽琴','劉黻','宋','宋诗','song-poetry','','[]','何人不愛琴，難聽是真聲。',48,'全唐诗/poet.song.226000.json','["何人不愛琴，難聽是真聲。", "急雨蓬中過，流泉石底鳴。", "憂時身欲瘦，歷處夢猶驚。", "擬續昌黎操，泠泠寫此情。"]'),
('0c3953c1-d01b-4ee8-a461-bb8e3ff0b5d8','逢臘','劉黻','宋','宋诗','song-poetry','','[]','一歲忽逢臘，倚闌清氣浮。',48,'全唐诗/poet.song.226000.json','["一歲忽逢臘，倚闌清氣浮。", "雪飛浙山上，月照楚江頭。", "家遠易成夢，酒慳難散愁。", "讀書果何補，自笑不騎牛。"]'),
('27e8f40c-b0bf-475b-b17f-12cada826652','得弟書','劉黻','宋','宋诗','song-poetry','','[]','我自甘流落，翻令汝不眠。',48,'全唐诗/poet.song.226000.json','["我自甘流落，翻令汝不眠。", "世嗤伯氏拙，家頼阿奴賢。", "地惡烟爲瘴，書遲日作年。", "何時風雨夕，炙火勘新編。"]'),
('408d4b85-7aeb-4744-96dd-a11f53ab793a','立春','劉黻','宋','宋诗','song-poetry','','[]','臘月廿四夕，冷坐梅花州。',48,'全唐诗/poet.song.226000.json','["臘月廿四夕，冷坐梅花州。", "無夢到金馬，有詩迎土牛。", "半生常見肘，一歲又從頭。", "形影人相釋，先生達理否。"]'),
('f94380c3-4f9e-4159-bda1-228f298929f2','謝胡編校惠藥醫膝病遂以藥名賦','劉黻','宋','宋诗','song-poetry','','[]','益智莫如愚，誰甘遂作非。',48,'全唐诗/poet.song.226000.json','["益智莫如愚，誰甘遂作非。", "年增思續斷，親老憶當歸。", "起石安吟久，防風見客稀。", "前胡古君子，松節自相依。"]'),
('3770c790-0f31-490c-b204-ddfc7261d6dd','元夕','劉黻','宋','宋诗','song-poetry','','[]','一來生萬感，動是兩番春。',48,'全唐诗/poet.song.226000.json','["一來生萬感，動是兩番春。", "俗朴少燈火，年豐多醉人。", "遠鄉猶有舊，明月只如新。", "無奈梅花落，相看老樹身。"]'),
('8f71c82a-81ed-4259-b324-ed6a6211caac','寄郭仙尉','劉黻','宋','宋诗','song-poetry','','[]','三千里外人，梅下忽逢君。',48,'全唐诗/poet.song.226000.json','["三千里外人，梅下忽逢君。", "共對鴉山月，如依雁蕩雲。", "命奇明主棄，心白老天聞。", "貰酒非耽飲，煩渠禦瘴氛。"]'),
('33ce3726-bc85-4d6e-ac2f-8521013700c4','餞張都巡','劉黻','宋','宋诗','song-poetry','','[]','有梅橫石澗，庾嶺樹還同。',48,'全唐诗/poet.song.226000.json','["有梅橫石澗，庾嶺樹還同。", "名更因詩重，心常與月通。", "期君堅老節，媿我作頹翁。", "此去天風便，吹歸館閣中。"]'),
('7fc1f3ee-8966-4d73-ae51-57f72120b788','飄零','劉黻','宋','宋诗','song-poetry','','[]','飄零吾道在，安處即爲家。',48,'全唐诗/poet.song.226000.json','["飄零吾道在，安處即爲家。", "夜雨生蒲葉，秋風到蓼花。", "貌添平日瘦，學悟少年差。", "白足閒相問，蕉溪一供茶。"]'),
('b6aa3edc-406e-4ed7-990d-eb359a483d2b','偶作','劉黻','宋','宋诗','song-poetry','','[]','四十一年身，天南作逐臣。',48,'全唐诗/poet.song.226000.json','["四十一年身，天南作逐臣。", "病居僧却到，淡飯僕猶嗔。", "州淺稀高木，山荒闕伏神。", "退藏還有味，所憾遠雙親。"]'),
('18cd46e2-6cbf-4b33-aabf-463b0d3c8e1d','寺居','劉黻','宋','宋诗','song-poetry','','[]','寺居貧亦樂，多被憶家分。',48,'全唐诗/poet.song.226000.json','["寺居貧亦樂，多被憶家分。", "井脈寒生霧，鐘聲遠入雲。", "青松知出處，白髮耐耕耘。", "此地民風古，如何弄梃聞。"]'),
('934ff22d-42dd-446f-a650-68a98604ad2b','閒步','劉黻','宋','宋诗','song-poetry','','[]','出門俱寂寞，短褐步東皋。',48,'全唐诗/poet.song.226000.json','["出門俱寂寞，短褐步東皋。", "語簡反疑傲，詩枯亦近騷。", "水輪寒碓急，山寨晚烟高。", "邈矣飛來雁，令人賦折刀。"]'),
('13ac7a5a-edbd-4651-ac8f-6dab59ffa564','拜無垢先生祠','劉黻','宋','宋诗','song-poetry','','[]','中興遺此老，夢寐亦中原。',48,'全唐诗/poet.song.226000.json','["中興遺此老，夢寐亦中原。", "泣血兩朝事，披肝一萬言。", "名方登禁掖，身已謫南源。", "苦學無寒暑，雙趺片石存。"]'),
('e04ab00e-67d8-4ebd-9827-b96bcc2ca36a','飲啄','劉黻','宋','宋诗','song-poetry','','["\u897f\u6e56"]','飲啄天之分，吾何泣遠涂。',48,'全唐诗/poet.song.226000.json','["飲啄天之分，吾何泣遠涂。", "落身近南粵，結夢屢西湖。", "僱僕知鄉誼，依僧免屋租。", "新栽窗外竹，明月照同癯。"]'),
('a3eb2f9d-fcb9-4dea-8a6c-d7b76112457e','和題臨賦  其一','劉黻','宋','宋诗','song-poetry','','[]','近南逢劇暑，多病客難禁。',48,'全唐诗/poet.song.226000.json','["近南逢劇暑，多病客難禁。", "與物甘同靜，何人肯見尋。", "望雲生遠夢，看月得禪心。", "咫尺西關路，輸君杖履臨。"]'),
('94ce2d9d-90be-4d1d-8dbe-5536af08867b','和題臨賦  其二','劉黻','宋','宋诗','song-poetry','','[]','輸君杖履臨，草徑靜深深。',48,'全唐诗/poet.song.226000.json','["輸君杖履臨，草徑靜深深。", "野鳥隨晴步，鄰鐘答晚吟。", "飛沈皆有趣，窮達付無心。", "對月慳於酒，寒泉聊一斟。"]'),
('09a58cc3-2af2-465c-81f6-f0efc86de223','餞別郭帚齋游湘南','劉黻','宋','宋诗','song-poetry','','[]','扁舟今日去，昨夜月添愁。',48,'全唐诗/poet.song.226000.json','["扁舟今日去，昨夜月添愁。", "詩滿湘波上，名高庾嶺頭。", "友朋千載事，今古一般秋。", "石鼓多遺刻，君能寄雁不。"]'),
('09b810f6-1881-45d2-bc6a-058afac462f2','寄雲峰饒安國','劉黻','宋','宋诗','song-poetry','','[]','千年古松樹，樹下兩翁吟。',48,'全唐诗/poet.song.226000.json','["千年古松樹，樹下兩翁吟。", "語不到時事，笑皆非壯心。", "江添明月浄，山共白雲深。", "寂寞磚趺在，何時重許尋。"]'),
('823358aa-f04b-4939-a7bd-3439503ef424','和南澗叔見寄','劉黻','宋','宋诗','song-poetry','','[]','五年風雨別，家信憶浮沈。',48,'全唐诗/poet.song.226000.json','["五年風雨別，家信憶浮沈。", "獨隠金仙屋，誰明鐵漢心。", "粵鄰蠻瘴惡，蜀急客憂深。", "此地無黄犬，朝朝說寄音。"]'),
('517b97aa-24ff-4474-9835-19ab28c35f5f','和杜老人龍門寺詩題寶界東柱','劉黻','宋','宋诗','song-poetry','','[]','招提有宿緣，坐此豁心境。',48,'全唐诗/poet.song.226000.json','["招提有宿緣，坐此豁心境。", "風來松寄聲，月過竹移影。", "殿依鯉石古，井汲龜泉冷。", "究竟定慧門，如何日三省。"]'),
('4c535586-eaf9-4982-81f6-39955454557d','賦雲山閣呈貳車','劉黻','宋','宋诗','song-poetry','','[]','萬山列屏障，來往一溪雲。',48,'全唐诗/poet.song.226000.json','["萬山列屏障，來往一溪雲。", "倚檻古今異，望闕南北分。", "地清梅是主，天闊鷺成群。", "唐相經行處，勛名更屬君。"]'),
('9dfeed7f-9129-49b6-a1fa-e9204f840398','迂拙','劉黻','宋','宋诗','song-poetry','','[]','迂拙全無補，區區祇耐勞。',48,'全唐诗/poet.song.226000.json','["迂拙全無補，區區祇耐勞。", "青燈常獨照，白髮不相饒。", "戀闕江雲隔，憶家山月高。", "武夷有餘稿，何事注離騷。"]'),
('bbde1d88-dbf0-4a6e-b8d3-5be04bf918cd','園翁','劉黻','宋','宋诗','song-poetry','','[]','租得西山數畝園，自甘學圃竟窮年。',64,'全唐诗/poet.song.226000.json','["租得西山數畝園，自甘學圃竟窮年。", "芟鋤如秉太史筆，種接應分造化權。", "編竹爲防鄰犬踐，蟠花不礙樹禽眠。", "聖朝徵士惟科目，束帛無因到爾前。"]'),
('fa5e5d93-35d9-4f43-93fe-3307a91b4a9c','梅花','劉黻','宋','宋诗','song-poetry','','[]','之子孤高勢莫攀，分甘肥遯此林間。',64,'全唐诗/poet.song.226000.json','["之子孤高勢莫攀，分甘肥遯此林間。", "獨先草木有生意，幾歷風霜無老顔。", "氣質泠泠全太古，聲名籍籍重孤山。", "時人却擬調羹手，到底調羹不似閒。"]'),
('11b569c7-91cd-46b7-b120-41c9ec4d2951','葦航','劉黻','宋','宋诗','song-poetry','','[]','世路崎嶇即險灘，扁舟隨處著漁竿。',64,'全唐诗/poet.song.226000.json','["世路崎嶇即險灘，扁舟隨處著漁竿。", "主盟鷗鷺交全淡，管領江湖夢亦安。", "吟定月侵蓬戶靜，釣閒潮打石磯寒。", "即今航國真難事，莫作尋常一葦看。"]'),
('a12d9008-607e-4742-87a6-7b2ff9d8cac3','錢塘觀潮','劉黻','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','此是東南形勝地，子胥祠下步周遭。',64,'全唐诗/poet.song.226000.json','["此是東南形勝地，子胥祠下步周遭。", "不知幾點英雄淚，翻作千年憤怒濤。", "雷鼓遠驚江怪蟄，雪車橫駕海門高。", "吳兒視命輕猶葉，爭舞潮頭意氣豪。"]'),
('a5b7145f-1a58-4abf-8e58-10c932a7df80','偶得','劉黻','宋','宋诗','song-poetry','','[]','淡飯清茶處處安，學儒容易識真難。',64,'全唐诗/poet.song.226000.json','["淡飯清茶處處安，學儒容易識真難。", "風無形跡通群竅，日有光明阻覆盤。", "竹色滿庭留夜氣，柳陰夾徑怯秋寒。", "世間萬象俱呈露，輸與山人自在看。"]'),
('9e73237c-2544-438d-b90b-0dcac445a302','王宗臣趙處仁鄭季克同游分得村字','劉黻','宋','宋诗','song-poetry','','[]','出關非爲看桃李，愛識西山深處村。',64,'全唐诗/poet.song.226000.json','["出關非爲看桃李，愛識西山深處村。", "舟泊野橋分柳色，屐尋閒徑破苔痕。", "鳩占欲雨喚夫婦，雞傍殘陽聚子孫。", "得友不知商議久，歸來燈火已黄昏。"]'),
('df062834-5632-4647-afb0-b0c2d08bdfe6','黄山樓','劉黻','宋','宋诗','song-poetry','','[]','風生汐惡舟難去，獨上危樓立暮雲。',64,'全唐诗/poet.song.226000.json','["風生汐惡舟難去，獨上危樓立暮雲。", "數片斜陽隨處沒，一聲清磬隔江聞。", "廟靈古木懸新紙，碑老蒼苔補斷文。", "慚愧年豐官酒賤，往來人每樂醺醺。"]'),
('6a7ab3e9-d0ec-4da6-8058-0a0031712b3b','雨中和酬賈君寶','劉黻','宋','宋诗','song-poetry','','["\u897f\u6e56"]','廉纖花雨送殘春，不出書樓動數旬。',64,'全唐诗/poet.song.226000.json','["廉纖花雨送殘春，不出書樓動數旬。", "閒夢有魚占樂歲，瘦形如鶴耐清貧。", "漏欺白屋添苔暈，澤濁青林長樹身。", "惟憶西湖舊遊夕，光風霽月幾精神。"]'),
('f1579494-d921-48bd-afbd-c220319c98e6','寄魏僉判','劉黻','宋','宋诗','song-poetry','','["\u897f\u6e56"]','君住龜山我雁山，天教識面帝圻間。',64,'全唐诗/poet.song.226000.json','["君住龜山我雁山，天教識面帝圻間。", "書樓自喜看山色，詩卷相尋待月刪。", "鏡不可欺知貌改，寢惟無夢覺心閒。", "西湖大有真泉石，何日携琴更出關。"]'),
('f0016612-7cf7-484b-922e-cb37c39ef05b','寄徐徑畈吏部','劉黻','宋','宋诗','song-poetry','','[]','舍則安貧用則行，休嗟時事幾番更。',64,'全唐诗/poet.song.226000.json','["舍則安貧用則行，休嗟時事幾番更。", "鸞皇只向明時出，鬼魅偏爲暗處生。", "改秩屢勤天子詔，養親甘共野人耕。", "要知出處惟參易，莫學鴟夷變姓名。"]'),
('c0ce61b1-5d6d-4b32-8cbe-2383277fca3f','又寄  其一','劉黻','宋','宋诗','song-poetry','','[]','元陽詔墨動天霞，喜到東都處士家。',64,'全唐诗/poet.song.226000.json','["元陽詔墨動天霞，喜到東都處士家。", "世路幾年滋艾草，道山今日聚梅花。", "作舟濟國看商傅，槃石補天過女媧。", "珍重諸賢扶大道，聲名毋使後人嗟。"]'),
('75603dc8-0c32-4e2a-b338-c5da9dc94134','又寄  其二','劉黻','宋','宋诗','song-poetry','','[]','愧不柯山與執經，曾將尺紙話飄萍。',64,'全唐诗/poet.song.226000.json','["愧不柯山與執經，曾將尺紙話飄萍。", "六年憶別心如醉，一日相逢眼倍醒。", "結友苦無鷗共志，癖書瘦得鶴同形。", "自憐所性惟方拙，水潔山高即座銘。"]'),
('d5600452-534a-44b7-a242-0db20870f802','題江湖偉觀','劉黻','宋','宋诗','song-poetry','','[]','柳殘荷老客凄涼，獨對西風立上方。',64,'全唐诗/poet.song.226000.json','["柳殘荷老客凄涼，獨對西風立上方。", "萬井人烟環魏闕，千年王氣到錢塘。", "湖澄古塔明寒嶼，江遠歸舟動夕陽。", "北望中原在何所，半生贏得鬢毛霜。"]'),
('883bd599-8dac-4248-a05e-870038dac866','投趙玉堂使君','劉黻','宋','宋诗','song-poetry','','[]','鑾坡榮拜錦袍新，雁蕩行春作守臣。',64,'全唐诗/poet.song.226000.json','["鑾坡榮拜錦袍新，雁蕩行春作守臣。", "無擾可回民氣脈，有才能振國精神。", "柝沈海嶠三更月，草長池塘一雨春。", "聞道鈴齋少公事，肯分吟席與樵人。"]'),
('1208466c-00ef-4d94-9232-87473fc010b6','和何明府愛蓮詩','劉黻','宋','宋诗','song-poetry','','[]','濂溪題品非輕許，祗愛亭亭臭味同。',64,'全唐诗/poet.song.226000.json','["濂溪題品非輕許，祗愛亭亭臭味同。", "日晚色歸霞照裏，夜凉香在月明中。", "獨慚冬葉留寒翠，却笑春花學醉紅。", "天付清姿嘗浄植，曾聞結社有陶公。"]'),
('4b3e84b1-355d-48cf-97ae-e628be3f424a','次何愛山喜雨韻','劉黻','宋','宋诗','song-poetry','','[]','梵宮默禱託爐烟，火繖愁張六月天。',64,'全唐诗/poet.song.226000.json','["梵宮默禱託爐烟，火繖愁張六月天。", "雨倏隨車符蟻垤，水分沃野免龜田。", "已知簾影多琴暇，更與花封結飯緣。", "坐聽四方同潤澤，庶幾大有特書年。"]'),
('0048e194-58f3-481b-b7d4-0bb8190ab042','偕剡中諸友遊明心寺','劉黻','宋','宋诗','song-poetry','','[]','一春風雨掩柴扉，今日相羊竟晚暉。',64,'全唐诗/poet.song.226000.json','["一春風雨掩柴扉，今日相羊竟晚暉。", "山遠從誰尋古蹟，水高何處認漁磯。", "衣冠揖遜禽魚悅，觴詠流行草樹馡。", "共出戴公亭下路，邑人疑是舞雩歸。"]'),
('716b4bdd-8166-4d2a-b8ca-44516ecc77d1','輓趙少卿','劉黻','宋','宋诗','song-poetry','','[]','班陞金掌擢清才，苦欲歸田挽不回。',64,'全唐诗/poet.song.226000.json','["班陞金掌擢清才，苦欲歸田挽不回。", "浙右尚思菩薩去，荆南空望使星來。", "苔侵書閣秋山靜，竹鎖吟庭夜鶴哀。", "路出簫臺多巷祭，幾人和淚折寒梅。"]'),
('c416ae46-710b-47d2-93b1-cdf588720dc9','輓曹夫人','劉黻','宋','宋诗','song-poetry','','[]','一見豐碑已愴情，大家名重乞誰銘。',64,'全唐诗/poet.song.226000.json','["一見豐碑已愴情，大家名重乞誰銘。", "金花屢錫華封誥，白髮重看禁從榮。", "三世種成庭上桂，一生讀盡藏中經。", "當年曾佐先夫子，誓守潼川寇自平。"]'),
('4f369b16-14fc-442b-b240-098c154f80ab','輓楊砥軒錄參','劉黻','宋','宋诗','song-poetry','','[]','訃落鄉山各淚傾，世間難泯是賢名。',64,'全唐诗/poet.song.226000.json','["訃落鄉山各淚傾，世間難泯是賢名。", "一生官正爲州掾，到死人稱似砥平。", "夜燭已殘賓館寂，曉梅空點墨池清。", "祗應養得丹砂熟，却向金華洞裏行。"]'),
('74c1c814-f3ec-4676-899d-c65c8617ada9','輓萬竹西隠君','劉黻','宋','宋诗','song-poetry','','[]','哭到先生道已窮，夕陽千古起悲風。',32,'全唐诗/poet.song.226000.json','["哭到先生道已窮，夕陽千古起悲風。", "耆英會上減名哲，高士傳中添此翁。"]'),
('efc306cf-c445-4dee-b97c-e65784897ed6','呈徑畈徐左司','劉黻','宋','宋诗','song-poetry','','[]','五載相違一日過，巷無車跡有樵歌。',64,'全唐诗/poet.song.226000.json','["五載相違一日過，巷無車跡有樵歌。", "因嗟世上深危證，合住山中養太和。", "蔓草不知春事去，梅花曾識歲寒多。", "予今問道三千里，白髮雙親可奈何。"]'),
('bb385122-387c-415c-bde5-465000f369fe','貴溪道中','劉黻','宋','宋诗','song-poetry','','[]','自昔輸忠多賈禍，逢人何敢說抨彈。',64,'全唐诗/poet.song.226000.json','["自昔輸忠多賈禍，逢人何敢說抨彈。", "三杯村酒逐時醉，五里堠碑隨處看。", "行李無金童僕歎，深林有虎路塗難。", "流行坎止吾儒事，但把胸中易自寬。"]'),
('247f3ab5-bf3d-4b5e-ae76-70dc0dac249d','賦求仁齋和趙使君','劉黻','宋','宋诗','song-poetry','','[]','一編論語半言仁，克復工夫理趣真。',64,'全唐诗/poet.song.226000.json','["一編論語半言仁，克復工夫理趣真。", "斂在黄堂三寸地，散爲橫浦十分春。", "元陽有宰群霾伏，太極無邊萬象陳。", "生意源源如穀種，即爲天地本來身。"]'),
('b275ccfe-edcb-4a0c-aa61-fd4c354f2687','道源','劉黻','宋','宋诗','song-poetry','','[]','父師兄弟一堂深，貌像如生世所欽。',64,'全唐诗/poet.song.226000.json','["父師兄弟一堂深，貌像如生世所欽。", "直向端倪明萬古，不專佔畢詔來今。", "地靈香火溪山護，嶺近衣冠嵐霧侵。", "千派萬流同一水，來從濂洛洗人心。"]'),
('34454004-d57d-4cdc-aeca-86c68b7905e6','和酬劉監嶽','劉黻','宋','宋诗','song-poetry','','[]','四十餘程到庾關，到來無日不看山。',64,'全唐诗/poet.song.226000.json','["四十餘程到庾關，到來無日不看山。", "誓持冰雪松筠操，肯學春風桃李顔。", "一飯不忘三祝處，瓣香何慊二忠間。", "梵宮咫尺騷壇近，猶願奚囊續往還。"]'),
('9351d2a6-7344-4bca-9afb-06d6116c0dbb','橫浦有感','劉黻','宋','宋诗','song-poetry','','[]','風雨憂時夢不成，忍將佞舌博功名。',64,'全唐诗/poet.song.226000.json','["風雨憂時夢不成，忍將佞舌博功名。", "學如谷永生何辱，節若劉陶死亦榮。", "蒼蘚無心同客靜，寒梅有眼照人明。", "此邦風物多淳古，曾識濂溪與二程。"]'),
('4369f94d-d5ca-4c33-81da-8d5110141684','思親','劉黻','宋','宋诗','song-poetry','','[]','擬著青衫歸拜親，青衫未著已危身。',64,'全唐诗/poet.song.226000.json','["擬著青衫歸拜親，青衫未著已危身。", "鴉山地阻無書到，雁蕩峰高有夢頻。", "節物荒涼嗟遠客，家庭笑語愧鄉人。", "葵心但秉丹衷在，冬極從來又有春。"]'),
('732ebccd-9dd2-4df1-9bbf-554d4973a849','和趙友竹呈求仁使君','劉黻','宋','宋诗','song-poetry','','[]','賢哉太守即長城，領客郊行天放晴。',64,'全唐诗/poet.song.226000.json','["賢哉太守即長城，領客郊行天放晴。", "鷗鳥不驚知政靜，樵夫相對說官清。", "騷壇突兀誰劘壘，學海蒼寒敢濯纓。", "世事無如一杯酒，龍門謹勿太標名。"]'),
('fc99dc8b-c85e-4215-a7b8-473539bd419d','次酬胡編校賦竹屋  其一','劉黻','宋','宋诗','song-poetry','','[]','癖爲看書借壁光，肯隨鵬鷃論行藏。',64,'全唐诗/poet.song.226000.json','["癖爲看書借壁光，肯隨鵬鷃論行藏。", "聽僧魚鼓齋糧辦，留客茶杯禮數常。", "小屋槃姍貪巷靜，矮檐傴僂笑身長。", "黄花也識人寥落，不待重陽已吐香。"]'),
('9fa0bdd2-6b91-49f6-98c5-06c56482c52d','次酬胡編校賦竹屋  其二','劉黻','宋','宋诗','song-poetry','','[]','紫氣曾臨屋有光，老僧相對說修藏。',64,'全唐诗/poet.song.226000.json','["紫氣曾臨屋有光，老僧相對說修藏。", "貌癯漸覺衣冠古，交淡誰知道誼常。", "文類錦機君獨艷，才如襪線我無長。", "近來悟得安心法，菜飯蒲團一炷香。"]'),
('d6497022-a469-44bc-8a43-b09791327e16','次酬胡編校賦竹屋  其三','劉黻','宋','宋诗','song-poetry','','[]','一屋中含萬象光，掩關獨坐類龜藏。',64,'全唐诗/poet.song.226000.json','["一屋中含萬象光，掩關獨坐類龜藏。", "梧桐弄月思康節，楓柞吟秋憶履常。", "事到中年心更懶，人從多難識應長。", "幾回夢覺南窗下，聞得鄰家煮稻香。"]'),
('99b28bf2-faa6-4bc9-8400-39470913f010','賦望雲寮','劉黻','宋','宋诗','song-poetry','','[]','家山一望三千里，華髮雙親七十稀。',64,'全唐诗/poet.song.226000.json','["家山一望三千里，華髮雙親七十稀。", "自許朴忠寬社稷，誰知甘旨悞庭闈。", "菜根有味逢春雨，草色無邊傍日暉。", "總總白雲何處是，夜寒結夢但東歸。"]'),
('5f3dec0d-0b64-4313-a3a1-5c4d0365194e','謫居','劉黻','宋','宋诗','song-poetry','','[]','無垢雙趺十四年，予今恰已一年全。',64,'全唐诗/poet.song.226000.json','["無垢雙趺十四年，予今恰已一年全。", "開窗賸向春風坐，閉戶閒聽暮雨眠。", "白髮相尋非偶爾，青山可對只依然。", "蘧廬世事皆如此，且誦先生庭草篇。"]'),
('2d0711d5-3b5a-45f9-a102-c3797c613bc3','次酬楊德中','劉黻','宋','宋诗','song-poetry','','[]','丹心炯炯老天知，莫問人間識者稀。',64,'全唐诗/poet.song.226000.json','["丹心炯炯老天知，莫問人間識者稀。", "孤雁過門思古蕩，慈鴉滿樹憶重闈。", "醉因酒賤歌豐歲，寒覺衣單戀晚暉。", "珍重五窮同寂寞，忍教結柳向誰歸。"]'),
('664df3af-bc2e-48fd-9d47-25e1ee4def8b','輓妻母鄭夫人  其一','劉黻','宋','宋诗','song-poetry','','[]','詩禮傳家耦吉人，雍雍完得性中仁。',64,'全唐诗/poet.song.226000.json','["詩禮傳家耦吉人，雍雍完得性中仁。", "鄉評莫識生前面，堂影惟悲死後身。", "孀節虎號墳柏夜，婦儀魚憶澗頭春。", "九泉寂寂應無憾，雙璧分明作世珍。"]'),
('797afc43-de2d-4449-a92e-7b1d1629fa89','輓妻母鄭夫人  其二','劉黻','宋','宋诗','song-poetry','','[]','幸壻名門僅兩年，一編心事苦難牋。',64,'全唐诗/poet.song.226000.json','["幸壻名門僅兩年，一編心事苦難牋。", "袖因哭婦痕猶濕，觴未登堂訃已傳。", "自悟浮生如泡幻，渠知黨禍熾株連。", "墓頭片石垂千古，亦把蠻烟姓字鎸。"]'),
('250ee549-3c00-43f9-a4da-7f86304f9fce','此意','劉黻','宋','宋诗','song-poetry','','[]','此意蒼蒼曉不難，罰令狂士受饑寒。',64,'全唐诗/poet.song.226000.json','["此意蒼蒼曉不難，罰令狂士受饑寒。", "春風縱好惟貪坐，夜月雖明亦懶看。", "杜老却因貧得句，陶潛非爲拙辭官。", "世情一味嫌清淡，多刈幽蘭種牡丹。"]'),
('01a799cf-6c65-4a86-8b7b-b48e4ef6de55','壽趙使君計院求仁先生','劉黻','宋','宋诗','song-poetry','','[]','西江郡以梅花重，無愧梅花有此翁。',64,'全唐诗/poet.song.226000.json','["西江郡以梅花重，無愧梅花有此翁。", "學到靜邊皆實地，仁常熟處更春風。", "吏看判筆如神異，民擬生祠與佛同。", "願爲八荒開壽域，歡聲何但鯉城中。"]'),
('f8f06cd2-56df-4fc1-968d-b8b264e058d4','次胡潛父先輩','劉黻','宋','宋诗','song-poetry','','[]','聖世如何肯棄賢，唐書筆削頼君傳。',64,'全唐诗/poet.song.226000.json','["聖世如何肯棄賢，唐書筆削頼君傳。", "山雲相望三千里，嶺霧同游恰一年。", "才刃固難居衆後，智囊猶欠燭幾先。", "嗟吁寄跡寒梅下，白首青燈哭訴天。"]'),
('82b95145-2f6b-4522-a039-1f5c21c9b9af','用韻自述','劉黻','宋','宋诗','song-poetry','','[]','掩關誰復抱琴來，靜坐工夫欲換胎。',64,'全唐诗/poet.song.226000.json','["掩關誰復抱琴來，靜坐工夫欲換胎。", "事到平心方是道，行希前哲奈非才。", "鏡中華髮侵尋矣，松下衰翁矍鑠哉。", "畎畝未能忘一飯，經綸猶願濟雲雷。"]'),
('f42df6c6-1657-4eb0-8190-aef624e9380f','喜劉主簿歸','劉黻','宋','宋诗','song-poetry','','[]','同是青藜一祖來，晚成天欲老其才。',64,'全唐诗/poet.song.226000.json','["同是青藜一祖來，晚成天欲老其才。", "家傳虎榜新承渥，人說犧經舊屢魁。", "春色風流都羨柳，歲寒事業莫過梅。", "誰憐歷落如蕡者，閒把離騷嚥一杯。"]'),
('82df52d4-1d11-4644-bf99-f3ecfc292eef','病鷺','劉黻','宋','宋诗','song-poetry','','[]','得汝相依若友朋，無端鳴啄頓伶俜。',64,'全唐诗/poet.song.226000.json','["得汝相依若友朋，無端鳴啄頓伶俜。", "莫親野水應生夢，幾立斜陽不整翎。", "肩聳可齊工部瘦，神清猶逐楚臣醒。", "人言氣習多濡染，却笑吾今鬢亦星。"]'),
('f8bf1d49-fb72-45ba-a610-d40719f39e12','問鼠','劉黻','宋','宋诗','song-poetry','','[]','隻影投荒閲兩秋，汝曹何苦侮畸囚。',64,'全唐诗/poet.song.226000.json','["隻影投荒閲兩秋，汝曹何苦侮畸囚。", "詩書盡嚙從誰愬，冠履俱傷重我羞。", "相國溷人寧處垢，永州某氏未輕投。", "翻盆攪甕何時了，肯事張湯法吏不。"]'),
('3e46d42d-2f49-4c8f-99a4-d43d6e04c6f8','偶書','劉黻','宋','宋诗','song-poetry','','[]','暮雲漠漠數行鴉，心事凄涼正憶家。',64,'全唐诗/poet.song.226000.json','["暮雲漠漠數行鴉，心事凄涼正憶家。", "不向孤山留諫草，那能庾嶺見梅花。", "峒丁嗜鬭牙成血，楚俗趨蠻髮半髽。", "明日絕糧難早計，好𣂏流水嚼胡麻。"]'),
('0a28c6b1-7752-41d3-9804-aefd532d56f6','梅花','劉黻','宋','宋诗','song-poetry','','[]','人誇之子得春早，道眼看來春最遲。',64,'全唐诗/poet.song.226000.json','["人誇之子得春早，道眼看來春最遲。", "萬木已悲山欲瘦，一花纔與水相宜。", "乾坤寂寞常如客，今古平章無盡詩。", "說著色香猶近俗，丹心祗許伯夷知。"]'),
('28144910-5319-405e-82a6-3701d1c347e1','章江信筆','劉黻','宋','宋诗','song-poetry','','[]','自從謫向章江上，兩飯惟聽寶界鐘。',64,'全唐诗/poet.song.226000.json','["自從謫向章江上，兩飯惟聽寶界鐘。", "尚憶賈生陳痛哭，肯爲胡廣說中庸。", "春風舉世知騎鶴，夜雨何人識卧龍。", "吾道未嫌拘縶苦，一編炯炯照人胸。"]'),
('2c9e6d5e-b48d-47ca-a9bc-4bdce657b580','和陳大庾新建邑庠講堂','劉黻','宋','宋诗','song-poetry','','[]','從來道體播翔沈，黌序舂容領佩衿。',64,'全唐诗/poet.song.226000.json','["從來道體播翔沈，黌序舂容領佩衿。", "庭草靜中春不老，嶺梅孤處日相尋。", "艮蒙已探聖賢藴，剝復方知天地心。", "頼有諸公扶大道，如予未害入深林。"]'),
('7bae994f-42aa-4f21-9f7e-a380f80de0c9','和酬黄霞碭見寄','劉黻','宋','宋诗','song-poetry','','[]','此心難與俗人言，終日深居養浩然。',64,'全唐诗/poet.song.226000.json','["此心難與俗人言，終日深居養浩然。", "學到苦時方見道，數當厄處不由天。", "烟霞約客成三友，風雨憂時及四邊。", "珍重故人相勞苦，器之元與鐵同堅。"]'),
('cca4f41c-5f93-4148-8fb2-9686df026dd1','十月十三生日','劉黻','宋','宋诗','song-poetry','','[]','居常出戶便思親，況復流離值誕辰。',64,'全唐诗/poet.song.226000.json','["居常出戶便思親，況復流離值誕辰。", "命薄不嫌增甲子，騷清猶可記庚寅。", "菊香留晚招同醉，梅意纔先喜卜鄰。", "警省工夫須力進，客髭已有數莖新。"]'),
('198bcbf6-0b18-410d-a49b-99374bdf8be9','和郭帚齋詠龜泉','劉黻','宋','宋诗','song-poetry','','[]','鎔出形模造化工，石龜中有冽泉通。',64,'全唐诗/poet.song.226000.json','["鎔出形模造化工，石龜中有冽泉通。", "來從西峽蝦蟆碚，靜鎮南源瑪瑙宮。", "潤澤一城消衆渴，澄波千古照孤忠。", "貪廉名氏俱標榜，無涸無盈道不窮。"]'),
('8d57416c-9cf9-458c-8a90-90e48147bb9a','春雪和譚知縣韻酬北枝','劉黻','宋','宋诗','song-poetry','','[]','雪到南邊不論春，倚闌萬象縱橫陳。',64,'全唐诗/poet.song.226000.json','["雪到南邊不論春，倚闌萬象縱橫陳。", "糢糊世界山川老，軒豁人心宇宙新。", "鏡沼窺鸞應眩眼，藍關擁馬最傷神。", "功名悟到空花處，輸與當年高卧人。"]'),
('7070f6d2-5489-4f89-9f8b-668fce5bd8fb','諸葛武侯','劉黻','宋','宋诗','song-poetry','','[]','高卧曾吟梁父詩，痛無鍼石活當時。',64,'全唐诗/poet.song.226000.json','["高卧曾吟梁父詩，痛無鍼石活當時。", "天公未墜炎劉祀，心事能令先主知。", "八陣尚存驚對壘，一星纔落便無師。", "勛忠遺舄藏岷蜀，老柏蒼蒼萬古思。"]'),
('51833d92-622f-4e12-97b8-97f014cfb5bc','韓文公','劉黻','宋','宋诗','song-poetry','','[]','斯文久矣歎荆榛，一疏披忠徹紫宸。',64,'全唐诗/poet.song.226000.json','["斯文久矣歎荆榛，一疏披忠徹紫宸。", "不忍中原淪左袵，甘尋南土作纍臣。", "鄒軻以後功何遜，魯道于今脈尚新。", "宇宙欲昏星斗落，空山韓木亦悲春。"]'),
('e6ed73d0-261b-42a1-9a80-9d54d3194166','杜工部','劉黻','宋','宋诗','song-poetry','','[]','禾黍秋深泣亂離，盡將歲月付於詩。',64,'全唐诗/poet.song.226000.json','["禾黍秋深泣亂離，盡將歲月付於詩。", "天高有語雲霾隔，夜半無眠神鬼知。", "心抱孤忠生已晚，身逢多難死應遲。", "自從大雅收聲後，頼有篇章續楚辭。"]'),
('d282b3b2-e5d1-4334-9402-9b91f9c318fd','和帚齋見寄','劉黻','宋','宋诗','song-poetry','','[]','棲棲慣聽鼓魚聲，心印相傳第幾燈。',64,'全唐诗/poet.song.226000.json','["棲棲慣聽鼓魚聲，心印相傳第幾燈。", "江有白鷗閒似我，地惟蒼蘚懶於僧。", "吟難用世皆東野，窮亦憂時祗少陵。", "多謝故人相厚意，一箋當暑敵凝冰。"]'),
('1cc304ec-e6e5-4ff6-901c-605a2a60a0c0','詠桂呈張貳車','劉黻','宋','宋诗','song-poetry','','[]','昨夜秋風吹作花，異香早已滿天涯。',64,'全唐诗/poet.song.226000.json','["昨夜秋風吹作花，異香早已滿天涯。", "蓬萊深處兩三樹，風月分來第一家。", "綽約道妝如侍案，婆娑醉影欲乘槎。", "廣寒莫遣癡蟆食，留取芬芳與世誇。"]'),
('1baba36c-f725-4750-8b26-974f753b03ab','餞梅提刑','劉黻','宋','宋诗','song-poetry','','[]','梅花山下送先生，持節西江衣錦榮。',64,'全唐诗/poet.song.226000.json','["梅花山下送先生，持節西江衣錦榮。", "國步正巇須砥柱，邊塵方漲待澄清。", "來時野草知春暖，去路山禽語日晴。", "不怕風寒今滿地，摩挲浯石記勳名。"]'),
('3a4bb9cc-a090-40d8-8d56-388da1717b05','聽松','劉黻','宋','宋诗','song-poetry','','[]','寺門松未老，早有鶴來棲。',24,'全唐诗/poet.song.226000.json','["寺門松未老，早有鶴來棲。", "一夜枕衾冷，半天風雨啼。"]'),
('a084b244-515c-4e2e-811d-b383c19e4869','同俞季淵訪王脩齋遇雨次季淵韻','劉黻','宋','宋诗','song-poetry','','[]','投宿西山雨，抗論由群居。',24,'全唐诗/poet.song.226000.json','["投宿西山雨，抗論由群居。", "冥冥白霧深，誰卧隆中廬。"]'),
('f98dd5de-b787-4c32-a2f6-ed461029e254','次酬五羊李子先見寄','劉黻','宋','宋诗','song-poetry','','[]','山深萬木寂，一片古心枯。',24,'全唐诗/poet.song.226000.json','["山深萬木寂，一片古心枯。", "昨夜梅花月，相期道不孤。"]'),
('8d302fe6-5984-4f4d-b8fc-151bf529ef32','餞潘吳二察院去國五首  其一','劉黻','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','兩豸歸歟一相留，孤山草木亦含羞。',32,'全唐诗/poet.song.226000.json','["兩豸歸歟一相留，孤山草木亦含羞。", "忠言不必排閶闔，付與錢塘江自流。"]'),
('573da4c2-e3f2-4eaa-a859-f1fa24fb7d4a','餞潘吳二察院去國五首  其二','劉黻','宋','宋诗','song-poetry','','[]','塗碑共說臺官去，局面還憂宰相來。',32,'全唐诗/poet.song.226000.json','["塗碑共說臺官去，局面還憂宰相來。", "今古幾多興廢事，只緣忠佞是胚胎。"]'),
('9b1670b4-4784-4164-b45a-02a955147591','餞潘吳二察院去國五首  其三','劉黻','宋','宋诗','song-poetry','','[]','誰新白屋當靈鷲，倚漢橫霓幾棟梁。',32,'全唐诗/poet.song.226000.json','["誰新白屋當靈鷲，倚漢橫霓幾棟梁。", "因想中原陵寢處，斷垣衰草正斜陽。"]'),
('c7789f03-a65e-47ca-8fb7-979f71762e38','餞潘吳二察院去國五首  其四','劉黻','宋','宋诗','song-poetry','','[]','宰相從來號讀書，晚年似欲傚癡兒。',32,'全唐诗/poet.song.226000.json','["宰相從來號讀書，晚年似欲傚癡兒。", "癡兒多病傷於飽，爵祿如何對飽時。"]'),
('c9b7b699-a729-49e0-abea-d3e6c0e58e4c','餞潘吳二察院去國五首  其五','劉黻','宋','宋诗','song-poetry','','[]','生節雷聲午夜殘，囊封一疏奪冰寒。',32,'全唐诗/poet.song.226000.json','["生節雷聲午夜殘，囊封一疏奪冰寒。", "先生此去非沽譽，留與時人作樣看。"]'),
('634bb4b8-096c-408b-9467-f949d10e2204','和薛仲止漁村雜詩十首  其一','劉黻','宋','宋诗','song-poetry','','[]','料理楚辭甘冷闃，卜鄰惟喜近漁家。',32,'全唐诗/poet.song.226000.json','["料理楚辭甘冷闃，卜鄰惟喜近漁家。", "昨宵雨過平湖闊，閒看菰蒲添幾花。"]'),
('aa250c2a-3d6c-455f-9b01-d87fe69c62b5','和薛仲止漁村雜詩十首  其二','劉黻','宋','宋诗','song-poetry','','[]','半生心力在吟編，鍊得形如孟浩然。',32,'全唐诗/poet.song.226000.json','["半生心力在吟編，鍊得形如孟浩然。", "水屋數間城市隔，客來無路只呼船。"]'),
('3913172e-c192-45ad-8d74-3181c52d711a','和薛仲止漁村雜詩十首  其三','劉黻','宋','宋诗','song-poetry','','[]','老松瘦竹可相儔，穉髮駸駸到白頭。',32,'全唐诗/poet.song.226000.json','["老松瘦竹可相儔，穉髮駸駸到白頭。", "世道已如寒日晚，惟消把酒賦三休。"]'),
('c65cb051-07ea-4786-9800-36e09d6bbde3','和薛仲止漁村雜詩十首  其四','劉黻','宋','宋诗','song-poetry','','[]','非遠城中欲避塵，漁村鄰里笑言真。',32,'全唐诗/poet.song.226000.json','["非遠城中欲避塵，漁村鄰里笑言真。", "自從范子扁舟後，肯著蓑衣有幾人。"]'),
('860daf87-1a32-4545-a3d4-ac095a30fcb1','和薛仲止漁村雜詩十首  其五','劉黻','宋','宋诗','song-poetry','','[]','酒欲醒時鄰已靜，斗橫月落尚聞橈。',32,'全唐诗/poet.song.226000.json','["酒欲醒時鄰已靜，斗橫月落尚聞橈。", "炷香杯茗燈相照，不枉人生又一宵。"]'),
('47b8f4b4-c304-41f0-a2a5-f1d25eb29808','和薛仲止漁村雜詩十首  其六','劉黻','宋','宋诗','song-poetry','','[]','甘友漁樵懶做官，靜占時事轉艱難。',32,'全唐诗/poet.song.226000.json','["甘友漁樵懶做官，靜占時事轉艱難。", "近來地氣如南瘴，臘月梅花不識寒。"]'),
('9799db96-d22e-4ed9-a938-a8b2a96af1f8','和薛仲止漁村雜詩十首  其七','劉黻','宋','宋诗','song-poetry','','[]','苜蓿村中卜釣磯，臨流搆屋不嫌低。',32,'全唐诗/poet.song.226000.json','["苜蓿村中卜釣磯，臨流搆屋不嫌低。", "屋頭所種無多樹，大有新來白鷺棲。"]'),
('96d11a26-ee1f-453f-a381-c12461d905c5','和薛仲止漁村雜詩十首  其八','劉黻','宋','宋诗','song-poetry','','[]','情性常嗤俗者勞，世間何處免風濤。',32,'全唐诗/poet.song.226000.json','["情性常嗤俗者勞，世間何處免風濤。", "小舟泊向荷花蕩，一箇漁翁熟睡高。"]'),
('b97ad6c0-2659-4bc7-bc6d-ab8503c1cc3b','和薛仲止漁村雜詩十首  其九','劉黻','宋','宋诗','song-poetry','','[]','幸觀世事已忘機，觴詠流行度幾時。',32,'全唐诗/poet.song.226000.json','["幸觀世事已忘機，觴詠流行度幾時。", "萬物本來同一性，可知猿鳥不相疑。"]'),
('990fa1dc-7314-425b-94bc-b982846fc5bf','和薛仲止漁村雜詩十首  其一○','劉黻','宋','宋诗','song-poetry','','[]','白髮疏疏青道衣，苦吟應有鬼神知。',32,'全唐诗/poet.song.226000.json','["白髮疏疏青道衣，苦吟應有鬼神知。", "篇章但可陶情性，羞殺唐人自獻詩。"]'),
('8c123b07-8351-4c79-986f-ed61cfa0ffd2','寄西弟六首  其一','劉黻','宋','宋诗','song-poetry','','[]','寂寂書堂秋夜涼，一編心畫一爐香。',32,'全唐诗/poet.song.226000.json','["寂寂書堂秋夜涼，一編心畫一爐香。", "弟兄動是經年別，羞見天邊有雁行。"]'),
('5ab2285d-8cdd-4d6a-bfae-7710804c927b','寄西弟六首  其二','劉黻','宋','宋诗','song-poetry','','[]','儒生事業戒悠悠，鑿井求泉須到頭。',32,'全唐诗/poet.song.226000.json','["儒生事業戒悠悠，鑿井求泉須到頭。", "要識汝兄勤苦事，頂門白髮一莖秋。"]'),
('f0a12f94-2771-4bfd-a0c9-f5d32be0a8be','寄西弟六首  其三','劉黻','宋','宋诗','song-poetry','','[]','千里家山入夢頻，又封書尺寄行人。',32,'全唐诗/poet.song.226000.json','["千里家山入夢頻，又封書尺寄行人。", "未慚定省多疏闊，守道安貧即是親。"]'),
('28395acb-1a84-4552-85a5-e2b69fbb9d7d','寄西弟六首  其四','劉黻','宋','宋诗','song-poetry','','[]','汝兄望汝撐門戶，汝不耽書奈汝何。',32,'全唐诗/poet.song.226000.json','["汝兄望汝撐門戶，汝不耽書奈汝何。", "汝看二程兄弟傳，肯將幾月付蹉跎。"]'),
('a7010ab5-54a9-4729-b128-50aef3adde92','寄西弟六首  其五','劉黻','宋','宋诗','song-poetry','','[]','向上工夫肯憚難，須知簣土可爲山。',32,'全唐诗/poet.song.226000.json','["向上工夫肯憚難，須知簣土可爲山。", "若還志力無回轉，直透龍門亦等閒。"]'),
