('11c45855-edc1-43a6-bdd2-41ef53d02a7c','四先生像贊 南軒張宣公','劉黻','宋','宋诗','song-poetry','','[]','玉質金相，卓爾良貴。',40,'全唐诗/poet.song.226000.json','["玉質金相，卓爾良貴。", "有鑑在心，明利與義。", "大原斯闡，維世之模。", "表裏不貳，皇皇聖途。"]'),
('cdc79160-9f6e-486f-b261-1b7fc08be047','四先生像贊 東萊呂成公','劉黻','宋','宋诗','song-poetry','','[]','探微極深，經緯萬象。',40,'全唐诗/poet.song.226000.json','["探微極深，經緯萬象。", "不顯其傑，沈潛直養。", "體立同著，惟和且平。", "甘雨潤澤，古井淵渟。"]'),
('2bab16e6-bc9a-4b5d-9515-a09acc451d36','四先生像贊 象山陸文安公','劉黻','宋','宋诗','song-poetry','','[]','卓學邁倫，居超徑詣。',40,'全唐诗/poet.song.226000.json','["卓學邁倫，居超徑詣。", "觀我靈龜，以燭來世。", "展矣君子，克廣厥居。", "澄然自得，春風詠歸。"]'),
('7ea24ddd-40a0-404d-b93b-05ff991ba829','偈頌一百零二首  其一','釋紹曇','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西子湖邊泛渺茫，一堤寒綠看垂楊。',32,'全唐诗/poet.song.226000.json','["西子湖邊泛渺茫，一堤寒綠看垂楊。", "誰知業債難逃避，開眼堂堂入鑊湯。"]'),
('0be09b90-f095-4e6c-a431-6e92f09c1248','偈頌一百零二首  其二','釋紹曇','宋','宋诗','song-poetry','','[]','奴顔婢膝走人間，羞見羊裘七里灘。',32,'全唐诗/poet.song.226000.json','["奴顔婢膝走人間，羞見羊裘七里灘。", "文叔雖爲天子貴，子陵只作故人看。"]'),
('36d544df-c0a2-4dff-9ad3-cbd5ac3cb339','偈頌一百零二首  其三','釋紹曇','宋','宋诗','song-poetry','','[]','人家競賞元宵，佛隴百無一有。',60,'全唐诗/poet.song.226000.json','["人家競賞元宵，佛隴百無一有。", "管宴雖愧空疏，賓主不分新舊。", "隴頭月助放光明，谷口松編排節奏。", "春風舞袖樂昇平，不知身在然燈後。"]'),
('30df53da-2811-47e0-b92a-848bf1ea6aca','偈頌一百零二首  其四','釋紹曇','宋','宋诗','song-poetry','','[]','春日晴，燒痕青。',33,'全唐诗/poet.song.226000.json','["春日晴，燒痕青。", "錦雲片片，花霧溟溟。", "無位真人，面門出入，賊精賊精。"]'),
('62776a57-43be-416a-81da-43b240b92344','偈頌一百零二首  其五','釋紹曇','宋','宋诗','song-poetry','','[]','山舍春深，生涯日貧。',20,'全唐诗/poet.song.226000.json','["山舍春深，生涯日貧。", "桃花爛熳，不見靈雲。"]'),
('530e82c9-8687-4886-b8b2-16c8badb2ce9','偈頌一百零二首  其六','釋紹曇','宋','宋诗','song-poetry','','[]','赤脚走紅塵，全身入荒草。',64,'全唐诗/poet.song.226000.json','["赤脚走紅塵，全身入荒草。", "費了幾精神，不若居山好。", "一塢閑雲，千峰啼鳥。", "聲色純真，是非不到。", "堪悲堪笑寒山子，十年歸不得，忘却來時道。"]'),
('cc768444-ee60-41d2-885c-910faca819e6','偈頌一百零二首  其七','釋紹曇','宋','宋诗','song-poetry','','[]','松粉飄香，麥鬚弄黄。',58,'全唐诗/poet.song.226000.json','["松粉飄香，麥鬚弄黄。", "今朝春告別，無處覓行藏。", "燕子知不遷義，深談實相，對語雕梁。", "見汝諸人不會，啣泥營故壘，飛過莫家塘。"]'),
('3a30946b-dd03-4664-ba1e-da14e320a650','偈頌一百零二首  其八','釋紹曇','宋','宋诗','song-poetry','','[]','父不慈，子惡毒。',46,'全唐诗/poet.song.226000.json','["父不慈，子惡毒。", "熱血相噴，痛拳相𡎺。", "不共戴天讎，推入阿鼻獄。", "此冤此恨與誰論，海月山雲亦斷魂。"]'),
('32a74f2b-180e-47db-8d95-9fce3bf08cc0','偈頌一百零二首  其九','釋紹曇','宋','宋诗','song-poetry','','[]','平如鏡面，險似懸崖。',36,'全唐诗/poet.song.226000.json','["平如鏡面，險似懸崖。", "不容擬議，豈屬安排。", "閃電光中行活路，大悲院裏赴村齋。"]'),
('fb87df19-539f-4f5f-a23a-74548df15cab','偈頌一百零二首  其一○','釋紹曇','宋','宋诗','song-poetry','','[]','這一粒，甚處生。',50,'全唐诗/poet.song.226000.json','["這一粒，甚處生。", "陰陽未判，芽孽先萌。", "開花也一川雪霽，結實也萬頃雲橫。", "收拾歸來香滿鉢，飯餘散步自閑行。"]'),
('957075e8-8c12-49d9-9318-a032200171cb','偈頌一百零二首  其一一','釋紹曇','宋','宋诗','song-poetry','','[]','仙苑名花取次粧，鼕鼕羯皷謾催芳。',32,'全唐诗/poet.song.226000.json','["仙苑名花取次粧，鼕鼕羯皷謾催芳。", "春風不費纖毫力，拂掠枝頭便有香。"]'),
('897ba595-2814-4c0f-a96e-25cab7f0aa57','偈頌一百零二首  其一二','釋紹曇','宋','宋诗','song-poetry','','[]','地僻雲深，秋高境寂。',31,'全唐诗/poet.song.226000.json','["地僻雲深，秋高境寂。", "堂戶凄凉，無人面壁。", "雖然，浄地上誰肯狼藉。"]'),
('bbc4d6eb-3082-4962-8394-ccd3b3d12c31','偈頌一百零二首  其一三','釋紹曇','宋','宋诗','song-poetry','','[]','秋葉飄零，秋蟲夜鳴。',36,'全唐诗/poet.song.226000.json','["秋葉飄零，秋蟲夜鳴。", "色不是色，聲不是聲。", "達磨九年會不得，急携隻履問歸程。"]'),
('e90d65fd-cfca-4979-83dd-cbec394154a3','偈頌一百零二首  其一四','釋紹曇','宋','宋诗','song-poetry','','[]','撞烟樓，不知羞。',34,'全唐诗/poet.song.226000.json','["撞烟樓，不知羞。", "闢蟭螟眼，輥百花毬。", "四七二三阿轆轆，不思萬里有崖州。"]'),
('a7991a61-209b-4027-bc11-d77e085b5340','偈頌一百零二首  其一五','釋紹曇','宋','宋诗','song-poetry','','[]','佛壟山上雲，一片三四片。',54,'全唐诗/poet.song.226000.json','["佛壟山上雲，一片三四片。", "忽遇客推門，零亂舒還卷。", "有蹤由却沒蹤由，通身是眼尋難見。", "尋得見，木落千林，光浮碧巘。"]'),
('92d8f69a-1586-4e52-bd3e-34591013f30a','偈頌一百零二首  其一六','釋紹曇','宋','宋诗','song-poetry','','[]','頭上漫漫，脚下漫漫。',27,'全唐诗/poet.song.226000.json','["頭上漫漫，脚下漫漫。", "拈掇不得，地闊天寬，老僧住持事繁。"]'),
('b002e470-626f-4b86-a6a1-7242e05687c7','偈頌一百零二首  其一七','釋紹曇','宋','宋诗','song-poetry','','[]','橫該豎抹，古路封苔。',36,'全唐诗/poet.song.226000.json','["橫該豎抹，古路封苔。", "聖凡情盡，馬腹馿胎。", "不用閉門防俗客，愛閑能有幾人來。"]'),
('dad84d71-4e43-4750-b2cf-55324b15fe60','偈頌一百零二首  其一八','釋紹曇','宋','宋诗','song-poetry','','[]','山木陰陰，寒花淺深。',36,'全唐诗/poet.song.226000.json','["山木陰陰，寒花淺深。", "巢雲鶴怨，掛月猿吟。", "王維妙手畫不得，神光徒自覓安心。"]'),
('99384f21-c623-4913-9c9c-1a2b3c418196','偈頌一百零二首  其一九','釋紹曇','宋','宋诗','song-poetry','','[]','三十餘僧眼似眉，白雲深處聚頭嬉。',32,'全唐诗/poet.song.226000.json','["三十餘僧眼似眉，白雲深處聚頭嬉。", "燒枯柴火煨山芋，拽木羅籠總不知。"]'),
('84835667-b3c8-46ee-9022-de9e8b13fca8','偈頌一百零二首  其二○','釋紹曇','宋','宋诗','song-poetry','','[]','一塢耕樵，門扃綠蘿。',48,'全唐诗/poet.song.226000.json','["一塢耕樵，門扃綠蘿。", "富驕時少，貧樂時多。", "婦摇機軋軋，兒弄口喎喎。", "澗水松聲交節奏，何似東山瓦皷歌。"]'),
('b39dc31c-3ce4-4b03-b634-e6211af46ee0','偈頌一百零二首  其二一','釋紹曇','宋','宋诗','song-poetry','','[]','山鬟風急墜松釵，冷竈凝烟午未齋。',54,'全唐诗/poet.song.226000.json','["山鬟風急墜松釵，冷竈凝烟午未齋。", "黄獨煨香不能熟，老僧忍凍拾枯柴。", "見成活業，出格安排。", "懶瓚窮不徹，糞火一生埋。"]'),
('af308378-25e5-498e-b6f5-b653ee4e673d','偈頌一百零二首  其二二','釋紹曇','宋','宋诗','song-poetry','','[]','歲除生怕管筵空，品味無多只要豐。',32,'全唐诗/poet.song.226000.json','["歲除生怕管筵空，品味無多只要豐。", "掇轉虛空爲桉板，薄𠜱明月切清風。"]'),
('8fa06b6d-9d35-459e-8263-fd5490a00741','偈頌一百零二首  其二三','釋紹曇','宋','宋诗','song-poetry','','[]','春日打春牛，一擊百雜碎。',60,'全唐诗/poet.song.226000.json','["春日打春牛，一擊百雜碎。", "黄梅石女暗驚胎，生下無名物一塊。", "問四聖四聖不知，問六凡六凡不會。", "風前散作萬家春，賤似黄金貴似塵。"]'),
('d4a59e09-9595-43af-9207-736a2939c47d','偈頌一百零二首  其二四','釋紹曇','宋','宋诗','song-poetry','','[]','惟一堅密身，一切塵中現。',68,'全唐诗/poet.song.226000.json','["惟一堅密身，一切塵中現。", "老婆腰繫紫紗裙，嬌兒手把紅羅扇。", "南嶴東村，張坊李店。", "拜賀新年，春風滿面。", "歡悰不覺語聲高，驚落梅花一片兩片三四片。"]'),
('1f35bb6b-2d40-49c1-8c73-3d7bf427d3c7','偈頌一百零二首  其二五','釋紹曇','宋','宋诗','song-poetry','','[]','憎金以黄，謗沉無香。',46,'全唐诗/poet.song.226000.json','["憎金以黄，謗沉無香。", "達磨不會，歷魏遊梁。", "更有不識好惡底，齊腰立雪，寄食窮鄉，巴峽聞猿空斷腸。"]'),
('836465c4-5c69-49fb-93e9-1ea4789864b5','偈頌一百零二首  其二六','釋紹曇','宋','宋诗','song-poetry','','[]','秘魔擎叉，俱胝豎指。',44,'全唐诗/poet.song.226000.json','["秘魔擎叉，俱胝豎指。", "邪法難扶，如何得是。", "山僧冷地思量，不覺吞聲飲氣。", "攻乎異端，斯害也矣。"]'),
('a27fef2e-6de9-41cb-80c9-1cc9d355142a','偈頌一百零二首  其二七','釋紹曇','宋','宋诗','song-poetry','','[]','萬里澄江雪霽時，玉壺一色冷含輝。',32,'全唐诗/poet.song.226000.json','["萬里澄江雪霽時，玉壺一色冷含輝。", "漁翁認得烟村路，柳線穿魚带月歸。"]'),
('be0df892-7128-4551-a943-06bf30333506','偈頌一百零二首  其二八','釋紹曇','宋','宋诗','song-poetry','','[]','鈯斧埋藏歲月深，巖居日與白雲鄰。',32,'全唐诗/poet.song.226000.json','["鈯斧埋藏歲月深，巖居日與白雲鄰。", "業風無奈重飄皷，又作擔柴賣筊人。"]'),
('c94f9bd3-5eb1-4d6e-b881-288e0a9926b2','偈頌一百零二首  其二九','釋紹曇','宋','宋诗','song-poetry','','[]','堋八剌札，新翻曲調，逸格鄉談。',35,'全唐诗/poet.song.226000.json','["堋八剌札，新翻曲調，逸格鄉談。", "意隨流水遠，聲遏莫雲寒，月移花影上欄干。"]'),
('6830709c-dad3-4f37-a871-78df8b432ba4','偈頌一百零二首  其三○','釋紹曇','宋','宋诗','song-poetry','','[]','一不做，二不休。',54,'全唐诗/poet.song.226000.json','["一不做，二不休。", "得人一馬，還人一牛。", "豈不見臨濟三遭白棒，大愚肋下三拳痛𡎺，不共戴天讎。", "休休，說著令人滿面羞。"]'),
('b8112f75-9568-492f-aceb-dbb1883d2606','偈頌一百零二首  其三一','釋紹曇','宋','宋诗','song-poetry','','[]','不可以智知，金剛手把八稜槌。',58,'全唐诗/poet.song.226000.json','["不可以智知，金剛手把八稜槌。", "不可以識識，鎮州出箇大蘿蔔。", "不可以語言造，山禽聚集啼清曉。", "不可以寂默通，赤眼烏龜吞大蟲。"]'),
('b6dbeec6-1c16-40fc-b4dc-5a5edc0400d9','偈頌一百零二首  其三二','釋紹曇','宋','宋诗','song-poetry','','[]','覿面當機，東湧西沒。',40,'全唐诗/poet.song.226000.json','["覿面當機，東湧西沒。", "平地上險崖，惺惺中淈𣸩。", "不是心，不是佛，不是物，貶向無生國。"]'),
('e63ed2f5-73ac-4959-b2ba-8a7c4166de80','偈頌一百零二首  其三三','釋紹曇','宋','宋诗','song-poetry','','[]','出匣神鋒瑩鸊鵜，將軍珍襲已多時。',32,'全唐诗/poet.song.226000.json','["出匣神鋒瑩鸊鵜，將軍珍襲已多時。", "相承不是屠龍手，只作三文補履錐。"]'),
('d12efcb3-9076-425f-bb8a-867897f68995','偈頌一百零二首  其三四','釋紹曇','宋','宋诗','song-poetry','','[]','八月初，何處熱。',51,'全唐诗/poet.song.226000.json','["八月初，何處熱。", "出門荒草離披，四壁寒蛩凄切。", "衲僧家眼裏著得須彌山，耳裏著得四大海。", "聲色純真，只得一橛。"]'),
('922d446a-b4e6-4428-bf4f-a00dbd7946d3','偈頌一百零二首  其三五','釋紹曇','宋','宋诗','song-poetry','','[]','有一物，黑似漆，常在面門出入。',93,'全唐诗/poet.song.226000.json','["有一物，黑似漆，常在面門出入。", "騎聲蓋色，妙密中險崖。", "倒用逆施，險崖中妙密。", "三世諸佛遠之愈親，白牯狸奴得之轉失。", "法華不惜眉毛，爲汝當陽拈出。", "夭夭矯矯，粼粼皴皴，將謂南山鱉鼻，却是天台楖𣗖。"]'),
('5c542c26-f0c0-462b-b94f-50f216d77d24','偈頌一百零二首  其三六','釋紹曇','宋','宋诗','song-poetry','','[]','妙斲鼻頭墁，巧運風斤手。',99,'全唐诗/poet.song.226000.json','["妙斲鼻頭墁，巧運風斤手。", "千聖頭邊蓋覆來，密密綿綿無滲漏。", "不辭合土和灰，成就牛欄馬廐。", "只圖一箇不知恩，噇飯噇眠，易宵爲晝。", "翻笑脇尊者，脇不至席不唧𠺕。", "又笑稜道者，坐破七蒲團，馿前馬後，至今湖海揚家醜。"]'),
('07d687af-399d-4169-b992-2994d3940834','偈頌一百零二首  其三七','釋紹曇','宋','宋诗','song-poetry','','[]','棄金輪王位，尊貴不尊貴。',52,'全唐诗/poet.song.226000.json','["棄金輪王位，尊貴不尊貴。", "凍餓深雪中，冷地裏短氣。", "見明星，沒巴鼻。", "更言大地一切衆生成正覺，吽吽，棒折也未。"]'),
('0bd6ac88-a0c9-4ea3-a545-11acb1087bec','偈頌一百零二首  其三八','釋紹曇','宋','宋诗','song-poetry','','[]','高不高膚寸，低不低太華。',81,'全唐诗/poet.song.226000.json','["高不高膚寸，低不低太華。", "深不深蹄涔，淺不淺溟渤。", "法華高低深淺，瞞諸人一點不得。", "諸人高低深淺，亦瞞法華一點不得。", "盡情畫斷，更莫論量。", "綴鉢飯抄雲子白，晴甌茶泛雪花香。"]'),
('83eb2805-2ca5-4c67-9759-2b9effb80594','偈頌一百零二首  其三九','釋紹曇','宋','宋诗','song-poetry','','[]','玉几凌霄，橫趨密室。',48,'全唐诗/poet.song.226000.json','["玉几凌霄，橫趨密室。", "如風吹水自成紋，擲劍揮空無朕跡。", "子細思量，令人氣急。", "白木既無香，秤槌寧有汁。"]'),
('52060940-c272-49da-8497-7baf47fcb0b3','偈頌一百零二首  其四○','釋紹曇','宋','宋诗','song-poetry','','[]','三月春云暮，韶華似酒濃。',58,'全唐诗/poet.song.226000.json','["三月春云暮，韶華似酒濃。", "鶑啼楊柳雨，蝶弄海棠風。", "若作境會，過山尋蟻跡，不作境會，度水覓魚蹤。", "故國歸路遠，日暮泣途窮。"]'),
('4129529a-c3e3-42fb-a32c-a83e7d493d7b','偈頌一百零二首  其四一','釋紹曇','宋','宋诗','song-poetry','','[]','雪峰輥毬，睦州擔板。',40,'全唐诗/poet.song.226000.json','["雪峰輥毬，睦州擔板。", "展盡神通，搆得一半。", "那一半，戴嵩牛卧綠楊陰，韓幹馬嘶芳草岸。"]'),
('7cf13ca6-b326-4349-9d02-9a391f73e4a4','偈頌一百零二首  其四二','釋紹曇','宋','宋诗','song-poetry','','[]','水洗硬石頭，浪打枯楊樹，浄智莊嚴功德聚。',20,'全唐诗/poet.song.226000.json','["水洗硬石頭，浪打枯楊樹，浄智莊嚴功德聚。"]'),
('b75e0832-b1f8-4e1d-8317-bc32b5d93a74','偈頌一百零二首  其四三','釋紹曇','宋','宋诗','song-poetry','','[]','紅錦纏頭舞醉身，笙歌聲沸鳳樓春。',32,'全唐诗/poet.song.226000.json','["紅錦纏頭舞醉身，笙歌聲沸鳳樓春。", "百花叢裏扶歸去，誰道兒郎徹骨貧。"]'),
('961f5ff0-576f-4bc4-bdbc-16e9f76778ec','偈頌一百零二首  其四四','釋紹曇','宋','宋诗','song-poetry','','[]','千聖靈樞，妙在轉處。',28,'全唐诗/poet.song.226000.json','["千聖靈樞，妙在轉處。", "爍盡玄微，更進一步，莫來攔我毬門路。"]'),
('281e2fd8-469a-497d-9313-2525d0c54dae','偈頌一百零二首  其四五','釋紹曇','宋','宋诗','song-poetry','','[]','萬戟森嚴細柳營，信威獨許漢將軍。',32,'全唐诗/poet.song.226000.json','["萬戟森嚴細柳營，信威獨許漢將軍。", "誰知袖隠屠龍手，却把蒿枝箭策勳。"]'),
('e293922e-1cbe-4015-be7b-f7cd6e1afdf9','偈頌一百零二首  其四六','釋紹曇','宋','宋诗','song-poetry','','[]','百二十日夏，今朝始發頭。',48,'全唐诗/poet.song.226000.json','["百二十日夏，今朝始發頭。", "飯抄雲子白，羹煮菜香浮。", "未問寒山子，先看水牯牛。", "山前千頃地，信脚踏翻休。"]'),
('42039e67-8036-45b3-af53-1c8b56911cc8','偈頌一百零二首  其四七','釋紹曇','宋','宋诗','song-poetry','','[]','狗舐油鐺，鼠咬甑箅。',20,'全唐诗/poet.song.226000.json','["狗舐油鐺，鼠咬甑箅。", "用盡機思，喫沒滋味。"]'),
('787e4048-cfd2-43a7-beb2-79ce39e08804','偈頌一百零二首  其四八','釋紹曇','宋','宋诗','song-poetry','','[]','一雨潤枯焦，掃盡流金暑。',60,'全唐诗/poet.song.226000.json','["一雨潤枯焦，掃盡流金暑。", "薰風殿閣凉，諸佛出身處。", "堪笑勤川無義語，引得花木瓜，變成爛苦瓠。", "走徧衡梅賣與誰，一十三人聲怨皷。"]'),
('579f988e-30bd-40c2-90dc-d279df2dcb68','偈頌一百零二首  其四九','釋紹曇','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','洞庭七十二峰，飛雪一千餘丈。',48,'全唐诗/poet.song.226000.json','["洞庭七十二峰，飛雪一千餘丈。", "晨昏說法琅琅，誰謂盧公已往。", "元不往，在這裏。", "優曇火裏開，嗅著無香氣。"]'),
('0149554b-76b9-4af4-a82c-8ef44fd14fd0','偈頌一百零二首  其五○','釋紹曇','宋','宋诗','song-poetry','','[]','小小青山，叢叢翠竹。',92,'全唐诗/poet.song.226000.json','["小小青山，叢叢翠竹。", "野景無多，怡然縱目。", "明覺老人，向獨脫無依處。", "閑坐解疏慵，爲靜勝所縛。", "拄杖子，一夏同轍不同途。", "見山不是山，居竹不見竹。", "業識忙忙卒未休，忙中解唱陽春曲，欵乃一聲山水綠。"]'),
('753ae373-be80-4b95-8d39-3876aa25c667','偈頌一百零二首  其五一','釋紹曇','宋','宋诗','song-poetry','','[]','正因二字得聞，鼠糞污一釜羹。',50,'全唐诗/poet.song.226000.json','["正因二字得聞，鼠糞污一釜羹。", "乳峰初無箇事，飽噇飯了閑行。", "松門雨霽，苔徑雲橫。", "隄防平地上，著脚是深坑。"]'),
('bc436f6a-e462-4ffc-b447-1f50dd22b6ef','偈頌一百零二首  其五二','釋紹曇','宋','宋诗','song-poetry','','[]','一宿覺，三擔土。',42,'全唐诗/poet.song.226000.json','["一宿覺，三擔土。", "脚未跨門，丰骨已露。", "等閑舉一步，危徑結寒花，信彩示一機，斷崖飛瀑布。"]'),
('9c0bf279-137f-4cc9-b8b9-432cef139473','偈頌一百零二首  其五三','釋紹曇','宋','宋诗','song-poetry','','[]','社燕催歸，賓鴻欲返。',38,'全唐诗/poet.song.226000.json','["社燕催歸，賓鴻欲返。", "雪點白蘋洲，錦鋪紅蓼岸。", "蝦蟆入汝鼻孔裏，毒蛇穿汝眼睛中。"]'),
('99f27b22-b554-4888-8f2d-f2177ec5b8ad','偈頌一百零二首  其五四','釋紹曇','宋','宋诗','song-poetry','','[]','死柴頭，無烟火。',50,'全唐诗/poet.song.226000.json','["死柴頭，無烟火。", "信口一吹，面門爍破。", "可憐龍門遠知客禮首座。", "火爐頭熱血相噴，分爭你我，笑倒嵩山破竈墮。"]'),
('a01d4be4-ad33-4bb7-a11f-34da38ec0494','偈頌一百零二首  其五五','釋紹曇','宋','宋诗','song-poetry','','[]','上下三指，彼此七馬。',48,'全唐诗/poet.song.226000.json','["上下三指，彼此七馬。", "眼見如盲，口說如啞。", "拄杖子忍俊不禁，等閑捉敗。", "休休，盡法恐無民，且放天寒赦。"]'),
('7ad339a2-9104-469f-854a-95aaa9defc89','偈頌一百零二首  其五六','釋紹曇','宋','宋诗','song-poetry','','[]','不紹金輪尊貴位，被人打落當門齒。',68,'全唐诗/poet.song.226000.json','["不紹金輪尊貴位，被人打落當門齒。", "難嚲梁王掘地埋，脫身留得空棺履。", "死款供成，臨文不諱。", "乳竇今朝報不平，臭烟蓬㶿薰他鼻。", "任是老頑，也須噴嚏。"]'),
('5eab3c3c-4916-4c93-a33c-925c2452e2b8','偈頌一百零二首  其五七','釋紹曇','宋','宋诗','song-poetry','','[]','烟雨溟濛望眼迷，蘭舟小泊畫橋西。',32,'全唐诗/poet.song.226000.json','["烟雨溟濛望眼迷，蘭舟小泊畫橋西。", "兒童不識春流漲，却怪湖邊柳樹低。"]'),
('41f62005-28eb-4d82-9786-ce92e83fdd8d','偈頌一百零二首  其五八','釋紹曇','宋','宋诗','song-poetry','','[]','天寒人寒，滴水滴凍。',35,'全唐诗/poet.song.226000.json','["天寒人寒，滴水滴凍。", "赤脚走冰稜，力負千鈞重。", "堪笑霜趺擁葉人，漆桶漆桶。"]'),
('66d2f9be-ec07-4c17-9501-32da9d4ead1b','偈頌一百零二首  其五九','釋紹曇','宋','宋诗','song-poetry','','[]','野客吟殘，中巖月落。',56,'全唐诗/poet.song.226000.json','["野客吟殘，中巖月落。", "坐斷白雲，死不再活。", "只將宗鏡鑑惟心，法眼重重添翳膜。", "翳無藥，光爍爍。", "要識永明妙旨，更添香著。"]'),
('87376898-e1b9-4174-bfeb-90a9ee963ee7','偈頌一百零二首  其六○','釋紹曇','宋','宋诗','song-poetry','','[]','發得一機活，出得一言當。',40,'全唐诗/poet.song.226000.json','["發得一機活，出得一言當。", "萬里無片雲，青天合喫棒。", "不待春風著意吹，暗香已在梅花上。"]'),
('dfb5e3aa-490d-4d5a-a5be-1bf523e67449','偈頌一百零二首  其六一','釋紹曇','宋','宋诗','song-poetry','','[]','川僧素無頭腦，步步引人入草。',54,'全唐诗/poet.song.226000.json','["川僧素無頭腦，步步引人入草。", "忽驚野鴨群飛，便把鼻頭捏扭。", "哭不成哭，笑不成笑。", "只因家富小兒嬌，七世門風都壞了。"]'),
('c0e24833-1ba5-4527-a946-dbcb48d4370d','偈頌一百零二首  其六二','釋紹曇','宋','宋诗','song-poetry','','[]','未見岑大蟲，狐膽先驚破。',40,'全唐诗/poet.song.226000.json','["未見岑大蟲，狐膽先驚破。", "密室不通風，家私狼藉了。", "更說新開乳竇山，無端刻糞作旃檀。"]'),
('1a719f33-f089-41c6-abf2-cdeaccca7a00','偈頌一百零二首  其六三','釋紹曇','宋','宋诗','song-poetry','','[]','威音前，咸淳後。',68,'全唐诗/poet.song.226000.json','["威音前，咸淳後。", "一箇黑粼皴，機發牢關透。", "全身游戲生死園林，信脚踏翻聖凡窠臼。", "笑釋迦客夢未醒，恥彌勒藩籬未剖。", "客夢醒，藩籬剖，貶入無何有。"]'),
('391491a5-3055-4210-afd0-2d33917de3fc','偈頌一百零二首  其六四','釋紹曇','宋','宋诗','song-poetry','','[]','陌上語聲喧，賀歲人來去。',50,'全唐诗/poet.song.226000.json','["陌上語聲喧，賀歲人來去。", "鞦韆擘曉烟，綠蓋翻春霧。", "佛法無多，兩手分付。", "更問如何與若何，咸淳丙寅正月五。"]'),
('a24dc7e2-77c7-49cc-87ba-99704e80b2d5','偈頌一百零二首  其六五','釋紹曇','宋','宋诗','song-poetry','','[]','一喝三日聾，大寂門風喪。',56,'全唐诗/poet.song.226000.json','["一喝三日聾，大寂門風喪。", "深掘陷人坑，密布漫天網。", "笑一上，哭一上。", "做盡死模活樣，乳峰子細思量。", "沉本無香，何須起謗。"]'),
('1d635af8-2b59-4b36-8138-3cb448558c08','偈頌一百零二首  其六六','釋紹曇','宋','宋诗','song-poetry','','[]','花禁冷葉紅，草敵虛嵐翠。',24,'全唐诗/poet.song.226000.json','["花禁冷葉紅，草敵虛嵐翠。", "清浄盧舍那，全身荆棘裏。"]'),
('660a7c88-a5f2-41d3-8ae3-9ebb68aa9403','偈頌一百零二首  其六七','釋紹曇','宋','宋诗','song-poetry','','[]','喚作如如，早是變了也。',66,'全唐诗/poet.song.226000.json','["喚作如如，早是變了也。", "那堪世尊拈花，百鳥銜花，南泉一枝花，靈雲見桃花，石上栽花。", "總是虛花，且莫眼花。", "野老不知亡國恨，隔江猶唱後庭花。"]'),
('744f377e-b794-456b-8f77-d9cd6cf28dee','偈頌一百零二首  其六八','釋紹曇','宋','宋诗','song-poetry','','[]','玉几山前，凌霄峰下。',49,'全唐诗/poet.song.226000.json','["玉几山前，凌霄峰下。", "熱血嗔拳，做人話欛。", "犀牛扇颺向他方，捋虎鬚攔胸便打。", "一炷兜婁怨結成，貴買賤賣。"]'),
('652d2344-6f5d-4412-8a2c-b85f6530ae89','偈頌一百零二首  其六九','釋紹曇','宋','宋诗','song-poetry','','[]','桑疇雨過羅紈膩，麥隴風來餠餌香。',32,'全唐诗/poet.song.226000.json','["桑疇雨過羅紈膩，麥隴風來餠餌香。", "揭示西來端的意，好商量處錯商量。"]'),
('a6ecf7fa-94ee-4ece-a15e-b1f8698be808','偈頌一百零二首  其七○','釋紹曇','宋','宋诗','song-poetry','','[]','塞北安南幾戰爭，老來卜築傍烟村。',32,'全唐诗/poet.song.226000.json','["塞北安南幾戰爭，老來卜築傍烟村。", "却將舊斬樓蘭劍，換得黄牛教子孫。"]'),
('32cf49a8-3007-4561-984c-1e625c8e535f','偈頌一百零二首  其七一','釋紹曇','宋','宋诗','song-poetry','','[]','幕掛春烟，簟鋪秋水。',75,'全唐诗/poet.song.226000.json','["幕掛春烟，簟鋪秋水。", "高枕橫眠，鼻雷聒耳。", "爍石流金總不知，何須殿閣薰風至。", "又誰管九十日種粟燒畬，說什麽十三番悟明自己。", "灼然是箇無慚愧，閻羅王倒退三千里。"]'),
('c06cb57d-5f68-4edd-b2e8-00a000795b04','偈頌一百零二首  其七二','釋紹曇','宋','宋诗','song-poetry','','[]','旱地奔雷，青天撒雨。',94,'全唐诗/poet.song.226000.json','["旱地奔雷，青天撒雨。", "六戶不扃，龍無龍句。", "田地穩密底死汗迸流，妙用縱橫底寒毛卓豎。", "萬別千差透密機，撼動憨眠拄杖子。", "拄杖子喏，老老大大。", "百念灰寒，因甚被人唆使。", "只向道，四皓出商山，漢業歸明主。"]'),
('3845c2c5-e5a4-40d5-b121-9a21839dddfa','偈頌一百零二首  其七三','釋紹曇','宋','宋诗','song-poetry','','[]','一雨潤焦枯，大地承恩澤。',40,'全唐诗/poet.song.226000.json','["一雨潤焦枯，大地承恩澤。", "黄鋪𤱶畝雲，青鎖郊原色。", "刈禾鐮子疾如風，收放全歸掌握中。"]'),
('fea905b0-9b56-4868-9692-a1e6ebb08ca0','偈頌一百零二首  其七四','釋紹曇','宋','宋诗','song-poetry','','[]','一徑直，二周遮。',50,'全唐诗/poet.song.226000.json','["一徑直，二周遮。", "眉毛眼睫，地角天涯。", "雲門胡餠趙州茶，惠崇蘆鴈趙昌花。", "會則星河秋一雁，不會砧杵夜千家。"]'),
('a1796f11-9415-44c6-8510-3d7d6693927d','偈頌一百零二首  其七五','釋紹曇','宋','宋诗','song-poetry','','[]','虬龍一滴涎，鳳凰五色髓。',38,'全唐诗/poet.song.226000.json','["虬龍一滴涎，鳳凰五色髓。", "撲撲噴清香，穿却衲僧鼻。", "通身是，徧身是，吾無隠乎爾。"]'),
('09569692-3859-4d0b-ac9e-d672a80338af','偈頌一百零二首  其七六','釋紹曇','宋','宋诗','song-poetry','','[]','判虛空筆，摛錦繡文。',42,'全唐诗/poet.song.226000.json','["判虛空筆，摛錦繡文。", "光騰萬丈，入石三分。", "惡跡既被點破，只得飲氣吞聲。", "自有傍人道不平。"]'),
('7bf8c0e1-c47f-4a47-9871-94a59f3edc67','偈頌一百零二首  其七七','釋紹曇','宋','宋诗','song-poetry','','[]','讀破燈窗萬卷書，經綸勛業付洪儒。',32,'全唐诗/poet.song.226000.json','["讀破燈窗萬卷書，經綸勛業付洪儒。", "古今鼎鼐調羹手，幼學誰人不順朱。"]'),
('a11282b6-9e18-475c-acee-3dff58c4b0d4','偈頌一百零二首  其七八','釋紹曇','宋','宋诗','song-poetry','','[]','萬壑喬松，九枝靈草。',62,'全唐诗/poet.song.226000.json','["萬壑喬松，九枝靈草。", "瑞氣久鍾，清聲遠播。", "材大今爲宗廟梁，國香世産芝房寶。", "別露風規，尋僧論道。", "十二峰高勢莫齊，到頂方知天下小。"]'),
('6975e9df-82e4-45a1-b956-b32b6602c0ca','偈頌一百零二首  其七九','釋紹曇','宋','宋诗','song-poetry','','[]','活鱍鱍，硬糾糾，明眼人覷不透。',42,'全唐诗/poet.song.226000.json','["活鱍鱍，硬糾糾，明眼人覷不透。", "剛被春山杜宇知，點血啼清晝。", "臨風𨁝跳撼坤維，馿前馬後。"]'),
('d74238c3-a388-4e00-aa9f-3c8b26368c4d','偈頌一百零二首  其八○','釋紹曇','宋','宋诗','song-poetry','','[]','三月青春彈指過，九旬朱夏又從頭。',42,'全唐诗/poet.song.226000.json','["三月青春彈指過，九旬朱夏又從頭。", "茶抽雀舌郎忙摘，麥弄蝦鬚逐旋收。", "熾然說法，聲撼林丘。"]'),
('b390c809-e1bd-4564-8f03-27aa4299b2a5','偈頌一百零二首  其八一','釋紹曇','宋','宋诗','song-poetry','','[]','十二峰前塊石頭，雨洗風磨浄無染。',46,'全唐诗/poet.song.226000.json','["十二峰前塊石頭，雨洗風磨浄無染。", "苔衣剝落耿光寒，因甚諸人覷不見。", "覤得見，丈六金身，時時出現。"]'),
('011702ff-33af-4cdf-ac48-9aaadba65769','偈頌一百零二首  其八二','釋紹曇','宋','宋诗','song-poetry','','[]','以大圓覺，爲我伽藍。',127,'全唐诗/poet.song.226000.json','["以大圓覺，爲我伽藍。", "牛頭向北，馬頭向南。", "身心安居，平等性智。", "背負須彌，無息肩地。", "釋迦老子，不善用心，掘窖埋人，無一箇出頭得，只得短氣。", "瑞巖一衆，善惡不思，機智俱泯。", "青松白石，飽飯憨眠。", "成龍昇天，成蛇竄草，一絲毫羈絆他不得。", "鳳雛自有沖霄志，肯學鷦鷯戀一枝。"]'),
('994bb9a4-b972-4754-bfec-88eb9a454e30','偈頌一百零二首  其八三','釋紹曇','宋','宋诗','song-poetry','','[]','進人若將加諸膝，退人若將墜諸淵。',30,'全唐诗/poet.song.226000.json','["進人若將加諸膝，退人若將墜諸淵。", "雲門放去較憨，雪竇收來較險。"]'),
('d1b4c580-fe26-4a49-9386-b6d0fd3f4e82','偈頌一百零二首  其八四','釋紹曇','宋','宋诗','song-poetry','','[]','玉欄花藥鬭春工，雨濕胭脂臉暈紅。',32,'全唐诗/poet.song.226000.json','["玉欄花藥鬭春工，雨濕胭脂臉暈紅。", "絲管紛紛來賞翫，可憐吹落五更風。"]'),
('bbf1fe97-da87-4de2-9bd4-1690ea1b8310','偈頌一百零二首  其八五','釋紹曇','宋','宋诗','song-poetry','','[]','結夏已十日了也，寒山子作麽生。',80,'全唐诗/poet.song.226000.json','["結夏已十日了也，寒山子作麽生。", "村詩吟落韻，竹管貯殘羹。", "結夏已十日了也，水牯牛作麽生。", "愛從荒草去，不向坦途行。", "精神陡頓，頭角崢嶸。", "好把一坑埋瘞却，千峰雲靜月華明。"]'),
('9192ff6f-d02f-4d0a-847c-5fc147b1931b','偈頌一百零二首  其八六','釋紹曇','宋','宋诗','song-poetry','','[]','紫芝峰下，小小山居。',74,'全唐诗/poet.song.226000.json','["紫芝峰下，小小山居。", "家風淡薄，堂供蕭疏。", "茭粽葉包蒸米飯，野山茶點石菖蒲。", "天中令節，不用書符。", "百怪千妖自掃除，張道士、李師巫。", "望崖爭却步，遺下藥胡蘆。"]'),
('d88d1230-ee03-4608-83b1-dbaff9987bb0','偈頌一百零二首  其八七','釋紹曇','宋','宋诗','song-poetry','','[]','放下著，莫妄想。',42,'全唐诗/poet.song.226000.json','["放下著，莫妄想。", "無孔鐵槌，半斤八兩。", "面門拋擲，土曠人稀。", "堪笑趙州無業，一味鳳林吒之。"]'),
('6b0b1665-9e7a-4e8d-b2b7-0c207c0af21c','偈頌一百零二首  其八八','釋紹曇','宋','宋诗','song-poetry','','[]','鈎餌深拋五十年，鯨鰲吞海誤吞鈎。',32,'全唐诗/poet.song.226000.json','["鈎餌深拋五十年，鯨鰲吞海誤吞鈎。", "急翻身逐洪波去，暗織滄溟一片愁。"]'),
('f9b15c1f-e64b-4957-8502-6162b95af961','偈頌一百零二首  其八九','釋紹曇','宋','宋诗','song-poetry','','[]','一塊松根石，頑然自古來。',24,'全唐诗/poet.song.226000.json','["一塊松根石，頑然自古來。", "更無人覷著，歲歲長莓苔。"]'),
('7915a49a-aafa-467d-a76d-cd662d49a4e4','偈頌一百零二首  其九○','釋紹曇','宋','宋诗','song-poetry','','[]','雲居聞板聲，見神見鬼。',38,'全唐诗/poet.song.226000.json','["雲居聞板聲，見神見鬼。", "瑞巖聞板聲，普請瞌睡。", "夢中喚醒主人翁，鼻孔元來在眼底。"]'),
('de68772c-10ef-43b0-8a31-afebbef67a5c','偈頌一百零二首  其九一','釋紹曇','宋','宋诗','song-poetry','','[]','公燈不照私，渡水不濕脚。',50,'全唐诗/poet.song.226000.json','["公燈不照私，渡水不濕脚。", "連累老北堂，此錯非常錯。", "功回位轉，偏正中來。", "鳳宿龍巢金殿曉，香車應不碾宸苔。"]'),
('d17b3c45-842d-4417-b361-e79f9f4adc8c','偈頌一百零二首  其九二','釋紹曇','宋','宋诗','song-poetry','','[]','莊上喫油糍，鬼精魂罷休拈弄。',74,'全唐诗/poet.song.226000.json','["莊上喫油糍，鬼精魂罷休拈弄。", "雁影沉寒水，窮伎倆何用施呈。", "雖云博飯栽田，何似歸堂向火，靜悄悄，暖烘烘。", "不勞共話無賓主，衲被蒙頭萬境空，死水何曾有活龍。"]'),
('02bbacb4-f5a5-4237-988c-e2bb10fa778e','偈頌一百零二首  其九三','釋紹曇','宋','宋诗','song-poetry','','[]','棄萬乘金輪，栖六年雪嶺。',54,'全唐诗/poet.song.226000.json','["棄萬乘金輪，栖六年雪嶺。", "相從外道遊，不離那伽定。", "無奈凶星照命宮，積世箕裘都喪盡。", "雖云自業所招，且喜因邪打正。"]'),
('9efbed4f-f82b-43d8-b981-b9e03df239e0','偈頌一百零二首  其九四','釋紹曇','宋','宋诗','song-poetry','','[]','蔓草繫羅裙，山雲籠蓆帽。',53,'全唐诗/poet.song.226000.json','["蔓草繫羅裙，山雲籠蓆帽。", "皷舞賀元正，石女呵呵笑。", "喚作新年頭佛法，賺度人不少。", "不喚作新年頭佛法，賺度人不少。"]'),
('6fa4ba75-f1a0-4db1-9a09-671da1e8d0a9','偈頌一百零二首  其九五','釋紹曇','宋','宋诗','song-poetry','','[]','索寞芝峰，賞元宵節。',51,'全唐诗/poet.song.226000.json','["索寞芝峰，賞元宵節。", "佳賓到來，如何鋪設。", "能挑海底燈，細剪山頭月。", "東山瓦皷歌，堋八剌札，不是知音向誰說。"]'),
('dbe0fc3f-4d32-4264-95e5-7e7254465b86','偈頌一百零二首  其九六','釋紹曇','宋','宋诗','song-poetry','','[]','骨瘦如柴，機深似井。',36,'全唐诗/poet.song.226000.json','["骨瘦如柴，機深似井。", "劃地爲牢，酷行商令。", "兒孫無地雪深冤，燒炷兜婁苦告天。"]'),
('6966a5ee-bd44-428b-ad97-99c1b53a0568','偈頌一百零二首  其九七','釋紹曇','宋','宋诗','song-poetry','','[]','鉢飯糝桃花，釜羹烹野菜。',53,'全唐诗/poet.song.226000.json','["鉢飯糝桃花，釜羹烹野菜。", "喫了日烘烘，曝背茅簷下。", "佛法身心爛似泥，千聖眼覷無縫罅。", "吽吽，伎死禪和，喚起來打。"]'),
('1ca9c274-eb5f-4e49-b6d6-77dd8f210638','偈頌一百零二首  其九八','釋紹曇','宋','宋诗','song-poetry','','[]','風前不見花中葉，雨後難尋葉底花。',32,'全唐诗/poet.song.226000.json','["風前不見花中葉，雨後難尋葉底花。", "蜂蝶紛紛過牆去，只疑春色在鄰家。"]'),
('e4d989b4-6764-425a-aa3b-6aa46b37ce4e','偈頌一百零二首  其九九','釋紹曇','宋','宋诗','song-poetry','','[]','瑞巖徹骨窮，最苦冤憎會。',119,'全唐诗/poet.song.226000.json','["瑞巖徹骨窮，最苦冤憎會。", "厨無糝聚蠅，將何物分歲。", "擬烹露地牛，催納筋角反爲憂。", "擬取鳳凰髓，傷損太平祥瑞氣。", "擬吞栗棘蓬，塞斷咽喉氣不通。", "擬包鐵酸餡，欠紫絲頭難措辦。", "不如據見定，隨家豐儉。", "泉𣂏聖井，盤簇靈芝，鱠縷綠雲，餠翻剪月，飯後更煎茶一盞。"]'),
('b9657911-1415-432f-8629-d98613d0baa1','偈頌一百零二首  其一○○','釋紹曇','宋','宋诗','song-poetry','','[]','雪徑封寒蝶未知，暗香誰遣好風吹。',32,'全唐诗/poet.song.226000.json','["雪徑封寒蝶未知，暗香誰遣好風吹。", "野橋漏泄春光處，正是橫斜一兩枝。"]'),
('eb1bdfd6-4a1d-4be3-a7ef-60005f2ad2f1','偈頌一百零二首  其一○一','釋紹曇','宋','宋诗','song-poetry','','[]','是是，荆棘叢林，黄金田地。',46,'全唐诗/poet.song.226000.json','["是是，荆棘叢林，黄金田地。", "非非，伊蘭旃蔔，甘露蒺藜。", "是不是，非不非，鶴健將雛去，猿閑抱子歸。"]'),
('ece58003-7851-4566-9be4-8a85532afd62','偈頌一百零二首  其一○二','釋紹曇','宋','宋诗','song-poetry','','[]','向上機，頂門眼。',45,'全唐诗/poet.song.226000.json','["向上機，頂門眼。", "碗脫丘，漏燈盞。", "從上諸祖，已錯拈提，瑞巖今朝分明剖判。", "夜後打眠，齋時喫飯。"]'),
('4248ad1a-7fea-4899-8391-bbb4d04e5ceb','世尊乞食歸放拄杖以手拄頤坐眠贊','釋紹曇','宋','宋诗','song-poetry','','[]','雪嶺曾經苦，勤行七佛儀。',50,'全唐诗/poet.song.226000.json','["雪嶺曾經苦，勤行七佛儀。", "持鉢不得食，詐道不聞饑。", "六環錫重，無力扶持。", "颺下拄頤眠一覺，夢中消息許誰知。"]'),
('dd3e6e61-e39b-4509-b2db-b8315936f9ce','出山相贊','釋紹曇','宋','宋诗','song-poetry','','[]','六年雪凍不死，見明星便說悟。',30,'全唐诗/poet.song.226000.json','["六年雪凍不死，見明星便說悟。", "走出山來一窖無，被人喚作赤鬚胡。"]'),
('e55e3a99-7506-4f9b-a15d-0086f893f73f','寶公贊','釋紹曇','宋','宋诗','song-poetry','','[]','折杖頭，閑骨董。',24,'全唐诗/poet.song.226000.json','["折杖頭，閑骨董。", "惑梁王，少賣弄。", "鷹巢不至生鸞鳳。"]'),
('8ebfebd8-97b5-4c27-ac98-cf22a0f6fd96','布袋贊','釋紹曇','宋','宋诗','song-poetry','','[]','破布囊，無一窖。',34,'全唐诗/poet.song.226000.json','["破布囊，無一窖。", "靠著便憨眠，全不知天曉。", "若言彌勒分身，你且莫來謼我。"]'),
('b0410c01-b28a-468c-ae3b-b70f6420e0f8','寒山題詩贊','釋紹曇','宋','宋诗','song-poetry','','[]','國清竊得殘羹飯，也學人前弄竹篙。',32,'全唐诗/poet.song.226000.json','["國清竊得殘羹飯，也學人前弄竹篙。", "欲寫斷崖無活句，心如秋月待如何。"]'),
('ce7455e4-c2bc-4690-96c3-0ef51b113a87','拾得磨墨贊','釋紹曇','宋','宋诗','song-poetry','','[]','面皮頑惡髮鬚鬆，磨墨元來也不中。',32,'全唐诗/poet.song.226000.json','["面皮頑惡髮鬚鬆，磨墨元來也不中。", "冷看他人書淡字，不知污得布裙濃。"]'),
('ab6710f8-7d0d-4140-bdcc-3d9bf9479b2c','朝陽穿破衲贊','釋紹曇','宋','宋诗','song-poetry','','[]','斷線無蹊，折針缺鼻。',20,'全唐诗/poet.song.226000.json','["斷線無蹊，折針缺鼻。", "提得完全，金烏西墜。"]'),
('56a40e6e-aa51-483e-80ff-51a831c5bb64','對月了殘經贊','釋紹曇','宋','宋诗','song-poetry','','[]','五教三乘，之遶葛藤。',20,'全唐诗/poet.song.226000.json','["五教三乘，之遶葛藤。", "一言道盡，玉兔東昇。"]'),
('af120840-f087-4b60-8cc9-b7cd17bb3f27','豬頭和尚贊','釋紹曇','宋','宋诗','song-poetry','','[]','手把豬頭不自噇，面前背後鬼分贓。',32,'全唐诗/poet.song.226000.json','["手把豬頭不自噇，面前背後鬼分贓。", "重重敗闕無人識，贏得塗糊老定光。"]'),
('1f491768-9a76-4f64-ae66-3d48efc3ef44','嵩嶽珪禪師移樹圖贊','釋紹曇','宋','宋诗','song-poetry','','[]','野樹無根作麽移，蓋頭茅免八風吹。',32,'全唐诗/poet.song.226000.json','["野樹無根作麽移，蓋頭茅免八風吹。", "直饒深入那伽定，弄鬼精魂誰不知。"]'),
('7dfca46c-50ad-475e-b180-7a41572005e7','智者大師遷葬圖贊','釋紹曇','宋','宋诗','song-poetry','','[]','當年杜撰講天台，活被平人掘窖埋。',32,'全唐诗/poet.song.226000.json','["當年杜撰講天台，活被平人掘窖埋。", "若是黄金鑄靈骨，臭屍不到鬼扛擡。"]'),
('ba78bc8c-a889-4fc0-bbb5-4d9dc222d66f','船子贊','釋紹曇','宋','宋诗','song-poetry','','[]','千鈞重寄一絲輪，三寸離鈎抑逼人。',32,'全唐诗/poet.song.226000.json','["千鈞重寄一絲輪，三寸離鈎抑逼人。", "莫道踏翻船便了，夾山未必是金鱗。"]'),
('2df12270-cc75-4e43-9bf8-39019d6d058a','謝三郎贊','釋紹曇','宋','宋诗','song-poetry','','[]','雨笠烟蓑體露風，只傳漁業當心宗。',32,'全唐诗/poet.song.226000.json','["雨笠烟蓑體露風，只傳漁業當心宗。", "當時過得飛猿嶺，不到通身是爛膿。"]'),
('d52f7098-4a9d-436a-873b-5d3b87551f6c','癡絕和尚贊','釋紹曇','宋','宋诗','song-poetry','','[]','淳乎淳，沒機心。',82,'全唐诗/poet.song.226000.json','["淳乎淳，沒機心。", "撮莖草作翳睛藥，鍛黄丹成遶指金。", "發汾陽怒駡傷人語惡，中曹源蠱毒刻骨冤深。", "掃狐兔露蒼鷹牙爪，咬豬狗添老虎精神。", "是師真，非師真。", "僧繇描不得，閣筆幾沉吟。"]'),
('33586d14-3088-4b10-b52c-8a4b20315e75','佛鑑禪師贊','釋紹曇','宋','宋诗','song-poetry','','[]','奸豩頑蠻，更加白㑃。',77,'全唐诗/poet.song.226000.json','["奸豩頑蠻，更加白㑃。", "文武火煨石要香，麻皮頭纏人必倒。", "五處開場弄活機，是龍昇天蛇竄草。", "千不合，萬不合，鳳口山前，乞指路頭。", "被老破庵凌辱不少，至今忘却來時道。"]'),
('a6b5ac8d-5279-42c8-8563-2a15306af9e2','大川和尚贊','釋紹曇','宋','宋诗','song-poetry','','[]','面皮刮得霜，脊梁生鐵鑄。',85,'全唐诗/poet.song.226000.json','["面皮刮得霜，脊梁生鐵鑄。", "活弄惡機關，真本奉化子。", "據南山白額落却威，鎖冷泉清波無透路。", "最無端是不近人情，把斷貫索，倒懸佛祖，四海禪流惡見渠。", "任妙手僧繇，畫得全真，且無著處。"]'),
('346616d4-9911-430c-b008-70bc29f1c054','別山和尚贊','釋紹曇','宋','宋诗','song-poetry','','[]','嚴冷面皮，軟頑腸肚。',84,'全唐诗/poet.song.226000.json','["嚴冷面皮，軟頑腸肚。", "對同參唱菩薩蠻，與行家說無義語。", "縱蒼鷹搏物機，闢獅子翻身路。", "醫衲僧病下天王補心圓，移覩史宮換長庚大火聚。", "雖潜行密用處鶻眼迷蹤，點撿將來也是果州飯布。"]'),
('ab1a3877-5c9e-4d53-8f9f-5797fdf8fbee','送林荆州歸蓬萊','釋紹曇','宋','宋诗','song-poetry','','[]','蓬萊山翁抱仙骨，穩跨長鯨遊八極。',152,'全唐诗/poet.song.226000.json','["蓬萊山翁抱仙骨，穩跨長鯨遊八極。", "玉壺深貯海山雲，十載窮幽歸未得。", "年來骨蛻壺倒空，長鯨又化爲蒼龍。", "了無一物可依倚，卷舒出沒雲無蹤。", "而今返旆蓬萊去，直欲追尋赤松子。", "與渠擊碎大還丹，爲渠塞斷長生路。", "示之肘後符，佛魔歛袵龍蛇趨。", "授之不傳訣，珊瑚枝枝撐著月。", "阿呵呵，胸次風流知幾何，我分巖扃飽黄獨，佳音聽取到煙蘿。"]'),
('136ce3b3-133f-4dd7-8339-cf754cbf2a82','賀頑極和尚住越州光孝','釋紹曇','宋','宋诗','song-poetry','','[]','越王城北唐朝寺，千間老屋摧風雨。',118,'全唐诗/poet.song.226000.json','["越王城北唐朝寺，千間老屋摧風雨。", "塔影凌空落鑑湖，劫初鈴子丁東語。", "久無本色住山人，愁殺檀門許元度。", "剝否窮時復泰來，選差鐵面頑翁住。", "倒携無柄苕箒樁，積世狐蹤盡掃去。", "就翻鰻井逗曹源，浩浩湯湯流溢江湖無著處。", "豈不勝越人歌來何暮，平生無襦今五袴。"]'),
('7d20cb92-3f06-4615-9b91-25bdcdcb9cfd','聽烏檻角有感送衍上人歸鄉','釋紹曇','宋','宋诗','song-poetry','','[]','黄牛背上烏檻角，聲聲吹作村田樂。',128,'全唐诗/poet.song.226000.json','["黄牛背上烏檻角，聲聲吹作村田樂。", "低入重淵高入雲，擬別宮商都是錯。", "斷煙明滅柘崗西，這嗚咿喚那嗚咿。", "天地豁空群動息，野花驚秀不萌枝。", "古今酬唱知何限，記得完全忘一半。", "木人巧弄沒絃琴，石女細呈氈柏板。", "年來節奏總輸君，聽徹無聲自返聞。", "一曲還鄉人錯聽，聚頭喚作梅花引。"]'),
('0a972368-22af-4617-9a99-e33cb71b7642','舜侍者以拙自處請語爲警','釋紹曇','宋','宋诗','song-poetry','','[]','大地人求巧，子獨全其拙。',186,'全唐诗/poet.song.226000.json','["大地人求巧，子獨全其拙。", "喫飯倒把匙，刺眼翻著襪。", "只知困守株，不愁飛辯月。", "天真未解分，混沌一團鐵。", "抱璞尋鑪鎚，巧手難施設。", "朅來就拙玲瓏陰，氈拍板合無絃琴。", "摘楊黄花嗑然笑，樵童牧豎皆知音。", "豈不見稜道者，破七蒲團無縫罅。", "鬼窟翻身呼大差，卷起簾來見天下。", "又不見隆藏主，此是吾家睡虎子。", "氣肅西風牙爪露，千林掃跡無狐兔。", "須知巧自拙中出，巧拙到頭無處覓。", "無尋覓處知端的，急來與汝粗拳喫。"]'),
('8ddcdd12-9607-4ded-b549-bccf39a61db4','日本國光禪人旋鄉求語','釋紹曇','宋','宋诗','song-poetry','','[]','大唐國，日本國，臨風放出遼天鶻。',128,'全唐诗/poet.song.226000.json','["大唐國，日本國，臨風放出遼天鶻。", "不隔重溟見得親，依然却被重溟隔。", "光禪拚不顧渾身，咬定牙關力訪尋。", "白浪堆頭航一葦，普通年遠只如今。", "焚香扣我西來旨，三十烏藤敲出髓。", "非佛非物亦非心，擬議白雲千萬里。", "結成不共戴天冤，怒氣蒸雲走出門。", "這回必要討分曉，歸問阿爺隆長老。"]'),
('4e6d36ee-941b-4fe0-b5ce-b6026d7768db','日本慈源禪人歸國請偈','釋紹曇','宋','宋诗','song-poetry','','[]','牧間今年六十八，湖上掩關期養拙。',88,'全唐诗/poet.song.226000.json','["牧間今年六十八，湖上掩關期養拙。", "萬緣不掛一絲頭，對客懶饒三寸舌。", "問吾道，秧田潑綠農誇好。", "問吾禪，烟林噪晚聲未聞。", "無端外國人瞞我，插片木頭討甚麽。", "喫盞粗茶送出門，海山啼斷催歸鳥。"]'),
('8f6c38cf-6bce-49bc-8b07-5d9a2f6b1ab8','日本玄志禪人請語','釋紹曇','宋','宋诗','song-poetry','','[]','上人幼負凌雲志，十五爲僧今廿二。',96,'全唐诗/poet.song.226000.json','["上人幼負凌雲志，十五爲僧今廿二。", "鯨波不怕嶮如崖，遠涉要明西祖意。", "老松陰下扣烟扉，未透慈溪劈箭機。", "滿口鄉談學唐語，帝都丁喚那斯祁。", "粗拳便欲攔胸𡎺，又恐傍觀分背觸。", "快歸省問老傳衣，古磵寒泉休瞪目。"]'),
('27fd2126-df14-42cb-adaa-28451bad4eff','示日本景用禪人','釋紹曇','宋','宋诗','song-poetry','','[]','日本國與大唐國，一片皇風無間隔。',96,'全唐诗/poet.song.226000.json','["日本國與大唐國，一片皇風無間隔。", "如將棗葉置針鋒，破草鞋跟天地窄。", "上人滿腹𡎺疑團，夷夏區分扣牧間。", "老懶不能分說得，隔林春鳥語綿蠻。", "當機爲汝分明舉，不涉離微急薦取。", "佛祖玄關錯踏翻，金烏飛上珊瑚樹。"]'),
('90827748-4614-41e2-9754-08307703d184','示寶頭陀之徑山打鐘','釋紹曇','宋','宋诗','song-poetry','','[]','勞生夢寐分途轍，深省一聲何處發。',96,'全唐诗/poet.song.226000.json','["勞生夢寐分途轍，深省一聲何處發。", "客繫楓林半夜舟，僧敲烟寺黄昏月。", "爭似凌霄峰頂頭，怒鯨吼徹千林秋。", "飽噇眠漢不知曉，有眼如盲還聽否。", "我儂會得無聞性，說與頭陀終不信。", "不信試歸撞擊看，風遞落花山意寒。"]'),
('80e6dd51-3b7a-4fba-bac4-1f5bb9f8ff1b','煨芋','釋紹曇','宋','宋诗','song-poetry','','[]','山房不識春風面，地爐宿火煨紅軟。',128,'全唐诗/poet.song.226000.json','["山房不識春風面，地爐宿火煨紅軟。", "寒涕垂頤午夢醒，饑腸殷殷晴雷轉。", "霜猿剝啄啟巖扉，漏泄天香入翠微。", "霧幕烟籠收不得，等閑勾引白雲歸。", "破藤床上生涯足，和土和灰擘柔玉。", "放憨一飽萬緣空，口唱山歌手捫腹。", "可中真味與誰論，脯麟膾鳳徒腥羶。", "向使懶殘知有此，肯把虛名眩天子。"]'),
('ecae53e0-d5a1-45ff-ad12-7bb91025f092','挑薺','釋紹曇','宋','宋诗','song-poetry','','[]','小奚挑薺携籃去，尋遍頹垣與荒圃。',128,'全唐诗/poet.song.226000.json','["小奚挑薺携籃去，尋遍頹垣與荒圃。", "根染微黄怯曉霜，葉鋪嫩綠滋春雨。", "沙瓶鳴井𣂏寒泉，膏泥濯盡誇芳鮮。", "松風飋飋沸茶鼎，晴窗喚醒幽人眠。", "細嚼甘香凝齒頰，味與首陽薇不別。", "茆舍清貧樂未涯，搜吟況有梅梢月。", "五陵玉筯耽膏腴，豈知菜味天淵殊。", "茶罷筇枝發清興，山後山前行一轉。"]'),
('4bee86fd-203e-4c91-a1f8-eeef10d35dd7','賀天童滅翁和尚','釋紹曇','宋','宋诗','song-poetry','','[]','老饕八十再生牙，爛嚼虛空吐出滓。',32,'全唐诗/poet.song.226000.json','["老饕八十再生牙，爛嚼虛空吐出滓。", "點綴玲瓏巖下草，枝枝葉葉是曇花。"]'),
('fd893819-a8ea-4932-be34-7bf4b4939f3a','送僧參太白癡絕和尚并石溪和尚掛牌','釋紹曇','宋','宋诗','song-poetry','','[]','前寶公兮後寶公，分身說法在玲瓏。',32,'全唐诗/poet.song.226000.json','["前寶公兮後寶公，分身說法在玲瓏。", "參尋不用論賓主，十二面門元一同。"]'),
('d970b8d6-5f94-4093-9a57-253f517c2f87','送悟侍者參育王偃溪和尚','釋紹曇','宋','宋诗','song-poetry','','[]','茂陰深處擊寒冰，洗得娘生兩耳清。',32,'全唐诗/poet.song.226000.json','["茂陰深處擊寒冰，洗得娘生兩耳清。", "塞斷不聽呼小玉，順風來聽偃溪聲。"]'),
('de7ce8a3-041f-42fd-a4df-c3a4f8cfec2e','送雲卧接待庵主','釋紹曇','宋','宋诗','song-poetry','','[]','雲卧遺風仰正傳，接人全在钁頭邊。',32,'全唐诗/poet.song.226000.json','["雲卧遺風仰正傳，接人全在钁頭邊。", "臨機不用閑忉怛，自有春山蕨豎拳。"]'),
('38a7ca84-4aed-4c19-b289-4a391612e9c2','賀弁山和尚自雙林赴金山','釋紹曇','宋','宋诗','song-poetry','','[]','雙檮定起月三更，倒跨金鰲戲八紘。',32,'全唐诗/poet.song.226000.json','["雙檮定起月三更，倒跨金鰲戲八紘。", "袖裏門槌惡剌剌，德雲不敢占先行。"]'),
('29f49be8-387a-40ef-89c7-0873147a1f9d','送鑑禪人自天童之江心','釋紹曇','宋','宋诗','song-poetry','','[]','東谷生涯徹骨貧，煩君說與了師兄。',32,'全唐诗/poet.song.226000.json','["東谷生涯徹骨貧，煩君說與了師兄。", "一從鳳宿龍巢後，寶殿無人步月明。"]'),
('703011c2-4e1d-4122-bf81-f99234f11da6','賀天童心首座出世仗錫','釋紹曇','宋','宋诗','song-poetry','','[]','懶織蒲鞋罷養親，入蟭螟眼皷煙塵。',32,'全唐诗/poet.song.226000.json','["懶織蒲鞋罷養親，入蟭螟眼皷煙塵。", "只將打發雲門手，更與玲瓏接一人。"]'),
('49b4bc00-7f7c-4cfa-892a-8adbd39c7b6c','古樵','釋紹曇','宋','宋诗','song-poetry','','[]','七佛已前曾賣弄，分明一塊爛枯柴。',32,'全唐诗/poet.song.226000.json','["七佛已前曾賣弄，分明一塊爛枯柴。", "老盧不解擔當得，火種只今無地埋。"]'),
('1f5c5a5b-c3d8-43d7-9132-a732f148b2e5','雪磯','釋紹曇','宋','宋诗','song-poetry','','[]','訪戴歸來就繫舟，凍雲凝鎖玉花浮。',32,'全唐诗/poet.song.226000.json','["訪戴歸來就繫舟，凍雲凝鎖玉花浮。", "漁蓑釣罷尋盟去，近岸不知飛白鷗。"]'),
('54b68a72-ddc9-4d87-aa62-0fcb6d67bf80','無聞','釋紹曇','宋','宋诗','song-poetry','','[]','缺齒胡僧戲劇多，打虛空皷唱巴歌。',32,'全唐诗/poet.song.226000.json','["缺齒胡僧戲劇多，打虛空皷唱巴歌。", "山河大地連聲笑，爭奈聾人耳朶何。"]'),
('5f0d5a7c-1528-4bda-9ad4-89bb3aa8ffb9','鏡堂','釋紹曇','宋','宋诗','song-poetry','','[]','非明非暗亦非臺，萬像從教影現來。',32,'全唐诗/poet.song.226000.json','["非明非暗亦非臺，萬像從教影現來。", "剛被老盧書破壁，沒塵埃却有塵埃。"]'),
('69787f7a-1982-49c7-a0c5-66c317becf45','西窗','釋紹曇','宋','宋诗','song-poetry','','[]','格樣親傳鼻祖家，短簷時見夕陽斜。',32,'全唐诗/poet.song.226000.json','["格樣親傳鼻祖家，短簷時見夕陽斜。", "看渠巨闢通方眼，牛過依然露尾巴。"]'),
('3e2088e5-73f6-4fc5-8c76-2ef57a38243b','古桃','釋紹曇','宋','宋诗','song-poetry','','[]','仙苑春風幾奏名，三千年實結初成。',32,'全唐诗/poet.song.226000.json','["仙苑春風幾奏名，三千年實結初成。", "曾將一點枝頭血，換得靈雲兩眼睛。"]'),
('c69bb3bb-6d0a-4857-9c0e-d9dbf3be7405','松州','釋紹曇','宋','宋诗','song-poetry','','[]','一道陰凉自古來，依稀臨濟手親栽。',32,'全唐诗/poet.song.226000.json','["一道陰凉自古來，依稀臨濟手親栽。", "枝枝葉葉垂清露，點得合城人眼開。"]'),
('19fc32a1-fec4-460a-8001-c9ab99ca8a12','石井','釋紹曇','宋','宋诗','song-poetry','','[]','打硬工夫搆得深，誰知水底有蓬塵。',32,'全唐诗/poet.song.226000.json','["打硬工夫搆得深，誰知水底有蓬塵。", "放開一線路頭活，落賺幾多明眼人。"]'),
('8dad4d21-6274-4303-b40a-609a671b8ab4','古衲','釋紹曇','宋','宋诗','song-poetry','','[]','半肩寒擁片殘雲，七佛相傳直至今。',32,'全唐诗/poet.song.226000.json','["半肩寒擁片殘雲，七佛相傳直至今。", "破碎不堪提掇處，朝陽正好下金針。"]'),
('203a5087-8b93-448a-8ae5-2583137ba869','即翁','釋紹曇','宋','宋诗','song-poetry','','[]','萬象森羅等印心，了無一物可疏親。',32,'全唐诗/poet.song.226000.json','["萬象森羅等印心，了無一物可疏親。", "大梅坐此成窠窟，到老何曾解轉身。"]'),
('4d0828e9-546d-4b8a-b968-74740d603009','寄石溪和尚自鴈宕歸','釋紹曇','宋','宋诗','song-poetry','','[]','鴈峰削玉鎖層陰，彷彿梅陽瘴面春。',32,'全唐诗/poet.song.226000.json','["鴈峰削玉鎖層陰，彷彿梅陽瘴面春。", "回首揭天撾毒皷，聲怨何止十三人。"]'),
('1a0137a0-e8aa-4f95-bdb3-f03f55e7bc67','題老融羣牛圖','釋紹曇','宋','宋诗','song-poetry','','[]','三三五五戲平蕪，踏裂春風百草枯。',32,'全唐诗/poet.song.226000.json','["三三五五戲平蕪，踏裂春風百草枯。", "莫寫溈山僧某甲，恐人悟作祖師圖。"]'),
('e059c7e7-83f3-4391-a63e-157bbc50a185','題坐禪蝦蟆','釋紹曇','宋','宋诗','song-poetry','','[]','一從識得性分明，懶作春池皷吹聲。',32,'全唐诗/poet.song.226000.json','["一從識得性分明，懶作春池皷吹聲。", "閑把六門深鎖斷，白蓮香散水風清。"]'),
('b34191f2-3b73-48d1-8461-156327b4a2ae','偈頌一百零二首  其一','釋紹曇','宋','宋诗','song-poetry','','[]','大解脫門，無入作處。',28,'全唐诗/poet.song.226000.json','["大解脫門，無入作處。", "掣斷玄關，頭頭活路。", "信脚何妨行數步。"]'),
('d4553a53-a593-41b2-814c-052edd4fb064','偈頌一百零二首  其二','釋紹曇','宋','宋诗','song-poetry','','[]','德山軟頑，雲門放憨。',28,'全唐诗/poet.song.226000.json','["德山軟頑，雲門放憨。", "救不得也，瞿曇瞿曇。", "我也無端入閙籃。"]'),
('d6b1525b-1bb1-41bd-9dfb-e07e6a4ebb3d','偈頌一百零二首  其三','釋紹曇','宋','宋诗','song-poetry','','[]','震旦心宗，竺乾正眼。',32,'全唐诗/poet.song.226000.json','["震旦心宗，竺乾正眼。", "覿面當機，是非俱剗。", "不落思惟透險崖，階下漢。"]'),
('5422a4bd-6f21-4568-b287-6b88202e5477','偈頌一百零二首  其四','釋紹曇','宋','宋诗','song-poetry','','[]','臨崖擠人，惡語傷人。',30,'全唐诗/poet.song.226000.json','["臨崖擠人，惡語傷人。", "冤深潮海，嚼齒吞齦。", "啞，說著無非是惡心。"]'),
('7cb36d9b-e113-4dec-8901-7fad6f5d0d8d','偈頌一百零二首  其五','釋紹曇','宋','宋诗','song-poetry','','[]','未入雞足山，不踏黄梅路。',34,'全唐诗/poet.song.226000.json','["未入雞足山，不踏黄梅路。", "惡業苦無多，平白披毛去。", "明眼人前，一場笑具。"]'),
('1447688a-a1e5-4577-8d4d-c64872c8bdff','偈頌一百零二首  其六','釋紹曇','宋','宋诗','song-poetry','','[]','現成箇，見得到，行得到，說得到。',26,'全唐诗/poet.song.226000.json','["現成箇，見得到，行得到，說得到。", "須彌燈王，狼籍不少。"]'),
('c535ce2e-d9e1-4c70-9c23-22280d28b5e8','偈頌一百零二首  其七','釋紹曇','宋','宋诗','song-poetry','','[]','山雨釀春寒，曉濕梅花重。',40,'全唐诗/poet.song.226000.json','["山雨釀春寒，曉濕梅花重。", "結實較遲遲，且聽香浮動。", "化工有意待重來，永爲鼎鼐調羹用。"]'),
('eeb980c2-c1e7-4ab8-afd3-cfee2e0e5448','偈頌一百零二首  其八','釋紹曇','宋','宋诗','song-poetry','','[]','妙應群機，亨衢得路。',50,'全唐诗/poet.song.226000.json','["妙應群機，亨衢得路。", "浩浩塵中，如何辨主。", "辨得主，進退隨宜，不妨去住。", "倒跨楊岐三脚馿，南北東西誇獨步。"]'),
('172e20e9-c24a-472f-8f67-f62ed2f7f8e6','偈頌一百零二首  其九','釋紹曇','宋','宋诗','song-poetry','','[]','拘尸羅城，娑羅雙樹。',52,'全唐诗/poet.song.226000.json','["拘尸羅城，娑羅雙樹。", "死款難翻，賊身全露。", "引得波旬，叢然笑舞。", "後代兒孫口似椎，有屈誰伸訴，山花點滴啼紅雨。"]'),
('53301aba-c0a1-47c3-a7bc-f8f2cb688372','偈頌一百零二首  其一○','釋紹曇','宋','宋诗','song-poetry','','[]','衲僧拄杖頭，一升三合米。',76,'全唐诗/poet.song.226000.json','["衲僧拄杖頭，一升三合米。", "今年春雨多，一飽應難擬。", "覺海山仙，聞如是語。", "怒髮衝冠，驅神駕鬼。", "誅雲師，掃烟翠。", "放出金烏出海門，且聽歌舞樂豐年，只圖一箇不知恩。"]'),
('2874149e-ca6b-4b85-a4c3-850e5e0e0b1a','偈頌一百零二首  其一一','釋紹曇','宋','宋诗','song-poetry','','[]','寒食清明節，人家拜掃時。',95,'全唐诗/poet.song.226000.json','["寒食清明節，人家拜掃時。", "紙灰粘蝶翅，啼血染花枝。", "追親思遠，寫恨含悲。", "不論富貴，大小由之。", "唯有林泉衲子，無思無念，無欲無爲。", "圓蒲靜倚，瘦策閑戲。", "燕子自長春寂寂，長歌一曲囉囉哩，不是知音說向誰。"]'),
('9e2f6dce-ccf9-494d-8655-2deb2da4ed8e','偈頌一百零二首  其一二','釋紹曇','宋','宋诗','song-poetry','','[]','從上爪牙，千差萬別。',73,'全唐诗/poet.song.226000.json','["從上爪牙，千差萬別。", "截鶴續鳬，傷龜恕鼈。", "拄杖子，不入這保社。", "顢顢頇頇，跛跛挈挈。", "有眼如盲，有舌如結。", "靜倚松根，憨眠不徹。", "佛法從教爛似泥，不說不說。"]'),
('bc4f6ff4-3212-45fd-b1cd-b1c7e2879b15','偈頌一百零二首  其一三','釋紹曇','宋','宋诗','song-poetry','','[]','薄福住山，渾無暇日。',97,'全唐诗/poet.song.226000.json','["薄福住山，渾無暇日。", "忙時直是閑，緩處非常急。", "驅園夫奴子，鋤菜地，掃松行；指莫監楊團，拆東籬，補西壁。", "眼前事亂如麻，脚跟下黑如漆。", "驀有箇漢出來道，長老何太區區，只向道，任是七佛祖師，亦無這箇消息。"]'),
('3194a368-770e-4ffc-8e56-89c7d7827a7c','偈頌一百零二首  其一四','釋紹曇','宋','宋诗','song-poetry','','[]','撼茶樹，偷筍去。',42,'全唐诗/poet.song.226000.json','["撼茶樹，偷筍去。", "角虎出林，鐵蛇橫路，毒氣炎炎如火聚。", "眨上眉毛見得親，靈跡不在猿啼處。"]'),
('8ebdac41-48fd-4c0e-8b3a-89cdc072b698','偈頌一百零二首  其一五','釋紹曇','宋','宋诗','song-poetry','','[]','祖翁田地絕邊垠，契券分明孰敢侵。',32,'全唐诗/poet.song.226000.json','["祖翁田地絕邊垠，契券分明孰敢侵。", "削盡春風閑草木，松濤翻月竹篩金。"]'),
('98e684ef-7706-49fe-a955-a0313a954b9c','偈頌一百零二首  其一六','釋紹曇','宋','宋诗','song-poetry','','[]','肥馬碌碌，瘦馬碌碌。',50,'全唐诗/poet.song.226000.json','["肥馬碌碌，瘦馬碌碌。", "醫得眼前瘡，剜却心頭肉。", "朝不足，莫不足，六六依然三十六。", "雲門見睦州，良遂參麻谷。"]'),
('a6f61573-ab88-48fb-99f0-5ae658e51042','偈頌一百零二首  其一七','釋紹曇','宋','宋诗','song-poetry','','[]','萬機休罷住雲間，門掩青蘿竟日閑。',70,'全唐诗/poet.song.226000.json','["萬機休罷住雲間，門掩青蘿竟日閑。", "時聽嗚咿歌一曲，倒騎黄犢出松關。", "若作佛法會，錦包特石。", "若作世諦會，鐵裹泥團。", "惆悵無人知此意，臨風拍碎石闌干。"]'),
('278e2ca4-b9d4-424d-b1f0-dc6e88215f6f','偈頌一百零二首  其一八','釋紹曇','宋','宋诗','song-poetry','','[]','有服藥，甚功效。',52,'全唐诗/poet.song.226000.json','["有服藥，甚功效。", "不收肘後方書，不入神農本草。", "善財採處不識真，文殊用之不得妙。", "佛壟信手拈來，百病根源俱掃。"]'),
('1f1c014e-b895-4dc6-af3e-400109365cda','偈頌一百零二首  其一九','釋紹曇','宋','宋诗','song-poetry','','[]','烟晴竹樹啼姑惡，月冷松梢哭子規。',32,'全唐诗/poet.song.226000.json','["烟晴竹樹啼姑惡，月冷松梢哭子規。", "莫謂一聲聲破夢，未歸須憶到家時。"]'),
('2d1850df-96c7-4408-804e-2058893e184f','偈頌一百零二首  其二○','釋紹曇','宋','宋诗','song-poetry','','[]','三日晴，五日雨。',52,'全唐诗/poet.song.226000.json','["三日晴，五日雨。", "無象太平，滿田禾黍。", "不作佛法商量，亦非世諦流布。", "碧眼黄頭總不知，問訊輪皴拄杖子，牢記取。"]'),
('45530459-78e7-4353-8676-cbb99872c4e3','偈頌一百零二首  其二一','釋紹曇','宋','宋诗','song-poetry','','[]','顯大機，明大用，六月黄河連底凍。',39,'全唐诗/poet.song.226000.json','["顯大機，明大用，六月黄河連底凍。", "千聖不携，已靈不重。", "带角披毛異類行，漆桶漆桶。"]'),
('184a6ac0-b207-410b-baf0-b580f8a2e366','偈頌一百零二首  其二二','釋紹曇','宋','宋诗','song-poetry','','[]','有亦不管，無亦不管。',20,'全唐诗/poet.song.226000.json','["有亦不管，無亦不管。", "飯來開口，睡來合眼。"]'),
('1990a050-04e6-40ac-96c7-316a75708905','偈頌一百零二首  其二三','釋紹曇','宋','宋诗','song-poetry','','[]','出佛身血，破和合僧。',36,'全唐诗/poet.song.226000.json','["出佛身血，破和合僧。", "馿腮馬頷，逞技矜能。", "堪笑靈山兒戲劇，聚頭爭看蠟人冰。"]'),
('61fb33b0-9606-4ab1-a941-dd51eb0b6367','偈頌一百零二首  其二四','釋紹曇','宋','宋诗','song-poetry','','[]','丹桂飄庭際，寒蛩語砌陰。',42,'全唐诗/poet.song.226000.json','["丹桂飄庭際，寒蛩語砌陰。", "聲聲調雅奏，點點簇黄金。", "盡情拈出，宴樂嘉賓，佛壟雖貧未是貧。"]'),
('05701561-9100-4faa-8cd0-8511c4b0eb4d','偈頌一百零二首  其二五','釋紹曇','宋','宋诗','song-poetry','','[]','有一物，無人識。',56,'全唐诗/poet.song.226000.json','["有一物，無人識。", "或在東南，或居西北。", "破草鞋跟踏著，價重千金；折拄杖頭挑來，分文不直。", "識不識，吳地冬瓜，鎮州蘿蔔。"]'),
('081dfdfc-486f-469c-a32f-725924dae4f5','偈頌一百零二首  其二六','釋紹曇','宋','宋诗','song-poetry','','[]','一月行空，千門賞玩。',48,'全唐诗/poet.song.226000.json','["一月行空，千門賞玩。", "自己光明，幾人著眼。", "馬師父子盡力揩磨，不得一半。", "諸人要見真月麽，何似破漆碗。"]'),
('a6359e2f-aead-4c42-bdb8-82b8af96c3d2','偈頌一百零二首  其二七','釋紹曇','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','正令全提，無在不在。',48,'全唐诗/poet.song.226000.json','["正令全提，無在不在。", "簸箕有唇，洞庭無蓋。", "若作奇特商量，入地獄如箭射。", "不作奇特商量，入地獄如箭射。"]'),
('762ce0e8-16db-46cb-960a-ba51376c209d','偈頌一百零二首  其二八','釋紹曇','宋','宋诗','song-poetry','','[]','地僻雲深，秋高境寂。',28,'全唐诗/poet.song.226000.json','["地僻雲深，秋高境寂。", "堂戶凄凉，無人面壁。", "浄地上誰肯狼籍。"]'),
('9e6ce971-0a0b-4bea-b38a-b06c80ad4ab6','偈頌一百零二首  其二九','釋紹曇','宋','宋诗','song-poetry','','[]','甘菊舒黄，茱萸噴香。',40,'全唐诗/poet.song.226000.json','["甘菊舒黄，茱萸噴香。", "淵明錯會，耽賞重陽。", "采采東籬下，南山見未忘。", "剛道花枝有短長。"]'),
('92bfb2a5-b024-4437-8e5c-da2b4b5cc532','偈頌一百零二首  其三○','釋紹曇','宋','宋诗','song-poetry','','[]','繭足尋莊到海門，天衣往事與誰論。',32,'全唐诗/poet.song.226000.json','["繭足尋莊到海門，天衣往事與誰論。", "長空雁影沉寒水，瘦立西風幾斷魂。"]'),
('02766500-4ceb-4b1e-a903-7f9bc6096a48','偈頌一百零二首  其三一','釋紹曇','宋','宋诗','song-poetry','','[]','鼠竊竺乾，身逃震旦。',42,'全唐诗/poet.song.226000.json','["鼠竊竺乾，身逃震旦。", "合火分贓，兒孫無眼。", "死款諸方不言，今朝佛壟分明斷。", "以何爲據，看。"]'),
('bf85693b-d14a-49f6-a443-1b406f053a99','偈頌一百零二首  其三二','釋紹曇','宋','宋诗','song-poetry','','[]','無量劫來，七顛八倒。',20,'全唐诗/poet.song.226000.json','["無量劫來，七顛八倒。", "打破虛空，全身入草。"]'),
('4e2934c6-098e-4bf8-b8a3-f8fdad3a2b50','偈頌一百零二首  其三三','釋紹曇','宋','宋诗','song-poetry','','[]','佛壟開爐，寒灰死火。',28,'全唐诗/poet.song.226000.json','["佛壟開爐，寒灰死火。", "撥著星兒，彌天罪過。", "笑倒嵩山破竈墮。"]'),
('b02ee5e6-63a6-46fa-8381-3a8b0b8a5c4c','偈頌一百零二首  其三四','釋紹曇','宋','宋诗','song-poetry','','[]','冬至日舒長，這箇長多少。',42,'全唐诗/poet.song.226000.json','["冬至日舒長，這箇長多少。", "虛空爲尺不能量，蟭螟眼中盛恰好。", "盛恰好，衒惑神光，迷逢達磨。"]'),
('07d1c1b9-bb62-4b00-9902-ecb539ff8984','偈頌一百零二首  其三五','釋紹曇','宋','宋诗','song-poetry','','[]','我也無端到住山，忙忙業識不曾閑。',54,'全唐诗/poet.song.226000.json','["我也無端到住山，忙忙業識不曾閑。", "白雲拂盡到枯葉，恐礙采樵人往還。", "寒松瑟瑟，幽鳥關關。", "家私花擘盡，誰道語音蠻。"]'),
('02e11221-4310-4a15-b1bf-b902fca3f0e6','偈頌一百零二首  其三六','釋紹曇','宋','宋诗','song-poetry','','[]','生平說大脫空，今受活地獄報。',28,'全唐诗/poet.song.226000.json','["生平說大脫空，今受活地獄報。", "一片無骨舌頭，數日和根爛了。"]'),
('b066e622-4ff8-4c13-8541-a3c85c067f7e','偈頌一百零二首  其三七','釋紹曇','宋','宋诗','song-poetry','','[]','古檜吟風，寒鴉布陣。',34,'全唐诗/poet.song.226000.json','["古檜吟風，寒鴉布陣。", "不落見聞，幾人錯認。", "不錯認，道士擎拳，闍梨問訊。"]'),
('e80c8fec-ce37-431f-b090-f7fbb6797dd9','偈頌一百零二首  其三八','釋紹曇','宋','宋诗','song-poetry','','[]','祝融峰，萬年松。',34,'全唐诗/poet.song.226000.json','["祝融峰，萬年松。", "翠陰籠鶴，瑞氣蟠龍。", "用獻聖明天子壽，枝枝葉葉自春風。"]'),
('e67c9a91-3c91-4de1-86d0-0e31f1ba0b3b','偈頌一百零二首  其三九','釋紹曇','宋','宋诗','song-poetry','','[]','入荒田不揀，信手拈來草。',74,'全唐诗/poet.song.226000.json','["入荒田不揀，信手拈來草。", "緯地與經天，頭頭俱是妙。", "打成一片見全功，碧眼黄頭俱靠倒。", "豈不見長慶稜道者坐破蒲團，一箇兩箇三箇，四五六七箇，家風狼籍知多少。"]'),
('0955d5d6-9ae7-4634-a2ce-8f78a1f1a901','偈頌一百零二首  其四○','釋紹曇','宋','宋诗','song-poetry','','[]','大道無方，至尊無位。',36,'全唐诗/poet.song.226000.json','["大道無方，至尊無位。", "睿哲文明，垂衣而治。", "堯風舜日萬斯年，舉世無思不戴天。"]'),
('0844f3e2-0573-4113-a7b2-2c6e5ea14a74','偈頌一百零二首  其四一','釋紹曇','宋','宋诗','song-poetry','','[]','高價賣生姜，雪真珠滿床。',66,'全唐诗/poet.song.226000.json','["高價賣生姜，雪真珠滿床。", "清貧雖徹骨，富敢鬭君王。", "灼然如是，膾身爲食，漬血爲漿，盡情供養，猶未相當。", "若也未是，和烟耕綠野，枯笛送斜陽。"]'),
('c0b44488-3548-4e2a-892a-26b6e3df7786','偈頌一百零二首  其四二','釋紹曇','宋','宋诗','song-poetry','','[]','這一燈，處甚起。',50,'全唐诗/poet.song.226000.json','["這一燈，處甚起。", "沒蹤由，難擬議。", "三賢十聖眼見如盲，芥狗泥豬放光動地。", "大家吹滅暗中行，然燈佛在你脚底。"]'),
('a8fc46e4-4c0b-4201-8d70-fdf0ac316c5d','偈頌一百零二首  其四三','釋紹曇','宋','宋诗','song-poetry','','[]','浪蕩貪觀野鴨兒，犯叢林合講清規。',32,'全唐诗/poet.song.226000.json','["浪蕩貪觀野鴨兒，犯叢林合講清規。", "鼻頭捏破知慚愧，燒炷楓香供養伊。"]');
